function scrollWorkOrderEditorToTop() {
  workOrderEditorBody?.scrollTo({ top: 0, left: 0, behavior: "auto" });
  workOrderActivityList?.scrollTo({ top: 0, left: 0, behavior: "auto" });
}

function setWorkOrderSaveState(mode, message = "") {
  if (!workOrderSaveState) {
    return;
  }

  const defaultMessages = {
    idle: "Automatsko spremanje je spremno.",
    pending: "Promjene cekaju spremanje...",
    saving: "Spremanje u tijeku...",
    saved: "Sve promjene su spremljene.",
    blocked: "Odaberi tvrtku da se RN spremi.",
    error: "Spremanje nije uspjelo.",
  };

  state.workOrderAutoSave.state = mode;
  workOrderSaveState.dataset.state = mode;
  workOrderSaveState.textContent = message || defaultMessages[mode] || defaultMessages.idle;
}

function clearWorkOrderAutoSaveTimer() {
  if (state.workOrderAutoSave.timerId) {
    window.clearTimeout(state.workOrderAutoSave.timerId);
    state.workOrderAutoSave.timerId = null;
  }
}

function resetWorkOrderAutoSaveState() {
  clearWorkOrderAutoSaveTimer();
  state.workOrderAutoSave = {
    timerId: null,
    saving: false,
    dirty: false,
    lastFingerprint: "",
    lastSavedAt: "",
    state: "idle",
  };
  setWorkOrderSaveState("idle");
}

function getWorkOrderPayloadFingerprint(payload = buildWorkOrderPayload()) {
  return JSON.stringify(payload);
}

function canAutoSaveWorkOrder(payload = buildWorkOrderPayload()) {
  if (workOrderIdInput.value) {
    return true;
  }

  return Boolean(payload.companyId);
}

function findCreatedWorkOrderMatch(previousIds, payload) {
  const created = state.workOrders.find((item) => !previousIds.has(String(item.id)));

  if (created) {
    return created;
  }

  return state.workOrders.find((item) => (
    String(item.companyId || "") === String(payload.companyId || "")
    && String(item.locationId || "") === String(payload.locationId || "")
    && String(item.openedDate || "") === String(payload.openedDate || "")
    && String(item.serviceLine || "") === String(payload.serviceLine || "")
    && String(item.department || "") === String(payload.department || "")
    && String(item.teamLabel || "") === String(payload.teamLabel || "")
    && getWorkOrderExecutors(item).join("||") === getWorkOrderExecutors(payload).join("||")
  )) ?? null;
}

async function persistWorkOrderAutoSave({ immediate = false } = {}) {
  clearWorkOrderAutoSaveTimer();

  if (!state.workOrderEditorOpen || !state.user) {
    return false;
  }

  if (state.workOrderAutoSave.saving) {
    state.workOrderAutoSave.dirty = true;
    state.workOrderAutoSave.timerId = window.setTimeout(() => {
      void persistWorkOrderAutoSave();
    }, WORK_ORDER_AUTOSAVE_DELAY_MS);
    return false;
  }

  const payload = buildWorkOrderPayload();
  const fingerprint = getWorkOrderPayloadFingerprint(payload);
  const isEditing = Boolean(workOrderIdInput.value);

  if (!canAutoSaveWorkOrder(payload)) {
    state.workOrderAutoSave.dirty = false;
    setWorkOrderSaveState("blocked");
    return false;
  }

  if (isEditing && fingerprint === state.workOrderAutoSave.lastFingerprint && !immediate) {
    setWorkOrderSaveState("saved");
    return true;
  }

  state.workOrderAutoSave.saving = true;
  state.workOrderAutoSave.dirty = false;
  setWorkOrderSaveState("saving");

  const editingId = workOrderIdInput.value;
  const path = isEditing ? `/work-orders/${editingId}` : "/work-orders";
  const method = isEditing ? "PATCH" : "POST";
  const previousIds = new Set(state.workOrders.map((item) => String(item.id)));
  const success = await runMutation(() => apiRequest(path, {
    method,
    body: payload,
  }), workOrderError);

  state.workOrderAutoSave.saving = false;

  if (!success) {
    state.workOrderAutoSave.dirty = true;
    setWorkOrderSaveState("error", workOrderError.textContent || "Spremanje nije uspjelo.");
    return false;
  }

  state.workOrderAutoSave.lastFingerprint = fingerprint;
  state.workOrderAutoSave.lastSavedAt = new Date().toISOString();

  if (isEditing) {
    renderWorkOrderEditorSummary();
    void loadWorkOrderActivity(editingId);
  } else {
    const created = findCreatedWorkOrderMatch(previousIds, payload);

    if (created) {
      workOrderIdInput.value = created.id;
      renderWorkOrderEditorSummary();
      void loadWorkOrderActivity(created.id);
      void loadWorkOrderDocuments(created.id);
    }
  }

  setWorkOrderSaveState("saved");

  if (state.workOrderAutoSave.dirty) {
    queueWorkOrderAutoSave();
  }

  return true;
}

function queueWorkOrderAutoSave() {
  if (!state.workOrderEditorOpen || !state.user) {
    return;
  }

  const payload = buildWorkOrderPayload();

  if (!canAutoSaveWorkOrder(payload)) {
    clearWorkOrderAutoSaveTimer();
    state.workOrderAutoSave.dirty = false;
    setWorkOrderSaveState("blocked");
    return;
  }

  state.workOrderAutoSave.dirty = true;
  setWorkOrderSaveState("pending");
  clearWorkOrderAutoSaveTimer();
  state.workOrderAutoSave.timerId = window.setTimeout(() => {
    void persistWorkOrderAutoSave();
  }, WORK_ORDER_AUTOSAVE_DELAY_MS);
}

function getMeasurementSheetOwnerFieldIndex() {
  if (state.measurementSheet.ownerKind !== "template_field" || !state.measurementSheet.ownerFieldId) {
    return -1;
  }

  return documentTemplateFieldDrafts.findIndex((field) => String(field.id) === String(state.measurementSheet.ownerFieldId));
}

function persistMeasurementSheetToTemplateField({ rerenderFieldRows = false } = {}) {
  const fieldIndex = getMeasurementSheetOwnerFieldIndex();

  if (fieldIndex < 0) {
    return;
  }

  const currentField = documentTemplateFieldDrafts[fieldIndex];
  const snapshot = buildMeasurementSheetSnapshot({ includeBlankStructure: true })
    ?? buildTemplateMeasurementSheetFromLegacyConfig(currentField);
  const sheet = ensureDocumentTemplateMeasurementFieldSheet({
    ...currentField,
    sheet: snapshot,
  });

  documentTemplateFieldDrafts[fieldIndex] = {
    ...currentField,
    type: "measurement_table",
    sheet,
    columns: sheet.columns.map((column) => column.label).join(", "),
    rowCount: String(Math.max(DEFAULT_MEASUREMENT_ROW_COUNT, sheet.rows.length || DEFAULT_MEASUREMENT_ROW_COUNT)),
  };

  renderDocumentTemplatePreviewContent();
  syncDocumentTemplateEditorChrome();

  if (rerenderFieldRows) {
    renderDocumentTemplateFieldRows();
  }
}

function handleMeasurementSheetMutation({ immediate = false } = {}) {
  if (state.measurementSheet.ownerKind === "template_field") {
    persistMeasurementSheetToTemplateField();
    return;
  }

  if (state.measurementSheet.ownerKind === "document_template_runtime_field") {
    persistMeasurementSheetToDocumentTemplateRuntimeField();
    return;
  }

  if (!state.workOrderEditorOpen || !state.user) {
    return;
  }

  if (immediate) {
    void persistWorkOrderAutoSave({ immediate: true });
    return;
  }

  queueWorkOrderAutoSave();
}

function renderWorkOrderEditorSummary() {
  if (!workOrderEditorTitle || !workOrderEditorSubtitle || !workOrderEditorMeta || !workOrderEditorCompanySummary) {
    return;
  }

  const activeId = String(workOrderIdInput.value || "");
  const persistedItem = state.workOrders.find((item) => String(item.id) === activeId) ?? null;
  const workOrderNumber = persistedItem?.workOrderNumber || "";
  const selectedServiceItems = readWorkOrderServiceSelection();
  const serviceLine = getSelectedWorkOrderServiceSummary();
  const department = String(workOrderDepartmentInput.value ?? "").trim();
  const teamLabel = String(workOrderTeamLabelInput.value ?? "").trim();
  const description = String(workOrderDescriptionInput.value ?? "").trim();
  const company = getCompany(workOrderCompanyIdInput.value);
  const location = getLocation(workOrderLocationIdInput.value);
  const companyName = company?.name || "";
  const locationName = location?.name || "";
  const compactServiceSummary = [serviceLine, department].filter(Boolean).join(" · ");
  const completedServices = getWorkOrderCompletedServiceCount({ serviceItems: selectedServiceItems });
  const serviceSummary = [
    department,
    serviceLine,
    selectedServiceItems.length > 0 ? `${completedServices}/${selectedServiceItems.length} odrađeno` : "",
  ].filter(Boolean).join(" · ");
  const contactSummary = [
    getSelectedContactName(),
    String(workOrderContactPhoneInput.value ?? "").trim() || String(workOrderContactEmailInput.value ?? "").trim(),
  ].filter(Boolean).join(" · ");
  const linkReference = String(workOrderLinkReferenceInput.value ?? "").trim();
  const executorValues = readWorkOrderExecutorSelection();

  workOrderEditorContext.textContent = activeId ? "Uređivanje radnog naloga" : "Otvaranje novog RN";
  workOrderEditorTitle.textContent = activeId ? (workOrderNumber || "Radni nalog") : "Novi radni nalog";
  workOrderEditorSubtitle.textContent = description
    || compactServiceSummary
    || [companyName, locationName].filter(Boolean).join(" · ")
    || "Promjene se spremaju automatski.";

  const companySummaryNodes = [];

  if (companyName) {
    const companyLine = document.createElement("strong");
    companyLine.className = "work-order-editor-company-primary";
    companyLine.textContent = companyName;
    companySummaryNodes.push(companyLine);
  }

  if (workOrderHeadquartersInput.value.trim()) {
    const headquartersLine = document.createElement("span");
    headquartersLine.className = "work-order-editor-company-line";
    headquartersLine.textContent = `Sjedište · ${workOrderHeadquartersInput.value.trim()}`;
    companySummaryNodes.push(headquartersLine);
  }

  if (workOrderCompanyOibInput.value.trim()) {
    const oibLine = document.createElement("span");
    oibLine.className = "work-order-editor-company-line";
    oibLine.textContent = `OIB · ${workOrderCompanyOibInput.value.trim()}`;
    companySummaryNodes.push(oibLine);
  }

  if (companySummaryNodes.length === 0) {
    const placeholderLine = document.createElement("span");
    placeholderLine.className = "work-order-editor-company-line is-placeholder";
    placeholderLine.textContent = "Odaberi tvrtku, sjedište i OIB će se prikazati ovdje.";
    companySummaryNodes.push(placeholderLine);
  }

  workOrderEditorCompanySummary.replaceChildren(...companySummaryNodes);

  if (workOrderNumberPreview) {
    workOrderNumberPreview.dataset.mode = workOrderNumber ? "assigned" : "pending";
    workOrderNumberPreview.textContent = workOrderNumber ? `RN ${workOrderNumber}` : "Broj nakon spremanja";
  }

  const statusBadge = createBadge(
    getSelectedOptionText(workOrderStatusInput) || workOrderStatusInput.value || "Otvoreni RN",
    statusBadgeClass(workOrderStatusInput.value || "Otvoreni RN"),
  );
  statusBadge.classList.add("work-order-editor-chip");

  const priorityBadge = createBadge(
    getSelectedOptionText(workOrderPriorityInput) || workOrderPriorityInput.value || "Normal",
    priorityBadgeClass(workOrderPriorityInput.value || "Normal"),
  );
  priorityBadge.classList.add("work-order-editor-chip");

  const chips = document.createElement("div");
  chips.className = "work-order-editor-chip-row";
  chips.append(statusBadge, priorityBadge);

  if (workOrderTagTextInput.value.trim()) {
    chips.append(createWorkOrderEditorInfoChip(workOrderTagTextInput.value.trim(), "accent"));
  }

  if (teamLabel) {
    chips.append(createWorkOrderEditorInfoChip(teamLabel, "accent"));
  }

  if (linkReference) {
    chips.append(createWorkOrderEditorInfoChip(linkReference, "soft"));
  }

  const facts = document.createElement("div");
  facts.className = "work-order-editor-facts";
  facts.append(
    createWorkOrderEditorMetaItem(
      "number",
      "Broj RN",
      workOrderNumber || "Dodjeljuje se nakon spremanja",
    ),
    createWorkOrderEditorMetaItem(
      "location",
      "Lokacija",
      locationName || "Odaberi lokaciju",
    ),
    createWorkOrderEditorMetaItem(
      "dates",
      "Datumi",
      `${formatCompactOpenedDate(workOrderOpenedDateInput.value)} · ${formatCompactDueDate(workOrderDueDateInput.value)}`,
    ),
    createWorkOrderEditorMetaItem(
      "service",
      "Usluga",
      serviceSummary || "Bez usluge",
    ),
    createWorkOrderEditorMetaItem(
      "team",
      "Tim",
      teamLabel || "Bez tima",
    ),
    createWorkOrderEditorMetaItem(
      "contact",
      "Kontakt",
      contactSummary || "Bez kontakta",
    ),
  );

  const assigneeWrap = document.createElement("div");
  assigneeWrap.className = "work-order-editor-assignees";

  if (executorValues.length > 0) {
    executorValues.slice(0, 5).forEach((executor) => {
      assigneeWrap.append(createWorkOrderMiniExecutor(executor, { className: "work-order-editor-assignee" }));
    });
    if (executorValues.length > 5) {
      assigneeWrap.append(createExecutorOverflowBadge(executorValues.length - 5, "work-order-editor-assignee"));
    }
  } else {
    const empty = document.createElement("span");
    empty.className = "work-order-editor-assignees-empty";
    empty.textContent = "Bez izvršitelja";
    assigneeWrap.append(empty);
  }

  const assigneeMeta = createWorkOrderEditorMetaItem("assignees", "Izvršitelji", "", assigneeWrap);
  assigneeMeta.classList.add("is-assignee-group");
  facts.append(assigneeMeta);
  workOrderEditorMeta.replaceChildren(chips, facts);
  workOrderStatusInput.dataset.status = slugifyValue(workOrderStatusInput.value || "Otvoreni RN");
  renderTopbarBreadcrumbs();
}

function renderWorkOrderEditorExecutorPicker() {
  if (!workOrderExecutorsPicker) {
    return;
  }

  const wrapper = document.createElement("div");
  wrapper.className = "work-order-calendar-executor-picker work-order-editor-executor-picker";

  const trigger = document.createElement("button");
  trigger.type = "button";
  trigger.className = "work-order-calendar-executor-trigger work-order-editor-executor-trigger";
  trigger.setAttribute("aria-haspopup", "dialog");
  trigger.setAttribute("aria-expanded", "false");

  const getCurrentValues = () => readWorkOrderExecutorSelection();
  const setCurrentValues = (values) => {
    setWorkOrderCalendarExecutorTriggerContent(trigger, values);
  };

  const positionMenuPortal = (menu) => {
    const triggerRect = trigger.getBoundingClientRect();
    const menuRect = menu.getBoundingClientRect();
    const viewportWidth = window.innerWidth;
    const viewportHeight = window.innerHeight;

    let left = triggerRect.left;
    let top = triggerRect.bottom + 8;

    if (left + menuRect.width > viewportWidth - 12) {
      left = Math.max(12, viewportWidth - menuRect.width - 12);
    }

    if (top + menuRect.height > viewportHeight - 12) {
      top = Math.max(12, triggerRect.top - menuRect.height - 8);
    }

    menu.style.left = `${Math.round(left)}px`;
    menu.style.top = `${Math.round(top)}px`;
    menu.style.minWidth = `${Math.max(280, Math.round(triggerRect.width))}px`;
  };

  const closeMenu = () => {
    wrapper.classList.remove("is-open");
    trigger.setAttribute("aria-expanded", "false");
    if (wrapper._menuPortal) {
      wrapper._menuPortal.remove();
      wrapper._menuPortal = null;
    }
  };

  wrapper._closeMenu = closeMenu;

  const openMenu = () => {
    closeOpenWorkOrderStatusMenus(wrapper);

    if (wrapper._menuPortal) {
      return;
    }

    let draftValues = getCurrentValues();
    let searchQuery = "";

    const menu = document.createElement("div");
    menu.className = "work-item-status-menu work-item-status-menu-portal work-order-calendar-executor-menu-portal";
    menu.setAttribute("role", "dialog");
    menu.setAttribute("aria-label", "Izbor izvršitelja");

    ["pointerdown", "mousedown", "click", "keydown"].forEach((eventName) => {
      menu.addEventListener(eventName, (event) => {
        event.stopPropagation();
      });
    });

    const searchWrap = document.createElement("div");
    searchWrap.className = "work-order-calendar-executor-search";

    const searchInput = document.createElement("input");
    searchInput.type = "search";
    searchInput.className = "work-order-calendar-executor-search-input";
    searchInput.placeholder = "Traži po imenu ili prezimenu";
    searchInput.autocomplete = "off";
    searchInput.spellcheck = false;
    searchWrap.append(searchInput);

    const selection = document.createElement("div");
    selection.className = "work-order-calendar-executor-selection";

    const helper = document.createElement("p");
    helper.className = "work-order-calendar-executor-helper";

    const optionsList = document.createElement("div");
    optionsList.className = "work-order-calendar-executor-options";

    const clearButton = document.createElement("button");
    clearButton.type = "button";
    clearButton.className = "ghost-button work-order-calendar-executor-clear";
    clearButton.textContent = "Očisti";

    const selectionsEqual = (leftValues, rightValues) => {
      if (leftValues.length !== rightValues.length) {
        return false;
      }

      return leftValues.every((value, index) => value === rightValues[index]);
    };

    const toggleDraftValue = (value) => {
      const normalizedValue = String(value ?? "").trim();
      if (!normalizedValue) {
        return;
      }

      if (draftValues.includes(normalizedValue)) {
        draftValues = draftValues.filter((entry) => entry !== normalizedValue);
        return;
      }

      draftValues = [...draftValues, normalizedValue];
    };

    const applyDraftValues = (nextValues, { focusSearch = true } = {}) => {
      const normalized = normalizeWorkOrderExecutorValues(nextValues);
      draftValues = normalized;

      if (!selectionsEqual(normalized, getCurrentValues())) {
        writeWorkOrderExecutorSelection(normalized, {
          dispatchEventName: "change",
          renderPicker: false,
        });
      }

      setCurrentValues(normalized);
      syncMenuState();

      if (focusSearch) {
        searchInput.focus({ preventScroll: true });
      }
    };

    const renderSelection = () => {
      selection.replaceChildren();

      if (draftValues.length === 0) {
        const empty = document.createElement("span");
        empty.className = "work-order-calendar-executor-selection-empty";
        empty.textContent = "Bez izvršitelja";
        selection.append(empty);
        return;
      }

      draftValues.forEach((value) => {
        const chip = document.createElement("button");
        chip.type = "button";
        chip.className = "work-order-calendar-executor-chip";
        chip.title = `Makni ${value}`;

        const avatar = createWorkOrderMiniExecutor(value);
        avatar.removeAttribute("title");

        const label = document.createElement("span");
        label.className = "work-order-calendar-executor-chip-label";
        label.textContent = value;

        const remove = document.createElement("span");
        remove.className = "work-order-calendar-executor-chip-remove";
        remove.setAttribute("aria-hidden", "true");
        remove.textContent = "x";

        chip.append(avatar, label, remove);
        chip.addEventListener("click", (event) => {
          event.stopPropagation();
          applyDraftValues(draftValues.filter((entry) => entry !== value));
        });

        selection.append(chip);
      });
    };

    const renderOptions = () => {
      optionsList.replaceChildren();

      const visibleOptions = getWorkOrderExecutorOptions(getCurrentValues())
        .filter((option) => matchesWorkOrderExecutorSearch(option, searchQuery));

      if (visibleOptions.length === 0) {
        const empty = document.createElement("p");
        empty.className = "work-order-calendar-executor-empty";
        empty.textContent = "Nema izvršitelja za ovaj pojam.";
        optionsList.append(empty);
        return;
      }

      visibleOptions.forEach((option) => {
        const isSelected = draftValues.includes(option.value);
        const optionButton = document.createElement("button");
        optionButton.type = "button";
        optionButton.className = "work-item-status-option work-order-calendar-executor-option";
        optionButton.classList.toggle("is-selected", isSelected);
        optionButton.setAttribute("role", "menuitemcheckbox");
        optionButton.setAttribute("aria-checked", String(isSelected));

        const avatar = createWorkOrderMiniExecutor(option, {
          className: "work-order-calendar-executor-option-avatar",
        });

        const label = document.createElement("span");
        label.className = "work-order-calendar-executor-option-label";
        label.textContent = option.label;

        const marker = document.createElement("span");
        marker.className = "work-order-calendar-executor-option-marker";
        marker.setAttribute("aria-hidden", "true");
        marker.textContent = isSelected ? "✓" : "+";

        optionButton.append(avatar, label, marker);
        optionButton.addEventListener("click", (event) => {
          event.stopPropagation();
          toggleDraftValue(option.value);
          applyDraftValues(draftValues);
        });

        optionsList.append(optionButton);
      });
    };

    const syncMenuState = () => {
      renderSelection();
      renderOptions();
      helper.textContent = draftValues.length > 0
        ? `${draftValues.length} odabranih izvršitelja.`
        : "Odaberi jednog ili više izvršitelja.";
      clearButton.disabled = draftValues.length === 0;
      requestAnimationFrame(() => positionMenuPortal(menu));
    };

    clearButton.addEventListener("click", (event) => {
      event.stopPropagation();
      applyDraftValues([]);
    });

    searchInput.addEventListener("input", () => {
      searchQuery = searchInput.value || "";
      renderOptions();
      requestAnimationFrame(() => positionMenuPortal(menu));
    });

    searchInput.addEventListener("keydown", (event) => {
      if (event.key === "Escape") {
        event.preventDefault();
        closeMenu();
        trigger.focus({ preventScroll: true });
        return;
      }

      if (event.key !== "Enter") {
        return;
      }

      const visibleOptions = getWorkOrderExecutorOptions(getCurrentValues())
        .filter((option) => matchesWorkOrderExecutorSearch(option, searchQuery));

      if (visibleOptions.length !== 1) {
        return;
      }

      event.preventDefault();
      toggleDraftValue(visibleOptions[0].value);
      applyDraftValues(draftValues);
    });

    menu.append(searchWrap, selection, helper, optionsList, clearButton);

    syncMenuState();

    document.body.append(menu);
    wrapper._menuPortal = menu;
    wrapper.classList.add("is-open");
    trigger.setAttribute("aria-expanded", "true");
    positionMenuPortal(menu);
    requestAnimationFrame(() => {
      positionMenuPortal(menu);
      searchInput.focus({ preventScroll: true });
      searchInput.select();
    });
  };

  ["pointerdown", "mousedown", "click", "keydown"].forEach((eventName) => {
    wrapper.addEventListener(eventName, (event) => {
      event.stopPropagation();
    });
  });

  trigger.addEventListener("click", (event) => {
    event.stopPropagation();
    if (wrapper.classList.contains("is-open")) {
      closeOpenWorkOrderStatusMenus();
      return;
    }
    openMenu();
  });

  setCurrentValues(getCurrentValues());
  wrapper.append(trigger);
  workOrderExecutorsPicker.replaceChildren(wrapper);
}

function getWorkOrderServiceCatalogOptions(currentItems = []) {
  const options = [];
  const seen = new Set();

  currentItems.forEach((item) => {
    const key = String(item.serviceId || `${item.serviceCode}::${item.name}`).trim();
    if (!key || seen.has(key)) {
      return;
    }

    options.push({
      id: item.serviceId || key,
      name: item.name,
      serviceCode: item.serviceCode,
      linkedTemplateIds: [...(item.linkedTemplateIds ?? [])],
      linkedTemplateTitles: [...(item.linkedTemplateTitles ?? [])],
      status: "inactive",
      isSnapshot: true,
    });
    seen.add(key);
  });

  sortServiceCatalogItems(state.serviceCatalog ?? []).forEach((item) => {
    const key = String(item.id || `${item.serviceCode}::${item.name}`).trim();
    if (!key || seen.has(key)) {
      return;
    }

    options.push(item);
    seen.add(key);
  });

  return options;
}

function matchesWorkOrderServiceSearch(option, query = "") {
  const normalizedQuery = normalizeLooseName(query);

  if (!normalizedQuery) {
    return true;
  }

  const haystack = [
    option.name,
    option.serviceCode,
    ...(option.linkedTemplateTitles ?? []),
  ]
    .join(" ")
    .toLowerCase();

  return haystack.includes(normalizedQuery);
}

function setWorkOrderServicePickerTriggerContent(trigger, items = []) {
  const selectedItems = getWorkOrderServiceItems({ serviceItems: items });
  trigger.replaceChildren();
  trigger.title = selectedItems.length > 0
    ? selectedItems.map((item) => item.name || item.serviceCode).join(", ")
    : "Dodaj usluge";

  const label = document.createElement("span");
  label.className = "work-order-service-picker-label";
  label.textContent = selectedItems.length > 0
    ? `Uredi usluge (${selectedItems.length})`
    : "+ Dodaj usluge";

  trigger.append(label);

  if (selectedItems.length > 0) {
    const meta = document.createElement("span");
    meta.className = "work-order-service-picker-empty";
    meta.textContent = `${getWorkOrderCompletedServiceCount({ serviceItems: selectedItems })}/${selectedItems.length} odrađeno`;
    trigger.append(meta);
  }
}

function renderWorkOrderServiceSelection() {
  if (!workOrderServiceSelection) {
    return;
  }

  const selectedItems = readWorkOrderServiceSelection();
  const legacySummary = String(workOrderServiceLineInput?.value ?? "").trim();

  if (selectedItems.length === 0) {
    const empty = document.createElement("p");
    empty.className = "work-order-service-empty";
    empty.textContent = legacySummary ? "Ovaj RN još koristi stari unos usluge." : "Još nema odabranih usluga.";

    if (legacySummary) {
      const legacy = document.createElement("article");
      legacy.className = "work-order-service-item";

      const copy = document.createElement("div");
      copy.className = "work-order-service-item-copy";

      const titleRow = document.createElement("div");
      titleRow.className = "work-order-service-item-title-row";
      const title = document.createElement("strong");
      title.textContent = legacySummary;
      titleRow.append(title, createBadge("Legacy unos", "work-order-service-code-badge"));
      copy.append(titleRow);

      legacy.append(copy);
      workOrderServiceSelection.replaceChildren(legacy, empty);
    } else {
      workOrderServiceSelection.replaceChildren(empty);
    }
    if (workOrderServiceTemplateHint) {
      workOrderServiceTemplateHint.textContent = legacySummary
        ? "Ako odabereš usluge iz kataloga, stari tekst usluge zamijenit će se strukturiranim stavkama."
        : "Odaberi jednu ili više usluga. Templatei povezani s uslugom prikazuju se ovdje kao podsjetnik za zapisnik.";
    }
    return;
  }

  const templateNames = Array.from(new Set(
    selectedItems.flatMap((item) => item.linkedTemplateTitles ?? []).map((value) => String(value ?? "").trim()).filter(Boolean),
  ));

  if (workOrderServiceTemplateHint) {
    workOrderServiceTemplateHint.textContent = templateNames.length > 0
      ? `Povezani templatei: ${templateNames.join(" · ")}`
      : "Odabrane usluge trenutno nemaju povezan template.";
  }

  workOrderServiceSelection.replaceChildren(...selectedItems.map((item) => {
    const row = document.createElement("article");
    row.className = `work-order-service-item${item.isCompleted ? " is-completed" : ""}`;

    const copy = document.createElement("div");
    copy.className = "work-order-service-item-copy";

    const titleRow = document.createElement("div");
    titleRow.className = "work-order-service-item-title-row";
    const title = document.createElement("strong");
    title.textContent = item.name || item.serviceCode || "Usluga";
    titleRow.append(title);

    if (item.serviceCode) {
      titleRow.append(createBadge(item.serviceCode, "work-order-service-code-badge"));
    }

    const templates = document.createElement("div");
    templates.className = "work-order-service-item-templates";
    const templateTitles = (item.linkedTemplateTitles ?? []).filter(Boolean);

    if (templateTitles.length > 0) {
      templateTitles.forEach((templateTitle) => {
        templates.append(createBadge(templateTitle, "work-order-service-template-badge"));
      });
    } else {
      templates.append(createBadge("Bez templatea", "work-order-service-template-badge is-muted"));
    }

    copy.append(titleRow, templates);

    const actions = document.createElement("div");
    actions.className = "work-order-service-item-actions";

    const toggle = document.createElement("button");
    toggle.type = "button";
    toggle.className = `work-order-service-status-toggle${item.isCompleted ? " is-completed" : ""}`;
    toggle.textContent = item.isCompleted ? "✓" : "✕";
    toggle.title = item.isCompleted ? "Označi kao neodrađeno" : "Označi kao odrađeno";
    toggle.addEventListener("click", () => {
      const nextItems = selectedItems.map((entry) => (
        entry.serviceId === item.serviceId
          ? { ...entry, isCompleted: !entry.isCompleted }
          : entry
      ));
      writeWorkOrderServiceSelection(nextItems, {
        dispatchEventName: "change",
      });
    });

    const remove = document.createElement("button");
    remove.type = "button";
    remove.className = "work-order-service-remove";
    remove.textContent = "Ukloni";
    remove.addEventListener("click", () => {
      const nextItems = selectedItems.filter((entry) => entry.serviceId !== item.serviceId);
      writeWorkOrderServiceSelection(nextItems, {
        dispatchEventName: "change",
      });
    });

    actions.append(toggle, remove);
    row.append(copy, actions);
    return row;
  }));
}

function renderWorkOrderServicePicker() {
  if (!workOrderServicePicker) {
    return;
  }

  const wrapper = document.createElement("div");
  wrapper.className = "work-order-service-picker";

  const trigger = document.createElement("button");
  trigger.type = "button";
  trigger.className = "work-order-service-picker-trigger";
  trigger.setAttribute("aria-haspopup", "dialog");
  trigger.setAttribute("aria-expanded", "false");

  const getCurrentItems = () => readWorkOrderServiceSelection();
  const setCurrentItems = (items) => {
    setWorkOrderServicePickerTriggerContent(trigger, items);
  };

  const positionMenuPortal = (menu) => {
    const triggerRect = trigger.getBoundingClientRect();
    const menuRect = menu.getBoundingClientRect();
    const viewportWidth = window.innerWidth;
    const viewportHeight = window.innerHeight;

    let left = triggerRect.left;
    let top = triggerRect.bottom + 8;

    if (left + menuRect.width > viewportWidth - 12) {
      left = Math.max(12, viewportWidth - menuRect.width - 12);
    }

    if (top + menuRect.height > viewportHeight - 12) {
      top = Math.max(12, triggerRect.top - menuRect.height - 8);
    }

    menu.style.left = `${Math.round(left)}px`;
    menu.style.top = `${Math.round(top)}px`;
    menu.style.minWidth = `${Math.max(320, Math.round(triggerRect.width + 48))}px`;
  };

  const closeMenu = () => {
    wrapper.classList.remove("is-open");
    trigger.setAttribute("aria-expanded", "false");
    if (wrapper._menuPortal) {
      wrapper._menuPortal.remove();
      wrapper._menuPortal = null;
    }
  };

  wrapper._closeMenu = closeMenu;

  const openMenu = () => {
    closeOpenWorkOrderStatusMenus(wrapper);

    if (wrapper._menuPortal) {
      return;
    }

    let draftItems = getCurrentItems();
    let searchQuery = "";

    const menu = document.createElement("div");
    menu.className = "work-item-status-menu work-item-status-menu-portal work-order-service-picker-menu-portal";
    menu.setAttribute("role", "dialog");
    menu.setAttribute("aria-label", "Izbor usluga");

    ["pointerdown", "mousedown", "click", "keydown"].forEach((eventName) => {
      menu.addEventListener(eventName, (event) => {
        event.stopPropagation();
      });
    });

    const searchWrap = document.createElement("div");
    searchWrap.className = "work-order-service-picker-search";

    const searchInput = document.createElement("input");
    searchInput.type = "search";
    searchInput.className = "work-order-service-picker-search-input";
    searchInput.placeholder = "Traži po nazivu, šifri ili templateu";
    searchWrap.append(searchInput);

    const selection = document.createElement("div");
    selection.className = "work-order-service-picker-selection";

    const helper = document.createElement("p");
    helper.className = "work-order-service-picker-helper";

    const optionsList = document.createElement("div");
    optionsList.className = "work-order-service-picker-options";

    const clearButton = document.createElement("button");
    clearButton.type = "button";
    clearButton.className = "ghost-button work-order-service-picker-clear";
    clearButton.textContent = "Očisti";

    const toggleService = (service) => {
      const normalizedId = String(service.id || "").trim();
      const existing = draftItems.find((item) => String(item.serviceId) === normalizedId);

      if (existing) {
        draftItems = draftItems.filter((item) => String(item.serviceId) !== normalizedId);
        return;
      }

      draftItems = [
        ...draftItems,
        buildWorkOrderServiceItemSnapshot(service),
      ];
    };

    const syncMenuState = () => {
      selection.replaceChildren();

      if (draftItems.length === 0) {
        const empty = document.createElement("span");
        empty.className = "work-order-service-picker-selection-empty";
        empty.textContent = "Bez odabranih usluga";
        selection.append(empty);
      } else {
        draftItems.forEach((item) => {
          const chip = document.createElement("button");
          chip.type = "button";
          chip.className = `work-order-service-picker-selection-chip${item.isCompleted ? " is-completed" : ""}`;
          chip.textContent = item.serviceCode || item.name || "Usluga";
          chip.title = `Makni ${item.name || item.serviceCode}`;
          chip.addEventListener("click", () => {
            draftItems = draftItems.filter((entry) => String(entry.serviceId) !== String(item.serviceId));
            writeWorkOrderServiceSelection(draftItems, {
              dispatchEventName: "change",
              renderPicker: false,
            });
            draftItems = getCurrentItems();
            setCurrentItems(draftItems);
            syncMenuState();
          });
          selection.append(chip);
        });
      }

      optionsList.replaceChildren();
      const visibleOptions = getWorkOrderServiceCatalogOptions(draftItems)
        .filter((option) => matchesWorkOrderServiceSearch(option, searchQuery));

      if (visibleOptions.length === 0) {
        const empty = document.createElement("p");
        empty.className = "work-order-service-picker-empty";
        empty.textContent = "Nema usluga za ovaj pojam.";
        optionsList.append(empty);
      } else {
        visibleOptions.forEach((option) => {
          const isSelected = draftItems.some((item) => String(item.serviceId) === String(option.id));
          const optionButton = document.createElement("button");
          optionButton.type = "button";
          optionButton.className = `work-item-status-option work-order-service-picker-option${isSelected ? " is-selected" : ""}`;

          const copy = document.createElement("div");
          copy.className = "work-order-service-picker-option-copy";
          const title = document.createElement("strong");
          title.textContent = option.name || "Usluga";
          const meta = document.createElement("span");
          meta.textContent = [
            option.serviceCode || "",
            option.status === "inactive" ? "Neaktivna" : "Aktivna",
            (option.linkedTemplateTitles ?? []).length > 0 ? `${option.linkedTemplateTitles.length} templatea` : "",
          ].filter(Boolean).join(" · ");
          copy.append(title, meta);

          const marker = document.createElement("span");
          marker.className = "work-order-service-picker-option-marker";
          marker.textContent = isSelected ? "✓" : "+";

          optionButton.append(copy, marker);
          optionButton.addEventListener("click", () => {
            toggleService(option);
            writeWorkOrderServiceSelection(draftItems, {
              dispatchEventName: "change",
              renderPicker: false,
            });
            draftItems = getCurrentItems();
            setCurrentItems(draftItems);
            syncMenuState();
          });
          optionsList.append(optionButton);
        });
      }

      helper.textContent = draftItems.length > 0
        ? `${draftItems.length} odabranih usluga · ${getWorkOrderCompletedServiceCount({ serviceItems: draftItems })} označeno kao odrađeno.`
        : "Odaberi usluge iz kataloga i kasnije ih označavaj kvačicom ili X.";
      clearButton.disabled = draftItems.length === 0;
      requestAnimationFrame(() => positionMenuPortal(menu));
    };

    clearButton.addEventListener("click", () => {
      draftItems = [];
      writeWorkOrderServiceSelection([], {
        dispatchEventName: "change",
        renderPicker: false,
      });
      draftItems = getCurrentItems();
      setCurrentItems(draftItems);
      syncMenuState();
    });

    searchInput.addEventListener("input", () => {
      searchQuery = searchInput.value || "";
      syncMenuState();
    });

    searchInput.addEventListener("keydown", (event) => {
      if (event.key === "Escape") {
        event.preventDefault();
        closeMenu();
        trigger.focus({ preventScroll: true });
      }
    });

    menu.append(searchWrap, selection, helper, optionsList, clearButton);
    syncMenuState();
    document.body.append(menu);
    wrapper._menuPortal = menu;
    wrapper.classList.add("is-open");
    trigger.setAttribute("aria-expanded", "true");
    positionMenuPortal(menu);
    requestAnimationFrame(() => {
      positionMenuPortal(menu);
      searchInput.focus({ preventScroll: true });
      searchInput.select();
    });
  };

  trigger.addEventListener("click", (event) => {
    event.stopPropagation();
    if (wrapper._menuPortal) {
      closeOpenWorkOrderStatusMenus();
      return;
    }
    openMenu();
  });

  setCurrentItems(getCurrentItems());
  wrapper.append(trigger);
  workOrderServicePicker.replaceChildren(wrapper);
}

function getWorkOrderDocumentWizardResolvedServiceItems(workOrder = {}) {
  const normalizedId = String(workOrder?.id || "").trim();
  const override = normalizedId ? getWorkOrderDocumentWizardOverride(normalizedId) : null;
  if (override && Object.prototype.hasOwnProperty.call(override, "serviceItems")) {
    return getWorkOrderServiceItems({ serviceItems: override.serviceItems });
  }
  return getWorkOrderServiceItems(workOrder);
}

function createWorkOrderDocumentWizardServicePicker(workOrder = {}) {
  const wrapper = document.createElement("div");
  wrapper.className = "work-order-service-picker work-order-document-service-picker";
  wrapper.dataset.preventRowOpen = "true";

  const trigger = document.createElement("button");
  trigger.type = "button";
  trigger.className = "work-order-service-picker-trigger work-order-document-service-trigger";
  trigger.dataset.preventRowOpen = "true";
  trigger.setAttribute("aria-haspopup", "dialog");
  trigger.setAttribute("aria-expanded", "false");

  const getCurrentItems = () => getWorkOrderDocumentWizardResolvedServiceItems(workOrder);
  const setCurrentItems = (items) => {
    setWorkOrderServicePickerTriggerContent(trigger, items);
  };

  const positionMenuPortal = (menu) => {
    const triggerRect = trigger.getBoundingClientRect();
    const menuRect = menu.getBoundingClientRect();
    const viewportWidth = window.innerWidth;
    const viewportHeight = window.innerHeight;

    let left = triggerRect.left;
    let top = triggerRect.bottom + 8;

    if (left + menuRect.width > viewportWidth - 12) {
      left = Math.max(12, viewportWidth - menuRect.width - 12);
    }

    if (top + menuRect.height > viewportHeight - 12) {
      top = Math.max(12, triggerRect.top - menuRect.height - 8);
    }

    menu.style.left = `${Math.round(left)}px`;
    menu.style.top = `${Math.round(top)}px`;
    menu.style.minWidth = `${Math.max(340, Math.round(triggerRect.width + 48))}px`;
  };

  const closeMenu = ({ commit = true } = {}) => {
    if (commit && typeof wrapper._commitPendingChange === "function") {
      wrapper._commitPendingChange();
    }
    wrapper._commitPendingChange = null;
    wrapper.classList.remove("is-open");
    trigger.setAttribute("aria-expanded", "false");
    if (wrapper._menuPortal) {
      wrapper._menuPortal.remove();
      wrapper._menuPortal = null;
    }
  };

  wrapper._closeMenu = closeMenu;

  const openMenu = () => {
    closeOpenWorkOrderStatusMenus(wrapper);

    if (wrapper._menuPortal) {
      return;
    }

    let draftItems = getCurrentItems();
    let searchQuery = "";
    let hasPendingChange = false;

    const menu = document.createElement("div");
    menu.className = "work-item-status-menu work-item-status-menu-portal work-order-service-picker-menu-portal";
    menu.setAttribute("role", "dialog");
    menu.setAttribute(
      "aria-label",
      `Odabir usluga za RN ${workOrder.workOrderNumber || "bez broja"}`,
    );

    ["pointerdown", "mousedown", "click", "keydown"].forEach((eventName) => {
      menu.addEventListener(eventName, (event) => {
        event.stopPropagation();
      });
    });

    const searchWrap = document.createElement("div");
    searchWrap.className = "work-order-service-picker-search";

    const searchInput = document.createElement("input");
    searchInput.type = "search";
    searchInput.className = "work-order-service-picker-search-input";
    searchInput.placeholder = "Traži po nazivu, šifri ili templateu";
    searchWrap.append(searchInput);

    const selection = document.createElement("div");
    selection.className = "work-order-service-picker-selection work-order-document-service-selection";

    const helper = document.createElement("p");
    helper.className = "work-order-service-picker-helper";

    const optionsList = document.createElement("div");
    optionsList.className = "work-order-service-picker-options";

    const clearButton = document.createElement("button");
    clearButton.type = "button";
    clearButton.className = "ghost-button work-order-service-picker-clear";
    clearButton.textContent = "Očisti";

    const actions = document.createElement("div");
    actions.className = "work-order-service-picker-footer";
    const doneButton = document.createElement("button");
    doneButton.type = "button";
    doneButton.className = "primary-button work-order-service-picker-done";
    doneButton.textContent = "Gotovo";

    const commitItems = (nextItems) => {
      setWorkOrderDocumentWizardOverride(workOrder.id, {
        serviceItems: nextItems,
      });
      setCurrentItems(nextItems);
      renderWorkOrderDocumentWizard();
    };

    wrapper._commitPendingChange = () => {
      if (!hasPendingChange) {
        return;
      }
      hasPendingChange = false;
      commitItems(draftItems);
    };

    const toggleService = (service) => {
      const normalizedId = String(service?.id || service?.serviceId || "").trim();
      const existing = draftItems.find((item) => String(item.serviceId || "") === normalizedId);

      if (existing) {
        draftItems = draftItems.filter((item) => String(item.serviceId || "") !== normalizedId);
      } else {
        draftItems = [
          ...draftItems,
          buildWorkOrderServiceItemSnapshot(service, service),
        ];
      }

      hasPendingChange = true;
      setCurrentItems(draftItems);
      syncMenuState();
    };

    const syncMenuState = () => {
      selection.replaceChildren();

      if (draftItems.length === 0) {
        const empty = document.createElement("span");
        empty.className = "work-order-service-picker-selection-empty";
        empty.textContent = "Bez odabranih usluga";
        selection.append(empty);
      } else {
        draftItems.forEach((item) => {
          const chip = document.createElement("button");
          chip.type = "button";
          chip.className = `work-order-service-picker-selection-chip${item.isCompleted ? " is-completed" : ""}`;
          chip.textContent = item.serviceCode || item.name || "Usluga";
          chip.title = `Makni ${item.name || item.serviceCode || "uslugu"}`;
          chip.addEventListener("click", () => {
            draftItems = draftItems.filter((entry) => String(entry.serviceId || "") !== String(item.serviceId || ""));
            commitItems(draftItems);
          });
          selection.append(chip);
        });
      }

      optionsList.replaceChildren();
      const visibleOptions = getWorkOrderServiceCatalogOptions(draftItems)
        .filter((option) => matchesWorkOrderServiceSearch(option, searchQuery));

      if (visibleOptions.length === 0) {
        const empty = document.createElement("p");
        empty.className = "work-order-service-picker-empty";
        empty.textContent = "Nema usluga za ovaj pojam.";
        optionsList.append(empty);
      } else {
        visibleOptions.forEach((option) => {
          const normalizedOptionId = String(option.id || option.serviceId || "").trim();
          const isSelected = draftItems.some((item) => String(item.serviceId || "") === normalizedOptionId);
          const optionButton = document.createElement("button");
          optionButton.type = "button";
          optionButton.className = `work-item-status-option work-order-service-picker-option${isSelected ? " is-selected" : ""}`;

          const copy = document.createElement("div");
          copy.className = "work-order-service-picker-option-copy";

          const title = document.createElement("strong");
          title.textContent = option.name || option.serviceCode || "Usluga";

          const meta = document.createElement("span");
          meta.textContent = [
            option.serviceCode || "",
            option.status === "inactive" ? "Neaktivna" : "Aktivna",
            (option.linkedTemplateTitles ?? []).length > 0 ? `${option.linkedTemplateTitles.length} templatea` : "",
          ].filter(Boolean).join(", ");

          copy.append(title, meta);

          const marker = document.createElement("span");
          marker.className = "work-order-service-picker-option-marker";
          marker.textContent = isSelected ? "✓" : "+";

          optionButton.append(copy, marker);
          optionButton.addEventListener("click", () => {
            toggleService(option);
          });

          optionsList.append(optionButton);
        });
      }

      helper.textContent = draftItems.length > 0
        ? `${draftItems.length} odabranih usluga, ${getWorkOrderCompletedServiceCount({ serviceItems: draftItems })} označeno kao odrađeno.`
        : "Dodaj ili makni usluge iz kataloga za ovaj RN.";
      clearButton.disabled = draftItems.length === 0;
      requestAnimationFrame(() => positionMenuPortal(menu));
    };

    clearButton.addEventListener("click", () => {
      draftItems = [];
      hasPendingChange = true;
      setCurrentItems([]);
      syncMenuState();
    });

    searchInput.addEventListener("input", () => {
      searchQuery = searchInput.value || "";
      syncMenuState();
    });

    searchInput.addEventListener("keydown", (event) => {
      if (event.key === "Escape") {
        event.preventDefault();
        closeMenu();
        trigger.focus({ preventScroll: true });
        return;
      }

      if (event.key !== "Enter") {
        return;
      }

      const visibleOptions = getWorkOrderServiceCatalogOptions(draftItems)
        .filter((option) => matchesWorkOrderServiceSearch(option, searchQuery));

      if (visibleOptions.length !== 1) {
        return;
      }

      event.preventDefault();
      toggleService(visibleOptions[0]);
    });

    doneButton.addEventListener("click", (event) => {
      event.stopPropagation();
      closeMenu();
      trigger.focus({ preventScroll: true });
    });

    actions.append(clearButton, doneButton);
    menu.append(searchWrap, selection, helper, optionsList, actions);
    syncMenuState();

    document.body.append(menu);
    wrapper._menuPortal = menu;
    wrapper.classList.add("is-open");
    trigger.setAttribute("aria-expanded", "true");
    positionMenuPortal(menu);
    requestAnimationFrame(() => {
      positionMenuPortal(menu);
      searchInput.focus({ preventScroll: true });
      searchInput.select();
    });
  };

  ["pointerdown", "mousedown", "click", "keydown"].forEach((eventName) => {
    wrapper.addEventListener(eventName, (event) => {
      event.stopPropagation();
    });
  });

  trigger.addEventListener("click", (event) => {
    event.stopPropagation();
    if (wrapper._menuPortal) {
      closeOpenWorkOrderStatusMenus();
      return;
    }
    openMenu();
  });

  setCurrentItems(getCurrentItems());
  wrapper.append(trigger);
  return wrapper;
}

function getCompany(companyId) {
  return state.companies.find((item) => item.id === companyId) ?? null;
}

function getLocation(locationId) {
  return state.locations.find((item) => item.id === locationId) ?? null;
}

function getDocumentTemplateById(templateId) {
  return state.documentTemplates.find((item) => String(item.id) === String(templateId)) ?? null;
}

function getServiceCatalogItemForWorkOrderService(service = {}) {
  const normalizedServiceId = String(service?.serviceId ?? service?.id ?? "").trim();
  if (normalizedServiceId) {
    const byId = state.serviceCatalog.find((item) => String(item.id) === normalizedServiceId);
    if (byId) {
      return byId;
    }
  }

  const normalizedCode = normalizeLooseName(service?.serviceCode ?? "");
  const normalizedName = normalizeLooseName(service?.name ?? "");

  if (!normalizedCode && !normalizedName) {
    return null;
  }

  return state.serviceCatalog.find((item) => {
    const itemCode = normalizeLooseName(item?.serviceCode ?? "");
    const itemName = normalizeLooseName(item?.name ?? "");

    if (normalizedCode && itemCode === normalizedCode) {
      return true;
    }

    if (normalizedName && itemName === normalizedName) {
      return true;
    }

    return normalizedCode && normalizedName && itemCode === normalizedCode && itemName === normalizedName;
  }) ?? null;
}

function getResolvedWorkOrderServiceTemplateTitles(service = {}) {
  const titleSet = new Set(
    (Array.isArray(service?.linkedTemplateTitles) ? service.linkedTemplateTitles : [])
      .map((value) => String(value ?? "").trim())
      .filter(Boolean),
  );
  const resolvedTemplateIds = new Set(
    (Array.isArray(service?.linkedTemplateIds) ? service.linkedTemplateIds : [])
      .map((value) => String(value ?? "").trim())
      .filter(Boolean),
  );
  const linkedServiceCatalogItem = getServiceCatalogItemForWorkOrderService(service);

  (Array.isArray(linkedServiceCatalogItem?.linkedTemplateIds) ? linkedServiceCatalogItem.linkedTemplateIds : [])
    .map((value) => String(value ?? "").trim())
    .filter(Boolean)
    .forEach((value) => resolvedTemplateIds.add(value));

  (Array.isArray(linkedServiceCatalogItem?.linkedTemplateTitles) ? linkedServiceCatalogItem.linkedTemplateTitles : [])
    .map((value) => String(value ?? "").trim())
    .filter(Boolean)
    .forEach((value) => titleSet.add(value));

  resolvedTemplateIds.forEach((templateId) => {
    const template = getDocumentTemplateById(templateId);
    if (template?.title) {
      titleSet.add(String(template.title).trim());
    }
  });

  return [...titleSet];
}

function getLocationsForCompany(companyId) {
  return state.locations
    .filter((item) => item.companyId === companyId)
    .sort((left, right) => left.name.localeCompare(right.name, "hr"));
}

function getWorkOrderTeamOptions() {
  return Array.from(new Set(
    state.workOrders
      .map((item) => String(item.teamLabel ?? "").trim())
      .filter(Boolean),
  )).sort((left, right) => left.localeCompare(right, "hr"));
}

function refreshWorkOrderTeamSuggestions() {
  if (!workOrderTeamSuggestions) {
    return;
  }

  workOrderTeamSuggestions.replaceChildren(
    ...getWorkOrderTeamOptions().map((label) => {
      const option = document.createElement("option");
      option.value = label;
      return option;
    }),
  );
}

function buildDefaultMeasurementColumns() {
  return DEFAULT_MEASUREMENT_COLUMNS.map((column) => ({ ...column }));
}

function normalizeMeasurementSheetValidationOptionsLocal(values = []) {
  return Array.from(new Set((Array.isArray(values) ? values : String(values ?? "")
    .split(/[\n,;|]/))
    .map((value) => String(value ?? "").trim())
    .filter(Boolean)))
    .slice(0, 160);
}

function normalizeMeasurementSheetColumnValidationSnapshotLocal(input = {}, availableColumnIds = new Set(), columnId = "") {
  const source = input && typeof input === "object" ? input : {};
  const type = String(source?.type || "").trim().toLowerCase() === "list" ? "list" : "none";
  const sourceMode = String(source?.sourceMode || "").trim().toLowerCase() === "custom" ? "custom" : "column";
  const sourceColumnId = String(source?.sourceColumnId || "").trim();
  const normalizedSourceColumnId = sourceMode === "column"
    && sourceColumnId
    && (!availableColumnIds.size || availableColumnIds.has(sourceColumnId))
    ? sourceColumnId
    : (sourceMode === "column" && columnId && (!availableColumnIds.size || availableColumnIds.has(columnId))
      ? columnId
      : "");

  if (type !== "list") {
    return {
      type: "none",
      sourceMode: "column",
      sourceColumnId: "",
      options: [],
      allowCustom: true,
    };
  }

  return {
    type: "list",
    sourceMode,
    sourceColumnId: sourceMode === "column" ? normalizedSourceColumnId : "",
    options: sourceMode === "custom"
      ? normalizeMeasurementSheetValidationOptionsLocal(source?.options)
      : [],
    allowCustom: Boolean(source?.allowCustom ?? true),
  };
}

function createMeasurementColumn(partial = {}) {
  measurementColumnCounter += 1;
  const fallbackId = partial.id || `measurement-custom-${measurementColumnCounter}`;

  return {
    id: fallbackId,
    label: partial.label || `Kolona ${measurementColumnCounter}`,
    placeholder: partial.placeholder || "Unos",
    width: partial.width || 160,
    computed: partial.computed || null,
    readonly: Boolean(partial.readonly),
    validation: normalizeMeasurementSheetColumnValidationSnapshotLocal(
      partial.validation,
      new Set([fallbackId]),
      fallbackId,
    ),
  };
}

function createMeasurementRow(partialCells = {}, partialFormats = {}) {
  measurementRowCounter += 1;

  const cells = {};
  const formats = {};

  state.measurementSheet.columns
    .filter((column) => !column.computed)
    .forEach((column) => {
      cells[column.id] = partialCells[column.id] ?? "";
      formats[column.id] = normalizeMeasurementCellFormat(partialFormats[column.id]);
    });

  return {
    id: `measurement-row-${measurementRowCounter}`,
    cells,
    formats,
  };
}

function buildDefaultMeasurementRows(count = DEFAULT_MEASUREMENT_ROW_COUNT) {
  return Array.from({ length: count }, () => createMeasurementRow());
}

function normalizeMeasurementSheetColumnSnapshotLocal(column = {}, index = 0) {
  const width = Number(column?.width);
  const columnId = String(column?.id || `measurement-column-${index + 1}`).trim() || `measurement-column-${index + 1}`;
  return {
    id: columnId,
    label: String(column?.label || `Kolona ${index + 1}`).trim() || `Kolona ${index + 1}`,
    placeholder: String(column?.placeholder || "").trim(),
    width: Number.isFinite(width) ? Math.min(640, Math.max(72, Math.round(width))) : 160,
    computed: typeof column?.computed === "string" && column.computed ? column.computed : null,
    readonly: Boolean(column?.readonly),
    validation: normalizeMeasurementSheetColumnValidationSnapshotLocal(
      column?.validation,
      new Set([columnId]),
      columnId,
    ),
  };
}

function normalizeMeasurementSheetRowSnapshotLocal(row = {}, columns = [], index = 0) {
  const editableColumns = columns.filter((column) => !column.computed);
  const cells = {};
  const formats = {};

  editableColumns.forEach((column) => {
    cells[column.id] = String(row?.cells?.[column.id] ?? "");
    formats[column.id] = normalizeMeasurementCellFormat(row?.formats?.[column.id]);
  });

  return {
    id: String(row?.id || `measurement-row-${index + 1}`).trim() || `measurement-row-${index + 1}`,
    cells,
    formats,
  };
}

function normalizeMeasurementSheetHeaderRowsSnapshotLocal(values = [], rows = []) {
  const rowIds = new Set((Array.isArray(rows) ? rows : []).map((row) => row.id));
  return Array.from(new Set((Array.isArray(values) ? values : [])
    .map((value) => String(value || "").trim())
    .filter((value) => value && rowIds.has(value))));
}

function normalizeMeasurementSheetMergeSnapshotLocal(merge = {}, rows = [], columns = []) {
  const rowId = String(merge?.rowId || "").trim();
  const columnId = String(merge?.columnId || "").trim();
  const rowSpan = Number.parseInt(merge?.rowSpan, 10);
  const colSpan = Number.parseInt(merge?.colSpan, 10);
  const rowIds = new Set(rows.map((row) => row.id));
  const columnIds = new Set(columns.filter((column) => !column.computed).map((column) => column.id));

  if (!rowId || !columnId || !rowIds.has(rowId) || !columnIds.has(columnId)) {
    return null;
  }

  const normalizedRowSpan = Number.isInteger(rowSpan) ? Math.max(1, Math.min(200, rowSpan)) : 1;
  const normalizedColSpan = Number.isInteger(colSpan) ? Math.max(1, Math.min(32, colSpan)) : 1;

  if (normalizedRowSpan <= 1 && normalizedColSpan <= 1) {
    return null;
  }

  return {
    rowId,
    columnId,
    rowSpan: normalizedRowSpan,
    colSpan: normalizedColSpan,
  };
}

function buildTemplateMeasurementSheetFromLegacyConfig(field = {}) {
  const rawColumns = Array.isArray(field?.columns)
    ? field.columns
    : String(field?.columns ?? "")
      .split(/[\n,]/)
      .map((entry) => entry.trim())
      .filter(Boolean);
  const columns = (rawColumns.length > 0 ? rawColumns : DEFAULT_MEASUREMENT_COLUMNS.map((column) => column.label))
    .slice(0, 16)
    .map((label, index) => normalizeMeasurementSheetColumnSnapshotLocal({
      id: `measurement-column-${index + 1}`,
      label,
      placeholder: label,
      width: index === 0 ? 220 : 160,
    }, index));
  const rowCount = Math.max(4, Math.min(120, Math.round(Number(field?.rowCount) || 12)));
  const rows = Array.from({ length: rowCount }, (_, index) => normalizeMeasurementSheetRowSnapshotLocal({
    id: `measurement-row-${index + 1}`,
  }, columns, index));

  return {
    columns,
    rows,
    merges: [],
    headerRows: [],
  };
}

function ensureDocumentTemplateMeasurementFieldSheet(field = {}) {
  if (field?.type !== "measurement_table") {
    return null;
  }

  return normalizeWorkOrderMeasurementSheet(field.sheet ?? field.measurementSheet)
    ?? buildTemplateMeasurementSheetFromLegacyConfig(field);
}

function isMeasurementFormatCustomized(format = {}) {
  const normalized = normalizeMeasurementCellFormat(format);
  return normalized.type !== "general"
    || normalized.decimals !== 2
    || normalized.border.top
    || normalized.border.right
    || normalized.border.bottom
    || normalized.border.left;
}

function isMeasurementSheetRowMeaningful(row = {}, columns = []) {
  return columns
    .filter((column) => !column.computed)
    .some((column) => (
      String(row?.cells?.[column.id] ?? "").trim()
      || isMeasurementFormatCustomized(row?.formats?.[column.id])
    ));
}

function isMeasurementSheetStructureCustomized(columns = []) {
  if (columns.length !== DEFAULT_MEASUREMENT_COLUMNS.length) {
    return true;
  }

  return columns.some((column, index) => {
    const baseline = DEFAULT_MEASUREMENT_COLUMNS[index] ?? {};
    return String(column.id || "") !== String(baseline.id || "")
      || String(column.label || "") !== String(baseline.label || "")
      || String(column.placeholder || "") !== String(baseline.placeholder || "")
      || Number(column.width || 0) !== Number(baseline.width || 0)
      || String(column.computed || "") !== String(baseline.computed || "")
      || Boolean(column.readonly) !== Boolean(baseline.readonly);
  });
}

function syncMeasurementSheetCountersFromState() {
  const columnMax = state.measurementSheet.columns.reduce((maxValue, column) => {
    const match = String(column?.id || "").match(/^measurement-custom-(\d+)$/);
    return match ? Math.max(maxValue, Number(match[1])) : maxValue;
  }, 0);
  const rowMax = state.measurementSheet.rows.reduce((maxValue, row) => {
    const match = String(row?.id || "").match(/^measurement-row-(\d+)$/);
    return match ? Math.max(maxValue, Number(match[1])) : maxValue;
  }, 0);

  measurementColumnCounter = Math.max(measurementColumnCounter, columnMax);
  measurementRowCounter = Math.max(measurementRowCounter, rowMax);
}

function getMeasurementSheetTemplateSummary(sheet = null) {
  const normalized = normalizeWorkOrderMeasurementSheet(sheet);

  if (!normalized?.columns?.length) {
    return "Prazan Excel blok";
  }

  const populatedRows = normalized.rows.reduce((count, row) => (
    isMeasurementSheetRowMeaningful(row, normalized.columns) ? count + 1 : count
  ), 0);
  const mergeCount = Array.isArray(normalized.merges) ? normalized.merges.length : 0;

  return [
    `${normalized.columns.length} kolona`,
    populatedRows > 0 ? `${populatedRows} popunjenih redova` : "spreman za unos",
    mergeCount > 0 ? `${mergeCount} merge` : "",
  ].filter(Boolean).join(" · ");
}

function applyMeasurementSheetSnapshot(snapshot = null) {
  clearScheduledMeasurementSheetRefresh();
  const normalized = normalizeWorkOrderMeasurementSheet(snapshot);
  const columns = normalized?.columns?.length
    ? normalized.columns.map((column, index) => normalizeMeasurementSheetColumnSnapshotLocal(column, index))
    : buildDefaultMeasurementColumns();
  const editableColumnIds = new Set(columns.filter((column) => !column.computed).map((column) => column.id));
  const normalizedColumns = columns.map((column) => ({
    ...column,
    validation: normalizeMeasurementSheetColumnValidationSnapshotLocal(
      column.validation,
      editableColumnIds,
      column.id,
    ),
  }));
  const rows = normalized?.rows?.length
    ? normalized.rows.map((row, index) => normalizeMeasurementSheetRowSnapshotLocal(row, normalizedColumns, index))
    : Array.from({ length: DEFAULT_MEASUREMENT_ROW_COUNT }, () => createMeasurementRow());
  const merges = (normalized?.merges ?? [])
    .map((merge) => normalizeMeasurementSheetMergeSnapshotLocal(merge, rows, normalizedColumns))
    .filter(Boolean);
  const headerRows = normalizeMeasurementSheetHeaderRowsSnapshotLocal(normalized?.headerRows, rows);

  state.measurementSheet.columns = normalizedColumns;
  state.measurementSheet.rows = rows;
  state.measurementSheet.merges = merges;
  state.measurementSheet.headerRows = headerRows;
  state.measurementSheet.resizing = null;
  state.measurementSheet.activeCell = null;
  state.measurementSheet.editingCell = null;
  state.measurementSheet.editorSource = null;
  state.measurementSheet.formulaReferences = [];
  state.measurementSheet.selectionAnchor = null;
  state.measurementSheet.selectedRange = null;
  state.measurementSheet.selectionDrag = null;
  state.measurementSheet.fillDrag = null;
  state.measurementSheet.fillMenu = null;
  state.measurementSheet.contextMenu = null;
  syncMeasurementSheetCountersFromState();
  syncMeasurementSheetHeaderFromWorkOrder();

  if (state.measurementSheet.isOpen) {
    renderMeasurementSheet();
  }
}

function buildMeasurementSheetSnapshot({ includeBlankStructure = false } = {}) {
  ensureMeasurementSheetStructure();
  const columns = state.measurementSheet.columns.map((column, index) => normalizeMeasurementSheetColumnSnapshotLocal(column, index));
  const rows = state.measurementSheet.rows.map((row, index) => normalizeMeasurementSheetRowSnapshotLocal(row, columns, index));
  const merges = (state.measurementSheet.merges ?? [])
    .map((merge) => normalizeMeasurementSheetMergeSnapshotLocal(merge, rows, columns))
    .filter(Boolean);
  const headerRows = normalizeMeasurementSheetHeaderRowsSnapshotLocal(state.measurementSheet.headerRows, rows);
  const lastMeaningfulRowIndex = rows.reduce((lastIndex, row, index) => (
    isMeasurementSheetRowMeaningful(row, columns) ? index : lastIndex
  ), -1);
  const hasMeaningfulRows = lastMeaningfulRowIndex >= 0;
  const hasCustomStructure = isMeasurementSheetStructureCustomized(columns);

  if (!includeBlankStructure && !hasMeaningfulRows && !hasCustomStructure && merges.length === 0 && headerRows.length === 0) {
    return null;
  }

  const keepRowCount = hasMeaningfulRows
    ? Math.max(DEFAULT_MEASUREMENT_ROW_COUNT, Math.min(rows.length, lastMeaningfulRowIndex + 4))
    : Math.max(DEFAULT_MEASUREMENT_ROW_COUNT, Math.min(rows.length || DEFAULT_MEASUREMENT_ROW_COUNT, 40));

  return {
    columns,
    rows: rows.slice(0, keepRowCount),
    merges,
    headerRows: normalizeMeasurementSheetHeaderRowsSnapshotLocal(headerRows, rows.slice(0, keepRowCount)),
  };
}

function parseMeasurementNumber(value) {
  const normalized = String(value ?? "").trim().replace(",", ".");

  if (!normalized) {
    return null;
  }

  const parsed = Number(normalized);
  return Number.isFinite(parsed) ? parsed : null;
}

function normalizeMeasurementDecimals(value) {
  return normalizeMeasurementCellFormat({ decimals: value }).decimals;
}

function normalizeMeasurementLiteralValue(rawValue) {
  const stringValue = String(rawValue ?? "").trim();

  if (!stringValue) {
    return "";
  }

  if (stringValue.toUpperCase() === "TRUE") {
    return true;
  }

  if (stringValue.toUpperCase() === "FALSE") {
    return false;
  }

  const numericPattern = /^[+-]?(?:\d+(?:[.,]\d+)?|[.,]\d+)$/;

  if (numericPattern.test(stringValue)) {
    const numericValue = parseMeasurementNumber(stringValue);

    if (numericValue !== null) {
      return numericValue;
    }
  }

  return rawValue ?? "";
}

function getMeasurementAverageValue(row) {
  const values = ["reading1", "reading2", "reading3"]
    .map((key) => parseMeasurementNumber(row.cells?.[key]))
    .filter((value) => value !== null);

  if (values.length === 0) {
    return null;
  }

  return values.reduce((sum, value) => sum + value, 0) / values.length;
}

function formatMeasurementAverage(row) {
  const average = getMeasurementAverageValue(row);

  if (average === null) {
    return "";
  }

  return new Intl.NumberFormat("hr-HR", {
    minimumFractionDigits: 0,
    maximumFractionDigits: 2,
  }).format(average);
}

function formatCurrencyAmount(value, currency = "EUR") {
  return new Intl.NumberFormat("hr-HR", {
    style: "currency",
    currency,
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(Number(value ?? 0) || 0);
}

function roundMoneyAmount(value) {
  return Math.round((Number(value ?? 0) || 0) * 100) / 100;
}

function getSpreadsheetColumnLabel(index) {
  let value = index + 1;
  let label = "";

  while (value > 0) {
    const remainder = (value - 1) % 26;
    label = String.fromCharCode(65 + remainder) + label;
    value = Math.floor((value - 1) / 26);
  }

  return label;
}

function ensureMeasurementSheetStructure() {
  if (state.measurementSheet.columns.length === 0) {
    state.measurementSheet.columns = buildDefaultMeasurementColumns();
  }

  state.measurementSheet.rows.forEach((row) => {
    if (!row.cells || typeof row.cells !== "object") {
      row.cells = {};
    }

    if (!row.formats || typeof row.formats !== "object") {
      row.formats = {};
    }

    state.measurementSheet.columns
      .filter((column) => !column.computed)
      .forEach((column) => {
        if (!(column.id in row.cells)) {
          row.cells[column.id] = "";
        }

        row.formats[column.id] = normalizeMeasurementCellFormat(row.formats[column.id]);
      });
  });

  if (state.measurementSheet.rows.length === 0) {
    state.measurementSheet.rows = buildDefaultMeasurementRows();
  }

  state.measurementSheet.merges = (state.measurementSheet.merges ?? [])
    .map((merge) => normalizeMeasurementSheetMergeSnapshotLocal(
      merge,
      state.measurementSheet.rows,
      state.measurementSheet.columns,
    ))
    .filter(Boolean);
  state.measurementSheet.headerRows = normalizeMeasurementSheetHeaderRowsSnapshotLocal(
    state.measurementSheet.headerRows,
    state.measurementSheet.rows,
  );
  ensureMeasurementMinimumRows(MIN_VISIBLE_MEASUREMENT_ROWS);
}

function getMeasurementColumnIndex(columnId) {
  return state.measurementSheet.columns.findIndex((column) => column.id === columnId);
}

function getMeasurementRowIndex(rowId) {
  return state.measurementSheet.rows.findIndex((row) => row.id === rowId);
}

function createMeasurementSelectionRange(startRowIndex, startColumnIndex, endRowIndex, endColumnIndex) {
  return {
    startRowIndex: Math.min(startRowIndex, endRowIndex),
    endRowIndex: Math.max(startRowIndex, endRowIndex),
    startColumnIndex: Math.min(startColumnIndex, endColumnIndex),
    endColumnIndex: Math.max(startColumnIndex, endColumnIndex),
  };
}

function getMeasurementSelectedRange() {
  if (state.measurementSheet.selectedRange) {
    return state.measurementSheet.selectedRange;
  }

  const activeCell = state.measurementSheet.activeCell;

  if (!activeCell) {
    return null;
  }

  const rowIndex = getMeasurementRowIndex(activeCell.rowId);
  const columnIndex = getMeasurementColumnIndex(activeCell.columnId);

  if (rowIndex < 0 || columnIndex < 0) {
    return null;
  }

  return createMeasurementSelectionRange(rowIndex, columnIndex, rowIndex, columnIndex);
}

function getMeasurementMergeDescriptor(merge = {}) {
  const anchorRowIndex = getMeasurementRowIndex(merge.rowId);
  const anchorColumnIndex = getMeasurementColumnIndex(merge.columnId);

  if (anchorRowIndex < 0 || anchorColumnIndex < 0) {
    return null;
  }

  const maxRowSpan = Math.max(1, Math.min(Number(merge.rowSpan) || 1, state.measurementSheet.rows.length - anchorRowIndex));
  const maxColSpan = Math.max(1, Math.min(Number(merge.colSpan) || 1, state.measurementSheet.columns.length - anchorColumnIndex));

  if (maxRowSpan <= 1 && maxColSpan <= 1) {
    return null;
  }

  return {
    rowId: merge.rowId,
    columnId: merge.columnId,
    rowSpan: maxRowSpan,
    colSpan: maxColSpan,
    anchorRowIndex,
    anchorColumnIndex,
    endRowIndex: anchorRowIndex + maxRowSpan - 1,
    endColumnIndex: anchorColumnIndex + maxColSpan - 1,
  };
}

function getMeasurementMergeDescriptors() {
  return (state.measurementSheet.merges ?? [])
    .map((merge) => getMeasurementMergeDescriptor(merge))
    .filter(Boolean);
}

function getMeasurementMergeAtPosition(rowIndex, columnIndex) {
  return getMeasurementMergeDescriptors().find((merge) => (
    rowIndex >= merge.anchorRowIndex
    && rowIndex <= merge.endRowIndex
    && columnIndex >= merge.anchorColumnIndex
    && columnIndex <= merge.endColumnIndex
  )) ?? null;
}

function rangesIntersect(left, right) {
  return left.startRowIndex <= right.endRowIndex
    && left.endRowIndex >= right.startRowIndex
    && left.startColumnIndex <= right.endColumnIndex
    && left.endColumnIndex >= right.startColumnIndex;
}

function getMeasurementMergedSelectionDescriptor(range = getMeasurementSelectedRange()) {
  if (!range) {
    return null;
  }

  return getMeasurementMergeDescriptors().find((merge) => rangesIntersect(range, {
    startRowIndex: merge.anchorRowIndex,
    endRowIndex: merge.endRowIndex,
    startColumnIndex: merge.anchorColumnIndex,
    endColumnIndex: merge.endColumnIndex,
  })) ?? null;
}

function canMergeMeasurementSelection(range = getMeasurementSelectedRange()) {
  if (!range) {
    return false;
  }

  if (range.startRowIndex === range.endRowIndex && range.startColumnIndex === range.endColumnIndex) {
    return false;
  }

  for (let columnIndex = range.startColumnIndex; columnIndex <= range.endColumnIndex; columnIndex += 1) {
    if (state.measurementSheet.columns[columnIndex]?.computed) {
      return false;
    }
  }

  return true;
}

function mergeMeasurementSelection() {
  const range = getMeasurementSelectedRange();

  if (!canMergeMeasurementSelection(range)) {
    return;
  }

  unmergeMeasurementSelection({ preserveSelection: true, suppressPersistence: true });
  const anchorRow = state.measurementSheet.rows[range.startRowIndex];
  const anchorColumn = state.measurementSheet.columns[range.startColumnIndex];

  if (!anchorRow || !anchorColumn) {
    return;
  }

  for (let rowIndex = range.startRowIndex; rowIndex <= range.endRowIndex; rowIndex += 1) {
    const row = state.measurementSheet.rows[rowIndex];

    if (!row?.cells) {
      continue;
    }

    for (let columnIndex = range.startColumnIndex; columnIndex <= range.endColumnIndex; columnIndex += 1) {
      if (rowIndex === range.startRowIndex && columnIndex === range.startColumnIndex) {
        continue;
      }

      const column = state.measurementSheet.columns[columnIndex];

      if (!column || column.computed) {
        continue;
      }

      row.cells[column.id] = "";
      row.formats = row.formats ?? {};
      row.formats[column.id] = normalizeMeasurementCellFormat();
    }
  }

  state.measurementSheet.merges = [
    ...(state.measurementSheet.merges ?? []),
    {
      rowId: anchorRow.id,
      columnId: anchorColumn.id,
      rowSpan: range.endRowIndex - range.startRowIndex + 1,
      colSpan: range.endColumnIndex - range.startColumnIndex + 1,
    },
  ];
  renderMeasurementSheet();
  handleMeasurementSheetMutation();
}

function unmergeMeasurementSelection({ preserveSelection = false, suppressPersistence = false } = {}) {
  const range = getMeasurementSelectedRange();

  if (!range) {
    return;
  }

  const merges = getMeasurementMergeDescriptors();
  const toRemove = merges.filter((merge) => rangesIntersect(range, {
    startRowIndex: merge.anchorRowIndex,
    endRowIndex: merge.endRowIndex,
    startColumnIndex: merge.anchorColumnIndex,
    endColumnIndex: merge.endColumnIndex,
  }));

  if (toRemove.length === 0) {
    return;
  }

  const removedKeys = new Set(toRemove.map((merge) => `${merge.rowId}:${merge.columnId}`));
  state.measurementSheet.merges = (state.measurementSheet.merges ?? []).filter((merge) => (
    !removedKeys.has(`${merge.rowId}:${merge.columnId}`)
  ));

  if (!preserveSelection) {
    renderMeasurementSheet();
  } else {
    renderMeasurementSelection();
  }
  if (!suppressPersistence) {
    handleMeasurementSheetMutation();
  }
}

function getMeasurementCellElement(rowId, columnId) {
  return measurementSheetBody?.querySelector(
    `td[data-row-id="${CSS.escape(rowId)}"][data-column-id="${CSS.escape(columnId)}"]`,
  ) ?? null;
}

function getMeasurementInputElement(rowId, columnId) {
  return getMeasurementCellElement(rowId, columnId)?.querySelector(".measurement-cell-input") ?? null;
}

function isMeasurementInputElement(element) {
  return element instanceof HTMLInputElement && element.classList.contains("measurement-cell-input");
}

function getMeasurementFormulaInputElement() {
  if (!state.measurementSheet.editingCell) {
    return null;
  }

  if (state.measurementSheet.editorSource === "formula-bar") {
    return measurementFormulaInput;
  }

  return getMeasurementInputElement(
    state.measurementSheet.editingCell.rowId,
    state.measurementSheet.editingCell.columnId,
  );
}

function isMeasurementFormulaEditingActive() {
  const formulaInput = getMeasurementFormulaInputElement();
  return formulaInput instanceof HTMLInputElement && isMeasurementFormula(formulaInput.value);
}

function isMeasurementFormulaBarActive() {
  return document.activeElement === measurementFormulaInput;
}

function getMeasurementCellReference(rowIndex, columnIndex) {
  return formatMeasurementCellReference(rowIndex, columnIndex);
}

function getMeasurementSelectionLabel() {
  const range = getMeasurementSelectedRange();

  if (!range) {
    return "";
  }

  const startReference = getMeasurementCellReference(range.startRowIndex, range.startColumnIndex);
  const endReference = getMeasurementCellReference(range.endRowIndex, range.endColumnIndex);
  return startReference === endReference ? startReference : `${startReference}:${endReference}`;
}

function getNextMeasurementOptionValue(currentValue, orderedValues, step = 1) {
  if (!Array.isArray(orderedValues) || orderedValues.length === 0) {
    return currentValue;
  }

  const currentIndex = orderedValues.indexOf(currentValue);
  const normalizedIndex = currentIndex >= 0 ? currentIndex : 0;
  const nextIndex = (normalizedIndex + step + orderedValues.length) % orderedValues.length;
  return orderedValues[nextIndex];
}

function formatMeasurementDecimalsBadge(decimals) {
  const normalized = Math.max(0, normalizeMeasurementDecimals(decimals));
  return normalized > 0 ? `0,${"0".repeat(normalized)}` : "0";
}

function setMeasurementToolbarButtonPresentation(button, icon, label) {
  if (!(button instanceof HTMLButtonElement)) {
    return;
  }

  button.textContent = icon;
  button.title = label;
  button.setAttribute("aria-label", label);
}

function getMeasurementActiveCellPosition() {
  const activeCell = state.measurementSheet.activeCell;

  if (!activeCell) {
    return null;
  }

  const rowIndex = getMeasurementRowIndex(activeCell.rowId);
  const columnIndex = getMeasurementColumnIndex(activeCell.columnId);

  if (rowIndex < 0 || columnIndex < 0) {
    return null;
  }

  return {
    rowIndex,
    columnIndex,
    row: state.measurementSheet.rows[rowIndex] ?? null,
    column: state.measurementSheet.columns[columnIndex] ?? null,
  };
}

function getMeasurementCellFormat(rowIndex, columnIndex) {
  const row = state.measurementSheet.rows[rowIndex];
  const column = state.measurementSheet.columns[columnIndex];

  if (!row || !column || column.computed) {
    return normalizeMeasurementCellFormat();
  }

  return normalizeMeasurementCellFormat(row.formats?.[column.id]);
}

function buildMeasurementBorderFromPreset(preset, range, rowIndex, columnIndex) {
  if (preset === "outline") {
    return normalizeMeasurementBorder({
      top: rowIndex === range.startRowIndex,
      right: columnIndex === range.endColumnIndex,
      bottom: rowIndex === range.endRowIndex,
      left: columnIndex === range.startColumnIndex,
    });
  }

  return normalizeMeasurementBorder(preset);
}

function getMeasurementCellStyleConfig(format = {}) {
  const normalized = normalizeMeasurementCellFormat(format);
  const textAlign = normalized.align !== "auto"
    ? normalized.align
    : (["number", "integer", "percent"].includes(normalized.type) ? "right" : "left");

  return {
    textAlign,
    fontFamily: MEASUREMENT_FONT_FAMILY_STYLES[normalized.fontFamily] || MEASUREMENT_FONT_FAMILY_STYLES.default,
    fontSize: `${normalized.fontSize}px`,
    fontWeight: normalized.bold ? "700" : "400",
    fontStyle: normalized.italic ? "italic" : "normal",
    textDecoration: normalized.underline ? "underline" : "none",
    fillColor: normalized.fillColor || "",
  };
}

function applyMeasurementCellStyleToElements(cell, input, format = {}) {
  const styleConfig = getMeasurementCellStyleConfig(format);

  if (cell instanceof HTMLElement) {
    cell.style.backgroundColor = styleConfig.fillColor || "";
    cell.style.textAlign = styleConfig.textAlign;
  }

  if (input instanceof HTMLElement) {
    input.style.textAlign = styleConfig.textAlign;
    input.style.fontFamily = styleConfig.fontFamily;
    input.style.fontSize = styleConfig.fontSize;
    input.style.fontWeight = styleConfig.fontWeight;
    input.style.fontStyle = styleConfig.fontStyle;
    input.style.textDecoration = styleConfig.textDecoration;
  }
}

function applyMeasurementCellBorderStyle(cell, border = {}) {
  if (!(cell instanceof HTMLElement)) {
    return;
  }

  const normalized = normalizeMeasurementBorder(border);
  const baseColor = "rgba(17, 17, 17, 0.12)";
  const activeColor = "rgba(17, 17, 17, 0.96)";
  cell.style.borderTop = `${normalized.top ? 2 : 1}px solid ${normalized.top ? activeColor : baseColor}`;
  cell.style.borderRight = `${normalized.right ? 2 : 1}px solid ${normalized.right ? activeColor : baseColor}`;
  cell.style.borderBottom = `${normalized.bottom ? 2 : 1}px solid ${normalized.bottom ? activeColor : baseColor}`;
  cell.style.borderLeft = `${normalized.left ? 2 : 1}px solid ${normalized.left ? activeColor : baseColor}`;
}

function isMeasurementHeaderRow(rowId = "") {
  return state.measurementSheet.headerRows.includes(String(rowId || ""));
}

function toggleMeasurementHeaderRows() {
  const range = getMeasurementSelectedRange();

  if (!range) {
    return;
  }

  const selectedRowIds = state.measurementSheet.rows
    .slice(range.startRowIndex, range.endRowIndex + 1)
    .map((row) => row?.id)
    .filter(Boolean);

  if (selectedRowIds.length === 0) {
    return;
  }

  const allSelectedAreHeaders = selectedRowIds.every((rowId) => isMeasurementHeaderRow(rowId));
  const nextHeaderRows = new Set(state.measurementSheet.headerRows);

  selectedRowIds.forEach((rowId) => {
    if (allSelectedAreHeaders) {
      nextHeaderRows.delete(rowId);
    } else {
      nextHeaderRows.add(rowId);
    }
  });

  state.measurementSheet.headerRows = normalizeMeasurementSheetHeaderRowsSnapshotLocal(
    state.measurementSheet.rows
      .map((row) => row.id)
      .filter((rowId) => nextHeaderRows.has(rowId)),
    state.measurementSheet.rows,
  );
  renderMeasurementSheet();
  handleMeasurementSheetMutation();
  return !allSelectedAreHeaders;
}

function getMeasurementBorderShadow(border) {
  const normalized = normalizeMeasurementBorder(border);
  const parts = [];
  const borderColor = "rgba(17, 17, 17, 0.96)";

  if (normalized.top) {
    parts.push(`inset 0 2px 0 0 ${borderColor}`);
  }

  if (normalized.right) {
    parts.push(`inset -2px 0 0 0 ${borderColor}`);
  }

  if (normalized.bottom) {
    parts.push(`inset 0 -2px 0 0 ${borderColor}`);
  }

  if (normalized.left) {
    parts.push(`inset 2px 0 0 0 ${borderColor}`);
  }

  return parts.length > 0 ? parts.join(", ") : "none";
}

function getMeasurementSelectedColumnIndexes(range = getMeasurementSelectedRange()) {
  if (!range) {
    return [];
  }

  const indexes = [];
  for (let columnIndex = range.startColumnIndex; columnIndex <= range.endColumnIndex; columnIndex += 1) {
    const column = state.measurementSheet.columns[columnIndex];
    if (column && !column.computed) {
      indexes.push(columnIndex);
    }
  }
  return indexes;
}

function getMeasurementValidationTargetColumnIndexes() {
  const selected = getMeasurementSelectedColumnIndexes();

  if (selected.length > 0) {
    return selected;
  }

  const activePosition = getMeasurementActiveCellPosition();
  if (!activePosition?.column || activePosition.column.computed) {
    return [];
  }

  return [activePosition.columnIndex];
}

function getMeasurementPrimaryValidationColumn() {
  const [columnIndex] = getMeasurementValidationTargetColumnIndexes();
  return Number.isInteger(columnIndex) ? state.measurementSheet.columns[columnIndex] ?? null : null;
}

function getMeasurementColumnValidationOptions(column = null) {
  const targetColumn = column && typeof column === "object"
    ? column
    : getMeasurementPrimaryValidationColumn();

  if (!targetColumn) {
    return [];
  }

  const validation = normalizeMeasurementSheetColumnValidationSnapshotLocal(
    targetColumn.validation,
    new Set(state.measurementSheet.columns.filter((entry) => !entry.computed).map((entry) => entry.id)),
    targetColumn.id,
  );

  if (validation.type !== "list") {
    return [];
  }

  if (validation.sourceMode === "custom") {
    return validation.options ?? [];
  }

  const sourceColumnId = validation.sourceColumnId || targetColumn.id;

  return Array.from(new Set(
    state.measurementSheet.rows
      .map((row) => String(row?.cells?.[sourceColumnId] ?? "").trim())
      .filter(Boolean),
  ));
}

function isMeasurementValidationValueAllowed(column = null, value = "") {
  const normalizedValue = String(value ?? "").trim();
  if (!normalizedValue || isMeasurementFormula(normalizedValue)) {
    return true;
  }

  const targetColumn = column && typeof column === "object"
    ? column
    : getMeasurementPrimaryValidationColumn();
  if (!targetColumn) {
    return true;
  }

  const validation = normalizeMeasurementSheetColumnValidationSnapshotLocal(
    targetColumn.validation,
    new Set(state.measurementSheet.columns.filter((entry) => !entry.computed).map((entry) => entry.id)),
    targetColumn.id,
  );

  if (validation.type !== "list" || validation.allowCustom) {
    return true;
  }

  const options = getMeasurementColumnValidationOptions(targetColumn);
  return options.some((option) => String(option).trim().toLowerCase() === normalizedValue.toLowerCase());
}

function applyMeasurementValidationToColumns(validationPatch = {}) {
  const targetIndexes = getMeasurementValidationTargetColumnIndexes();
  if (targetIndexes.length === 0) {
    return;
  }

  const editableColumnIds = new Set(state.measurementSheet.columns.filter((column) => !column.computed).map((column) => column.id));

  targetIndexes.forEach((columnIndex) => {
    const column = state.measurementSheet.columns[columnIndex];
    if (!column || column.computed) {
      return;
    }

    const nextValidation = normalizeMeasurementSheetColumnValidationSnapshotLocal(
      {
        ...(column.validation ?? {}),
        ...validationPatch,
      },
      editableColumnIds,
      column.id,
    );

    column.validation = nextValidation;
  });

  renderMeasurementSheet();
  syncMeasurementToolbar();
  handleMeasurementSheetMutation();
}

function getMeasurementSheetOwnerFieldDraft() {
  const ownerFieldId = String(state.measurementSheet.ownerFieldId || "").trim();
  if (!ownerFieldId) {
    return null;
  }
  return documentTemplateFieldDrafts.find((field) => String(field.id || "") === ownerFieldId) || null;
}

function getMeasurementSheetPresetScope() {
  if (state.measurementSheet.ownerKind !== "template_field") {
    return null;
  }

  const field = getMeasurementSheetOwnerFieldDraft();
  if (!field) {
    return null;
  }

  const template = buildDocumentTemplateDraft();
  const templateId = String(template.id || state.activeDocumentTemplateId || documentTemplateIdInput?.value || "").trim();
  const companyId = String(documentTemplateCompanyIdInput?.value || template.sampleCompanyId || "").trim();
  const locationId = String(documentTemplateLocationIdInput?.value || template.sampleLocationId || "").trim();
  const fieldKey = String(field.id || field.key || "").trim();
  const scopeKey = [templateId, companyId, locationId, fieldKey].join("::");

  return {
    template,
    field,
    templateId,
    companyId,
    locationId,
    fieldKey,
    scopeKey,
  };
}

function buildMeasurementSheetPresetLabel(item = {}) {
  const parts = [
    String(item.title || "").trim(),
  ].filter(Boolean);
  const updatedAt = String(item.updatedAt || item.createdAt || "").trim();
  if (updatedAt) {
    const parsedDate = new Date(updatedAt);
    if (!Number.isNaN(parsedDate.getTime())) {
      parts.push(formatCompactDate(parsedDate.toISOString().slice(0, 10)));
    }
  }
  return parts.join(" · ") || "Spremljena Excel tablica";
}

function renderMeasurementSheetPresetLibrary() {
  const scope = getMeasurementSheetPresetScope();
  const canRender = Boolean(
    measurementSheetPresetWrap
    && measurementSheetPresetSelect
    && measurementSheetPresetLoadButton
    && measurementSheetPresetSaveButton
    && measurementSheetPresetStatus
    && scope,
  );

  if (!canRender) {
    if (measurementSheetPresetWrap) {
      measurementSheetPresetWrap.hidden = true;
    }
    return;
  }

  const presetLibrary = state.measurementSheet.presetLibrary ?? {
    scopeKey: "",
    status: "idle",
    items: [],
    error: "",
    message: "",
  };
  const items = Array.isArray(presetLibrary.items) ? presetLibrary.items : [];
  const scopeReady = Boolean(scope.templateId && scope.companyId && scope.locationId && scope.fieldKey);

  measurementSheetPresetWrap.hidden = false;
  replaceSelectOptions(
    measurementSheetPresetSelect,
    [
      {
        value: "",
        label: scopeReady
          ? (items.length > 0 ? "Odaberi spremljenu Excel tablicu" : "Nema spremljenih Excel tablica")
          : "Prvo odaberi template, tvrtku i lokaciju",
      },
      ...items.map((item) => ({
        value: String(item.id || ""),
        label: buildMeasurementSheetPresetLabel(item),
      })),
    ],
    measurementSheetPresetSelect.value || items[0]?.id || "",
  );

  measurementSheetPresetSelect.disabled = !scopeReady || ["loading", "saving"].includes(presetLibrary.status);
  measurementSheetPresetLoadButton.disabled = !scopeReady || !measurementSheetPresetSelect.value;
  measurementSheetPresetSaveButton.disabled = !scopeReady || presetLibrary.status === "saving";

  if (!scopeReady) {
    measurementSheetPresetStatus.textContent = "Odaberi primjernu tvrtku i lokaciju te spremi template da bi Excel preset bio dostupan.";
    return;
  }

  if (presetLibrary.status === "loading") {
    measurementSheetPresetStatus.textContent = "Učitavam spremljene Excel tablice...";
    return;
  }

  if (presetLibrary.status === "saving") {
    measurementSheetPresetStatus.textContent = "Spremam Excel tablicu kao JSON preset...";
    return;
  }

  if (presetLibrary.error) {
    measurementSheetPresetStatus.textContent = presetLibrary.error;
    return;
  }

  if (presetLibrary.message) {
    measurementSheetPresetStatus.textContent = presetLibrary.message;
    return;
  }

  measurementSheetPresetStatus.textContent = items.length > 0
    ? "Možeš učitati spremljenu Excel tablicu ili prepisati novom verzijom."
    : "Još nema spremljene Excel tablice za ovu tvrtku i lokaciju.";
}

async function loadMeasurementSheetPresetLibrary({ force = false } = {}) {
  const scope = getMeasurementSheetPresetScope();

  if (!scope || !scope.templateId || !scope.companyId || !scope.locationId || !scope.fieldKey) {
    state.measurementSheet.presetLibrary = {
      scopeKey: scope?.scopeKey || "",
      status: "idle",
      items: [],
      error: "",
      message: "",
    };
    renderMeasurementSheetPresetLibrary();
    return;
  }

  const currentLibrary = state.measurementSheet.presetLibrary ?? {};
  if (!force && currentLibrary.scopeKey === scope.scopeKey && ["loading", "loaded"].includes(currentLibrary.status)) {
    renderMeasurementSheetPresetLibrary();
    return;
  }

  state.measurementSheet.presetLibrary = {
    scopeKey: scope.scopeKey,
    status: "loading",
    items: [],
    error: "",
    message: "",
  };
  renderMeasurementSheetPresetLibrary();

  try {
    const payload = await apiRequest(
      `/measurement-sheet-presets?templateId=${encodeURIComponent(scope.templateId)}&companyId=${encodeURIComponent(scope.companyId)}&locationId=${encodeURIComponent(scope.locationId)}&fieldKey=${encodeURIComponent(scope.fieldKey)}&limit=12`,
    );
    state.measurementSheet.presetLibrary = {
      scopeKey: scope.scopeKey,
      status: "loaded",
      items: Array.isArray(payload?.items) ? payload.items : [],
      error: "",
      message: "",
    };
  } catch (error) {
    state.measurementSheet.presetLibrary = {
      scopeKey: scope.scopeKey,
      status: "error",
      items: [],
      error: error.message || "Ne mogu učitati spremljene Excel tablice.",
      message: "",
    };
  }

  renderMeasurementSheetPresetLibrary();
}

function getSelectedMeasurementSheetPresetItem() {
  const selectedId = String(measurementSheetPresetSelect?.value || "").trim();
  if (!selectedId) {
    return null;
  }
  return (state.measurementSheet.presetLibrary?.items ?? []).find((item) => String(item.id || "") === selectedId) || null;
}

function applyMeasurementSheetPresetItem(item = null) {
  const snapshot = item?.sheet ? normalizeWorkOrderMeasurementSheet(item.sheet) : null;
  if (!snapshot) {
    return false;
  }

  applyMeasurementSheetSnapshot(snapshot);
  syncMeasurementSheetHeaderFromWorkOrder();
  renderMeasurementSheet();
  syncMeasurementToolbar();
  handleMeasurementSheetMutation();
  state.measurementSheet.presetLibrary = {
    ...(state.measurementSheet.presetLibrary ?? {}),
    message: "Spremljena Excel tablica je učitana.",
    error: "",
  };
  renderMeasurementSheetPresetLibrary();
  return true;
}

async function saveMeasurementSheetPreset() {
  const scope = getMeasurementSheetPresetScope();
  if (!scope || !scope.templateId || !scope.companyId || !scope.locationId || !scope.fieldKey) {
    renderMeasurementSheetPresetLibrary();
    return;
  }

  const company = getCompany(scope.companyId);
  const location = getLocation(scope.locationId);
  const snapshot = buildMeasurementSheetSnapshot({ includeBlankStructure: true })
    ?? ensureDocumentTemplateMeasurementFieldSheet(scope.field);

  state.measurementSheet.presetLibrary = {
    ...(state.measurementSheet.presetLibrary ?? {}),
    scopeKey: scope.scopeKey,
    status: "saving",
    error: "",
    message: "",
  };
  renderMeasurementSheetPresetLibrary();

  try {
    const payload = await apiRequest("/measurement-sheet-presets", {
      method: "POST",
      body: {
        templateId: scope.templateId,
        companyId: scope.companyId,
        locationId: scope.locationId,
        fieldKey: scope.fieldKey,
        title: [
          String(scope.field?.label || "").trim() || "Excel tablica",
          company?.name || "",
          location?.name || "",
        ].filter(Boolean).join(" · "),
        sheet: snapshot,
      },
    });

    const item = payload?.item ?? null;
    state.measurementSheet.presetLibrary = {
      scopeKey: scope.scopeKey,
      status: "loaded",
      items: item ? [item] : (state.measurementSheet.presetLibrary?.items ?? []),
      error: "",
      message: "Excel tablica je spremljena kao JSON preset za ovu tvrtku i lokaciju.",
    };
  } catch (error) {
    state.measurementSheet.presetLibrary = {
      ...(state.measurementSheet.presetLibrary ?? {}),
      scopeKey: scope.scopeKey,
      status: "error",
      error: error.message || "Ne mogu spremiti Excel preset.",
      message: "",
    };
  }

  renderMeasurementSheetPresetLibrary();
}

function getMeasurementActiveCellFormat() {
  const position = getMeasurementActiveCellPosition();

  if (!position) {
    return normalizeMeasurementCellFormat();
  }

  return getMeasurementCellFormat(position.rowIndex, position.columnIndex);
}

function getMeasurementActiveCellRawValue() {
  const position = getMeasurementActiveCellPosition();

  if (!position?.row || !position?.column || position.column.computed) {
    return "";
  }

  return position.row.cells?.[position.column.id] ?? "";
}

function setMeasurementCellRawValue(rowId, columnId, value) {
  const rowIndex = getMeasurementRowIndex(rowId);
  const columnIndex = getMeasurementColumnIndex(columnId);
  const row = state.measurementSheet.rows[rowIndex];
  const column = state.measurementSheet.columns[columnIndex];

  if (!row?.cells || !column || column.computed) {
    return;
  }

  row.cells[column.id] = value;
  handleMeasurementSheetMutation();
}

function applyMeasurementFormatToRange(formatOverrides = {}) {
  const range = getMeasurementSelectedRange();

  if (!range) {
    return;
  }

  for (let rowIndex = range.startRowIndex; rowIndex <= range.endRowIndex; rowIndex += 1) {
    const row = state.measurementSheet.rows[rowIndex];

    if (!row) {
      continue;
    }

    row.formats = row.formats ?? {};

    for (let columnIndex = range.startColumnIndex; columnIndex <= range.endColumnIndex; columnIndex += 1) {
      const column = state.measurementSheet.columns[columnIndex];

      if (!column || column.computed) {
        continue;
      }

      const nextFormat = {
        ...row.formats[column.id],
      };

      if ("type" in formatOverrides) {
        nextFormat.type = formatOverrides.type;
      }

      if ("decimals" in formatOverrides) {
        nextFormat.decimals = formatOverrides.decimals;
      }

      if ("align" in formatOverrides) {
        nextFormat.align = formatOverrides.align;
      }

      if ("fontFamily" in formatOverrides) {
        nextFormat.fontFamily = formatOverrides.fontFamily;
      }

      if ("fontSize" in formatOverrides) {
        nextFormat.fontSize = formatOverrides.fontSize;
      }

      if ("bold" in formatOverrides) {
        nextFormat.bold = formatOverrides.bold;
      }

      if ("italic" in formatOverrides) {
        nextFormat.italic = formatOverrides.italic;
      }

      if ("underline" in formatOverrides) {
        nextFormat.underline = formatOverrides.underline;
      }

      if ("fillColor" in formatOverrides) {
        nextFormat.fillColor = formatOverrides.fillColor;
      }

      if ("borderPreset" in formatOverrides) {
        nextFormat.border = buildMeasurementBorderFromPreset(
          formatOverrides.borderPreset,
          range,
          rowIndex,
          columnIndex,
        );
      }

      row.formats[column.id] = normalizeMeasurementCellFormat(nextFormat);
    }
  }
}

function applyMeasurementToolbarFormat(overrides = {}) {
  if (!state.measurementSheet.activeCell) {
    return;
  }

  applyMeasurementFormatToRange(overrides);
  refreshMeasurementSheetComputedValues();
  renderMeasurementSelection();
  renderMeasurementActiveCell();
  syncMeasurementToolbar();
  handleMeasurementSheetMutation();
}

function toggleMeasurementToolbarButtonState(button, isActive) {
  if (!(button instanceof HTMLElement)) {
    return;
  }

  button.classList.toggle("is-active", Boolean(isActive));
  button.setAttribute("aria-pressed", isActive ? "true" : "false");
}

function toggleMeasurementTextStyle(styleKey) {
  const activeFormat = getMeasurementActiveCellFormat();

  applyMeasurementToolbarFormat({
    [styleKey]: !Boolean(activeFormat?.[styleKey]),
  });
}

function applyMeasurementStylePreset(presetKey) {
  const preset = MEASUREMENT_STYLE_PRESETS[presetKey];

  if (!preset) {
    return;
  }

  applyMeasurementToolbarFormat(preset);
}

function applyMeasurementStylePresetToSelectedRows(presetKey) {
  const preset = MEASUREMENT_STYLE_PRESETS[presetKey];
  const range = getMeasurementSelectedRange();

  if (!preset || !range) {
    return;
  }

  const firstColumnIndex = getFirstEditableMeasurementColumnIndex();
  const lastColumnIndex = getLastEditableMeasurementColumnIndex();

  if (firstColumnIndex < 0 || lastColumnIndex < firstColumnIndex) {
    return;
  }

  const previousRange = state.measurementSheet.selectedRange;
  const previousAnchor = state.measurementSheet.selectionAnchor;
  state.measurementSheet.selectedRange = createMeasurementSelectionRange(
    range.startRowIndex,
    firstColumnIndex,
    range.endRowIndex,
    lastColumnIndex,
  );
  state.measurementSheet.selectionAnchor = {
    rowIndex: range.startRowIndex,
    columnIndex: firstColumnIndex,
  };
  applyMeasurementToolbarFormat(preset);
  state.measurementSheet.selectedRange = previousRange;
  state.measurementSheet.selectionAnchor = previousAnchor;
  renderMeasurementSelection();
  renderMeasurementActiveCell();
  syncMeasurementToolbar();
}

function setMeasurementAlignment(align) {
  applyMeasurementToolbarFormat({ align });
}

function getEditableMeasurementColumnIndexes() {
  return state.measurementSheet.columns.reduce((indexes, column, index) => {
    if (!column.computed) {
      indexes.push(index);
    }

    return indexes;
  }, []);
}

function getFirstEditableMeasurementColumnIndex() {
  return getEditableMeasurementColumnIndexes()[0] ?? -1;
}

function getLastEditableMeasurementColumnIndex() {
  const editableIndexes = getEditableMeasurementColumnIndexes();
  return editableIndexes[editableIndexes.length - 1] ?? -1;
}

function focusMeasurementCell(rowId, columnId, options = {}) {
  const {
    selectAll = false,
  } = options;

  const input = getMeasurementInputElement(rowId, columnId);

  if (!(input instanceof HTMLInputElement)) {
    return;
  }

  input.focus({ preventScroll: true });

  if (selectAll) {
    input.select();
  }
}

function syncMeasurementToolbar() {
  if (measurementNameBoxInput) {
    measurementNameBoxInput.value = getMeasurementSelectionLabel();
  }

  if (measurementFormulaInput) {
    const nextValue = getMeasurementActiveCellRawValue();

    if (!isMeasurementFormulaBarActive() || state.measurementSheet.editorSource !== "formula-bar") {
      measurementFormulaInput.value = nextValue;
    }

    measurementFormulaInput.disabled = !state.measurementSheet.activeCell;
  }

  const activeFormat = getMeasurementActiveCellFormat();

  if (measurementFormatTypeInput) {
    measurementFormatTypeInput.value = activeFormat.type;
    measurementFormatTypeInput.disabled = !state.measurementSheet.activeCell;
  }

  const activeTypeMeta = MEASUREMENT_TYPE_BUTTON_META[activeFormat.type] || MEASUREMENT_TYPE_BUTTON_META.general;
  setMeasurementToolbarButtonPresentation(
    measurementFormatTypeButton,
    activeTypeMeta.icon,
    `Tip ćelije: ${activeTypeMeta.label}`,
  );
  if (measurementFormatTypeButton instanceof HTMLButtonElement) {
    measurementFormatTypeButton.disabled = !state.measurementSheet.activeCell;
  }

  if (measurementFormatDecimalsInput) {
    measurementFormatDecimalsInput.value = String(activeFormat.decimals);
    measurementFormatDecimalsInput.disabled = !state.measurementSheet.activeCell || ["general", "text", "integer"].includes(activeFormat.type);
  }

  if (measurementFormatDecimalsIndicatorButton instanceof HTMLButtonElement) {
    const decimalsLabel = formatMeasurementDecimalsBadge(activeFormat.decimals);
    measurementFormatDecimalsIndicatorButton.textContent = decimalsLabel;
    measurementFormatDecimalsIndicatorButton.title = `Broj decimalnih mjesta: ${activeFormat.decimals}`;
    measurementFormatDecimalsIndicatorButton.setAttribute("aria-label", `Broj decimalnih mjesta: ${activeFormat.decimals}`);
    measurementFormatDecimalsIndicatorButton.disabled = !state.measurementSheet.activeCell;
  }
  [
    measurementFormatDecimalsDecreaseButton,
    measurementFormatDecimalsIncreaseButton,
  ].forEach((button) => {
    if (button instanceof HTMLButtonElement) {
      button.disabled = !state.measurementSheet.activeCell;
    }
  });

  if (measurementFormatBorderInput) {
    measurementFormatBorderInput.value = getMeasurementBorderPreset(activeFormat.border);
    measurementFormatBorderInput.disabled = !state.measurementSheet.activeCell;
  }

  const activeBorderPreset = getMeasurementBorderPreset(activeFormat.border);
  const activeBorderMeta = MEASUREMENT_BORDER_BUTTON_META[activeBorderPreset] || MEASUREMENT_BORDER_BUTTON_META.none;
  setMeasurementToolbarButtonPresentation(
    measurementFormatBorderButton,
    activeBorderMeta.icon,
    `Obrub ćelije: ${activeBorderMeta.label}`,
  );
  if (measurementFormatBorderButton instanceof HTMLButtonElement) {
    measurementFormatBorderButton.disabled = !state.measurementSheet.activeCell;
  }

  const validationColumn = getMeasurementPrimaryValidationColumn();
  const activeValidation = validationColumn
    ? normalizeMeasurementSheetColumnValidationSnapshotLocal(
      validationColumn.validation,
      new Set(state.measurementSheet.columns.filter((entry) => !entry.computed).map((entry) => entry.id)),
      validationColumn.id,
    )
    : normalizeMeasurementSheetColumnValidationSnapshotLocal();
  const validationColumnOptions = state.measurementSheet.columns
    .filter((column) => !column.computed)
    .map((column) => ({
      value: column.id,
      label: column.label || column.id,
    }));

  if (measurementValidationButton instanceof HTMLButtonElement) {
    measurementValidationButton.disabled = !validationColumn;
    measurementValidationButton.classList.toggle("is-active", Boolean(validationColumn) && activeValidation.type === "list");
    measurementValidationButton.textContent = activeValidation.type === "list" ? "List" : "DV";
    measurementValidationButton.title = activeValidation.type === "list"
      ? "Data Validation list aktivan"
      : "Data Validation list";
  }

  if (measurementValidationPopover instanceof HTMLElement) {
    measurementValidationPopover.hidden = !(state.measurementSheet.validationPopoverOpen && validationColumn);
  }

  if (measurementValidationTypeInput) {
    measurementValidationTypeInput.value = activeValidation.type;
    measurementValidationTypeInput.disabled = !validationColumn;
  }

  if (measurementValidationSourceModeInput) {
    measurementValidationSourceModeInput.value = activeValidation.sourceMode;
    measurementValidationSourceModeInput.disabled = !validationColumn || activeValidation.type !== "list";
  }

  if (measurementValidationSourceColumnInput) {
    replaceSelectOptions(
      measurementValidationSourceColumnInput,
      validationColumnOptions,
      activeValidation.sourceColumnId || validationColumn?.id || "",
    );
    measurementValidationSourceColumnInput.disabled = !validationColumn
      || activeValidation.type !== "list"
      || activeValidation.sourceMode !== "column";
  }

  if (measurementValidationOptionsInput) {
    measurementValidationOptionsInput.value = (activeValidation.options ?? []).join(", ");
    measurementValidationOptionsInput.disabled = !validationColumn
      || activeValidation.type !== "list"
      || activeValidation.sourceMode !== "custom";
  }

  if (measurementValidationAllowCustomInput) {
    measurementValidationAllowCustomInput.checked = Boolean(activeValidation.allowCustom);
    measurementValidationAllowCustomInput.disabled = !validationColumn || activeValidation.type !== "list";
  }

  if (measurementFormatFontFamilyInput) {
    measurementFormatFontFamilyInput.value = activeFormat.fontFamily;
    measurementFormatFontFamilyInput.disabled = !state.measurementSheet.activeCell;
  }

  if (measurementFormatFontSizeInput) {
    measurementFormatFontSizeInput.value = String(activeFormat.fontSize);
    measurementFormatFontSizeInput.disabled = !state.measurementSheet.activeCell;
  }

  if (measurementFormatFillColorInput) {
    measurementFormatFillColorInput.value = activeFormat.fillColor || "#ffffff";
    measurementFormatFillColorInput.disabled = !state.measurementSheet.activeCell;
  }

  toggleMeasurementToolbarButtonState(measurementFormatBoldButton, activeFormat.bold);
  toggleMeasurementToolbarButtonState(measurementFormatItalicButton, activeFormat.italic);
  toggleMeasurementToolbarButtonState(measurementFormatUnderlineButton, activeFormat.underline);
  [
    measurementFormatBoldButton,
    measurementFormatItalicButton,
    measurementFormatUnderlineButton,
  ].forEach((button) => {
    if (button instanceof HTMLButtonElement) {
      button.disabled = !state.measurementSheet.activeCell;
    }
  });

  toggleMeasurementToolbarButtonState(measurementAlignLeftButton, activeFormat.align === "left");
  toggleMeasurementToolbarButtonState(measurementAlignCenterButton, activeFormat.align === "center");
  toggleMeasurementToolbarButtonState(measurementAlignRightButton, activeFormat.align === "right");
  [
    measurementAlignLeftButton,
    measurementAlignCenterButton,
    measurementAlignRightButton,
    measurementStyleTitleButton,
    measurementMergeButton,
    measurementUnmergeButton,
  ].forEach((button) => {
    if (button instanceof HTMLButtonElement) {
      button.disabled = !state.measurementSheet.activeCell;
    }
  });

  toggleMeasurementToolbarButtonState(
    measurementStyleTitleButton,
    Boolean(getMeasurementSelectedRange())
      && state.measurementSheet.rows
        .slice(getMeasurementSelectedRange().startRowIndex, getMeasurementSelectedRange().endRowIndex + 1)
        .every((row) => isMeasurementHeaderRow(row?.id)),
  );

  measurementColorSwatchButtons.forEach((button) => {
    button.classList.toggle("is-active", (button.dataset.fillColor || "") === (activeFormat.fillColor || ""));
    button.disabled = !state.measurementSheet.activeCell;
  });
  if (measurementMergeButton instanceof HTMLButtonElement) {
    measurementMergeButton.disabled = !canMergeMeasurementSelection();
  }

  if (measurementUnmergeButton instanceof HTMLButtonElement) {
    measurementUnmergeButton.disabled = !getMeasurementMergedSelectionDescriptor();
  }
}

function ensureMeasurementRowsThrough(targetRowIndex) {
  while (state.measurementSheet.rows.length <= targetRowIndex) {
    state.measurementSheet.rows.push(createMeasurementRow());
  }
}

function appendMeasurementRows(count = MEASUREMENT_ROW_BATCH_SIZE) {
  const total = Math.max(1, count);

  for (let index = 0; index < total; index += 1) {
    state.measurementSheet.rows.push(createMeasurementRow());
  }
}

function ensureMeasurementMinimumRows(minimumCount = DEFAULT_MEASUREMENT_ROW_COUNT) {
  while (state.measurementSheet.rows.length < minimumCount) {
    appendMeasurementRows();
  }
}

function isMeasurementRowEmpty(row) {
  return state.measurementSheet.columns
    .filter((column) => !column.computed)
    .every((column) => !String(row.cells?.[column.id] ?? "").trim());
}

function appendMeasurementEditableColumn(partial = {}, options = {}) {
  const {
    toEnd = false,
  } = options;

  const column = createMeasurementColumn({
    label: partial.label || `Kolona ${state.measurementSheet.columns.filter((item) => !item.computed).length + 1}`,
    ...partial,
  });

  if (toEnd) {
    state.measurementSheet.columns.push(column);
  } else {
    const insertionIndex = state.measurementSheet.columns.findIndex((item) => item.computed || item.id === "note");

    if (insertionIndex >= 0) {
      state.measurementSheet.columns.splice(insertionIndex, 0, column);
    } else {
      state.measurementSheet.columns.push(column);
    }
  }

  state.measurementSheet.rows.forEach((row) => {
    row.cells[column.id] = row.cells[column.id] ?? "";
    row.formats = row.formats ?? {};
    row.formats[column.id] = normalizeMeasurementCellFormat(row.formats[column.id]);
  });

  return getMeasurementColumnIndex(column.id);
}

function insertMeasurementEditableColumnAt(index, partial = {}) {
  const column = createMeasurementColumn({
    label: partial.label || `Kolona ${state.measurementSheet.columns.filter((item) => !item.computed).length + 1}`,
    ...partial,
  });
  const insertionIndex = Math.max(0, Math.min(index, state.measurementSheet.columns.length));
  state.measurementSheet.columns.splice(insertionIndex, 0, column);

  state.measurementSheet.rows.forEach((row) => {
    row.cells[column.id] = row.cells[column.id] ?? "";
    row.formats = row.formats ?? {};
    row.formats[column.id] = normalizeMeasurementCellFormat(row.formats[column.id]);
  });

  return getMeasurementColumnIndex(column.id);
}

function ensureMeasurementEditableColumnsFrom(startColumnIndex, requiredWidth) {
  let editableIndexes = getEditableMeasurementColumnIndexes();
  const startPosition = editableIndexes.indexOf(startColumnIndex);

  if (startPosition < 0) {
    return [];
  }

  while (editableIndexes.length < startPosition + requiredWidth) {
    appendMeasurementEditableColumn({}, { toEnd: true });
    editableIndexes = getEditableMeasurementColumnIndexes();
  }

  return editableIndexes.slice(startPosition, startPosition + requiredWidth);
}

function getMeasurementCellDisplayValue(rowIndex, columnIndex) {
  const row = state.measurementSheet.rows[rowIndex];
  const column = state.measurementSheet.columns[columnIndex];

  if (!row || !column) {
    return "";
  }

  if (column.computed === "average") {
    return formatMeasurementAverage(row);
  }

  const rawValue = row.cells?.[column.id] ?? "";
  const format = getMeasurementCellFormat(rowIndex, columnIndex);

  if (!isMeasurementFormula(rawValue)) {
    return formatMeasurementLiteralDisplayValue(rawValue, format);
  }

  return getMeasurementCellDisplayText(rowIndex, columnIndex);
}

function isMeasurementEditingCell(rowId, columnId) {
  return state.measurementSheet.editorSource === "cell"
    && state.measurementSheet.editingCell?.rowId === rowId
    && state.measurementSheet.editingCell?.columnId === columnId;
}

function getMeasurementCellComputedValue(rowIndex, columnIndex, stack = new Set()) {
  const row = state.measurementSheet.rows[rowIndex];
  const column = state.measurementSheet.columns[columnIndex];

  if (!row || !column) {
    return "";
  }

  if (column.computed === "average") {
    return getMeasurementAverageValue(row) ?? "";
  }

  const rawValue = row.cells?.[column.id] ?? "";

  if (!isMeasurementFormula(rawValue)) {
    return normalizeMeasurementLiteralValue(rawValue);
  }

  const cellKey = `${rowIndex}:${columnIndex}`;

  if (stack.has(cellKey)) {
    throw new Error("Kruzna referenca u formuli.");
  }

  stack.add(cellKey);

  try {
    return evaluateMeasurementFormula(rawValue, {
      resolveCellReference(reference) {
        const { rowIndex: referenceRowIndex, columnIndex: referenceColumnIndex } =
          parseMeasurementCellReference(reference);

        if (referenceRowIndex < 0
          || referenceColumnIndex < 0
          || referenceRowIndex >= state.measurementSheet.rows.length
          || referenceColumnIndex >= state.measurementSheet.columns.length) {
          throw new Error(`Referenca ${reference} nije valjana.`);
        }

        return getMeasurementCellComputedValue(referenceRowIndex, referenceColumnIndex, stack);
      },
      resolveRange(startReference, endReference) {
        const start = parseMeasurementCellReference(startReference);
        const end = parseMeasurementCellReference(endReference);
        const startRowIndex = Math.max(0, Math.min(start.rowIndex, end.rowIndex));
        const endRowIndex = Math.max(start.rowIndex, end.rowIndex);
        const startColumnIndex = Math.max(0, Math.min(start.columnIndex, end.columnIndex));
        const endColumnIndex = Math.max(start.columnIndex, end.columnIndex);
        const matrix = [];

        for (let referenceRowIndex = startRowIndex; referenceRowIndex <= endRowIndex; referenceRowIndex += 1) {
          const rowValues = [];
          for (let referenceColumnIndex = startColumnIndex; referenceColumnIndex <= endColumnIndex; referenceColumnIndex += 1) {
            if (
              referenceRowIndex < 0
              || referenceColumnIndex < 0
              || referenceRowIndex >= state.measurementSheet.rows.length
              || referenceColumnIndex >= state.measurementSheet.columns.length
            ) {
              rowValues.push("");
              continue;
            }

            rowValues.push(getMeasurementCellComputedValue(referenceRowIndex, referenceColumnIndex, stack));
          }
          matrix.push(rowValues);
        }

        return matrix;
      },
    });
  } finally {
    stack.delete(cellKey);
  }
}

function getMeasurementCellDisplayText(rowIndex, columnIndex) {
  try {
    return formatMeasurementComputedDisplayValue(
      getMeasurementCellComputedValue(rowIndex, columnIndex),
      getMeasurementCellFormat(rowIndex, columnIndex),
    );
  } catch {
    return "#ERROR";
  }
}

function updateMeasurementFormulaReferences(formulaText) {
  if (!isMeasurementFormula(formulaText)) {
    state.measurementSheet.formulaReferences = [];
    return;
  }

  state.measurementSheet.formulaReferences = listMeasurementFormulaReferences(formulaText)
    .map((reference) => {
      try {
        return parseMeasurementCellReference(reference);
      } catch {
        return null;
      }
    })
    .filter(Boolean);
}

function renderMeasurementFormulaReferences() {
  measurementSheetBody
    ?.querySelectorAll(".is-formula-reference-cell")
    .forEach((cell) => cell.classList.remove("is-formula-reference-cell"));

  if (!state.measurementSheet.formulaReferences.length) {
    return;
  }

  state.measurementSheet.formulaReferences.forEach((reference) => {
    const row = state.measurementSheet.rows[reference.rowIndex];
    const column = state.measurementSheet.columns[reference.columnIndex];

    if (!row || !column) {
      return;
    }

    getMeasurementCellElement(row.id, column.id)?.classList.add("is-formula-reference-cell");
  });
}

function syncMeasurementFormulaEditState() {
  if (!state.measurementSheet.editingCell) {
    state.measurementSheet.formulaReferences = [];
    renderMeasurementFormulaReferences();
    syncMeasurementToolbar();
    return;
  }

  const input = getMeasurementFormulaInputElement();

  if (!(input instanceof HTMLInputElement)) {
    state.measurementSheet.formulaReferences = [];
    renderMeasurementFormulaReferences();
    syncMeasurementToolbar();
    return;
  }

  updateMeasurementFormulaReferences(input.value);
  renderMeasurementFormulaReferences();
  syncMeasurementToolbar();
}

function insertMeasurementFormulaReference(reference) {
  const input = getMeasurementFormulaInputElement();

  if (!(input instanceof HTMLInputElement) || !isMeasurementFormula(input.value)) {
    return;
  }

  const start = input.selectionStart ?? input.value.length;
  const end = input.selectionEnd ?? input.value.length;
  const nextValue = `${input.value.slice(0, start)}${reference}${input.value.slice(end)}`;

  input.value = nextValue;
  input.setSelectionRange(start + reference.length, start + reference.length);

  setMeasurementCellRawValue(
    state.measurementSheet.editingCell.rowId,
    state.measurementSheet.editingCell.columnId,
    nextValue,
  );

  syncMeasurementFormulaEditState();
  updateMeasurementEditingCellPreview(
    state.measurementSheet.editingCell.rowId,
    state.measurementSheet.editingCell.columnId,
  );
  scheduleMeasurementSheetComputedRefresh();
  input.focus({ preventScroll: true });
}

function maybeInsertMeasurementFormulaReference(rowId, columnId) {
  if (!isMeasurementFormulaEditingActive()) {
    return false;
  }

  if (state.measurementSheet.editingCell?.rowId === rowId
    && state.measurementSheet.editingCell?.columnId === columnId) {
    return false;
  }

  const rowIndex = getMeasurementRowIndex(rowId);
  const columnIndex = getMeasurementColumnIndex(columnId);

  if (rowIndex < 0 || columnIndex < 0) {
    return false;
  }

  insertMeasurementFormulaReference(getMeasurementCellReference(rowIndex, columnIndex));
  return true;
}

function shiftMeasurementFillValue(value, rowOffset, columnOffset) {
  if (!isMeasurementFormula(value)) {
    return value;
  }

  return shiftMeasurementFormulaReferences(value, rowOffset, columnOffset);
}

function enterMeasurementEditMode(rowId, columnId, options = {}) {
  const {
    selectAll = false,
    selectFormulaBody = false,
  } = options;

  state.measurementSheet.editingCell = { rowId, columnId };
  state.measurementSheet.editorSource = "cell";
  focusMeasurementCell(rowId, columnId, { selectAll });

  const input = getMeasurementFormulaInputElement();

  if (!isMeasurementInputElement(input)) {
    return;
  }

  const rowIndex = getMeasurementRowIndex(rowId);
  const columnIndex = getMeasurementColumnIndex(columnId);

  if (selectFormulaBody && isMeasurementFormula(input.value)) {
    const caretIndex = input.value.length;
    input.setSelectionRange(caretIndex, caretIndex);
  } else if (selectAll) {
    input.select();
  }

  if (rowIndex >= 0 && columnIndex >= 0) {
    updateMeasurementFormulaReferences(input.value);
    renderMeasurementFormulaReferences();
  }

  syncMeasurementToolbar();
}

function startMeasurementTypingInActiveCell(initialValue) {
  const activeCell = state.measurementSheet.activeCell;

  if (!activeCell) {
    return false;
  }

  setMeasurementSelection(activeCell.rowId, activeCell.columnId);
  enterMeasurementEditMode(activeCell.rowId, activeCell.columnId);

  const input = getMeasurementFormulaInputElement();

  if (!isMeasurementInputElement(input)) {
    return false;
  }

  input.value = initialValue;
  input.setSelectionRange(initialValue.length, initialValue.length);
  setMeasurementCellRawValue(activeCell.rowId, activeCell.columnId, initialValue);
  syncMeasurementFormulaEditState();
  updateMeasurementEditingCellPreview(activeCell.rowId, activeCell.columnId);
  scheduleMeasurementSheetComputedRefresh();
  return true;
}

function isMeasurementDirectTypingKey(event) {
  return event.key.length === 1
    && !event.ctrlKey
    && !event.metaKey
    && !event.altKey;
}

function exitMeasurementEditMode() {
  if (state.measurementSheet.editingCell) {
    const { rowId, columnId } = state.measurementSheet.editingCell;
    const rowIndex = getMeasurementRowIndex(rowId);
    const columnIndex = getMeasurementColumnIndex(columnId);
    const column = state.measurementSheet.columns[columnIndex];
    const row = state.measurementSheet.rows[rowIndex];
    const currentValue = row?.cells?.[column?.id] ?? "";

    if (column && row && !isMeasurementValidationValueAllowed(column, currentValue)) {
      setMeasurementCellRawValue(rowId, columnId, "");
      updateMeasurementEditingCellPreview(rowId, columnId);
    }
  }

  state.measurementSheet.editingCell = null;
  state.measurementSheet.editorSource = null;
  state.measurementSheet.formulaReferences = [];
  renderMeasurementFormulaReferences();
  scheduleMeasurementSheetComputedRefresh({ immediate: true });
  syncMeasurementToolbar();
}

function commitMeasurementEditMode() {
  const input = getMeasurementFormulaInputElement();

  if (input instanceof HTMLInputElement) {
    input.blur();
  }

  if (state.measurementSheet.editingCell) {
    exitMeasurementEditMode();
  }
}

function getMeasurementCellInputDisplayValue(rowIndex, columnIndex) {
  const row = state.measurementSheet.rows[rowIndex];
  const column = state.measurementSheet.columns[columnIndex];

  if (!row || !column) {
    return "";
  }

  const rawValue = row.cells?.[column.id] ?? "";
  const format = getMeasurementCellFormat(rowIndex, columnIndex);

  if (isMeasurementEditingCell(row.id, column.id)) {
    return rawValue;
  }

  if (isMeasurementFormula(rawValue)) {
    return getMeasurementCellDisplayText(rowIndex, columnIndex);
  }

  return formatMeasurementLiteralDisplayValue(rawValue, format);
}

function clearScheduledMeasurementSheetRefresh() {
  if (!measurementComputedRefreshTimerId) {
    return;
  }

  window.clearTimeout(measurementComputedRefreshTimerId);
  measurementComputedRefreshTimerId = 0;
}

function updateMeasurementEditingCellPreview(rowId, columnId) {
  const rowIndex = getMeasurementRowIndex(rowId);
  const columnIndex = getMeasurementColumnIndex(columnId);
  const row = state.measurementSheet.rows[rowIndex];
  const column = state.measurementSheet.columns[columnIndex];
  const cell = getMeasurementCellElement(rowId, columnId);

  if (!row || !column || !(cell instanceof HTMLTableCellElement)) {
    return;
  }

  const rawValue = row.cells?.[column.id] ?? "";
  const hasFormula = isMeasurementFormula(rawValue);
  const input = cell.querySelector(".measurement-cell-input");

  cell.classList.toggle("has-formula-cell", hasFormula);
  if (!hasFormula) {
    cell.classList.remove("has-formula-error");
  }

  if (input instanceof HTMLInputElement) {
    input.title = hasFormula ? rawValue : "";
  }

  const rowElement = measurementSheetBody?.querySelector(`tr[data-row-id="${CSS.escape(rowId)}"]`);
  rowElement?.classList.toggle("is-measurement-empty-row", isMeasurementRowEmpty(row));

  state.measurementSheet.columns.forEach((sheetColumn) => {
    if (sheetColumn.computed !== "average") {
      return;
    }

    const averageCell = getMeasurementCellElement(rowId, sheetColumn.id);

    if (averageCell instanceof HTMLTableCellElement) {
      averageCell.textContent = formatMeasurementAverage(row);
    }
  });
}

function scheduleMeasurementSheetComputedRefresh({ immediate = false } = {}) {
  clearScheduledMeasurementSheetRefresh();

  if (immediate) {
    refreshMeasurementSheetComputedValues();
    return;
  }

  measurementComputedRefreshTimerId = window.setTimeout(() => {
    measurementComputedRefreshTimerId = 0;
    refreshMeasurementSheetComputedValues();
  }, MEASUREMENT_COMPUTE_DEBOUNCE_MS);
}

function refreshMeasurementSheetComputedValues() {
  clearScheduledMeasurementSheetRefresh();

  if (!measurementSheetBody) {
    return;
  }

  state.measurementSheet.rows.forEach((row, rowIndex) => {
    state.measurementSheet.columns.forEach((column, columnIndex) => {
      const cell = getMeasurementCellElement(row.id, column.id);

      if (!(cell instanceof HTMLTableCellElement)) {
        return;
      }

      if (column.computed === "average") {
        applyMeasurementCellBorderStyle(cell, {});
        cell.textContent = formatMeasurementAverage(row);
        return;
      }

      const input = cell.querySelector(".measurement-cell-input");
      const rawValue = row.cells?.[column.id] ?? "";
      const hasFormula = isMeasurementFormula(rawValue);
      let hasError = false;
      const format = getMeasurementCellFormat(rowIndex, columnIndex);

      if (hasFormula) {
        hasError = getMeasurementCellDisplayText(rowIndex, columnIndex) === "#ERROR";
      }

      cell.classList.toggle("has-formula-cell", hasFormula);
      cell.classList.toggle("has-formula-error", hasError);
      applyMeasurementCellBorderStyle(cell, format.border);
      applyMeasurementCellStyleToElements(cell, input, format);

      if (input instanceof HTMLInputElement && !isMeasurementEditingCell(row.id, column.id)) {
        input.value = getMeasurementCellInputDisplayValue(rowIndex, columnIndex);
        input.title = hasFormula ? rawValue : "";
      }
    });
  });

  renderMeasurementFormulaReferences();
  syncMeasurementToolbar();
}

function clearMeasurementFillPreview() {
  measurementSheetBody
    ?.querySelectorAll(".is-fill-target, .is-fill-preview-selected")
    .forEach((cell) => cell.classList.remove("is-fill-target", "is-fill-preview-selected"));

  measurementSheetBody
    ?.querySelectorAll("th.is-fill-preview-row")
    .forEach((cell) => cell.classList.remove("is-fill-preview-row"));

  measurementSheetHead
    ?.querySelectorAll("th.is-fill-preview-column")
    .forEach((cell) => cell.classList.remove("is-fill-preview-column"));

  measurementSheetBody
    ?.querySelectorAll(".measurement-cell-input.is-fill-previewing")
    .forEach((input) => {
      if (!(input instanceof HTMLInputElement)) {
        return;
      }

      if (typeof input.dataset.previewOriginalValue === "string") {
        input.value = input.dataset.previewOriginalValue;
      }

      delete input.dataset.previewOriginalValue;
      input.classList.remove("is-fill-previewing");
    });
}

function clearMeasurementSelectionClasses() {
  measurementSheetBody
    ?.querySelectorAll(".is-selected-cell, .is-fill-origin, .is-selected-row")
    .forEach((cell) => cell.classList.remove("is-selected-cell", "is-fill-origin", "is-selected-row"));

  measurementSheetHead
    ?.querySelectorAll(".is-selected-column")
    .forEach((cell) => cell.classList.remove("is-selected-column"));
}

function renderMeasurementActiveCell() {
  measurementSheetBody
    ?.querySelectorAll(".is-active-cell")
    .forEach((cell) => cell.classList.remove("is-active-cell"));

  const activeCell = state.measurementSheet.activeCell;

  if (!activeCell) {
    return;
  }

  getMeasurementCellElement(activeCell.rowId, activeCell.columnId)?.classList.add("is-active-cell");
}

function renderMeasurementSelection() {
  clearMeasurementSelectionClasses();

  const selectedRange = getMeasurementSelectedRange();

  if (!selectedRange) {
    return;
  }

  for (let rowIndex = selectedRange.startRowIndex; rowIndex <= selectedRange.endRowIndex; rowIndex += 1) {
    const row = state.measurementSheet.rows[rowIndex];

    if (!row) {
      continue;
    }

    measurementSheetBody
      ?.querySelector(`tr[data-row-id="${CSS.escape(row.id)}"] > th`)
      ?.classList.add("is-selected-row");

    for (let columnIndex = selectedRange.startColumnIndex; columnIndex <= selectedRange.endColumnIndex; columnIndex += 1) {
      const column = state.measurementSheet.columns[columnIndex];

      if (!column) {
        continue;
      }

      measurementSheetHead
        ?.querySelector(`th[data-column-id="${CSS.escape(column.id)}"]`)
        ?.classList.add("is-selected-column");
      getMeasurementCellElement(row.id, column.id)?.classList.add("is-selected-cell");
    }
  }

  const fillOriginRow = state.measurementSheet.rows[selectedRange.endRowIndex];
  const fillOriginColumn = state.measurementSheet.columns[selectedRange.endColumnIndex];
  getMeasurementCellElement(fillOriginRow?.id, fillOriginColumn?.id)?.classList.add("is-fill-origin");
}

function setMeasurementSelectionByIndex(rowIndex, columnIndex, options = {}) {
  const {
    extend = false,
    focus = false,
    selectAll = false,
  } = options;

  const row = state.measurementSheet.rows[rowIndex];
  const column = state.measurementSheet.columns[columnIndex];

  if (!row || !column || column.computed) {
    return;
  }

  state.measurementSheet.activeCell = { rowId: row.id, columnId: column.id };

  if (extend && state.measurementSheet.selectionAnchor) {
    state.measurementSheet.selectedRange = createMeasurementSelectionRange(
      state.measurementSheet.selectionAnchor.rowIndex,
      state.measurementSheet.selectionAnchor.columnIndex,
      rowIndex,
      columnIndex,
    );
  } else {
    state.measurementSheet.selectionAnchor = { rowIndex, columnIndex };
    state.measurementSheet.selectedRange = createMeasurementSelectionRange(rowIndex, columnIndex, rowIndex, columnIndex);
  }

  state.measurementSheet.fillMenu = null;
  state.measurementSheet.contextMenu = null;
  clearMeasurementFillPreview();
  renderMeasurementSelection();
  renderMeasurementActiveCell();
  renderMeasurementContextMenu();
  syncMeasurementToolbar();

  if (focus) {
    focusMeasurementCell(row.id, column.id, { selectAll });
  }
}

function getCurrentMeasurementFillPreview() {
  return state.measurementSheet.fillDrag ?? state.measurementSheet.fillMenu?.pendingFill ?? null;
}

function renderMeasurementFillPreview() {
  clearMeasurementFillPreview();

  const fillDrag = getCurrentMeasurementFillPreview();

  if (!fillDrag || fillDrag.endRowIndex <= fillDrag.selectionRange.endRowIndex) {
    return;
  }

  const selectionHeight = fillDrag.selectionRange.endRowIndex - fillDrag.selectionRange.startRowIndex + 1;
  const targetColumns = getEditableMeasurementColumnsInRange(fillDrag.selectionRange).map((column) => {
    const snapshotValues = fillDrag.snapshotRows.map((row) => row.cells?.[column.id] ?? "");
    const snapshotFormats = fillDrag.snapshotRows.map((row) => normalizeMeasurementCellFormat(row.formats?.[column.id]));
    const numericValues = snapshotValues.map(parseMeasurementNumber);
    return {
      column,
      snapshotValues,
      snapshotFormats,
      numericValues,
      canSeries: numericValues.every((value) => value !== null),
    };
  });

  for (let rowIndex = fillDrag.selectionRange.endRowIndex + 1; rowIndex <= fillDrag.endRowIndex; rowIndex += 1) {
    const row = state.measurementSheet.rows[rowIndex];

    if (!row) {
      continue;
    }

    measurementSheetBody
      ?.querySelector(`tr[data-row-id="${CSS.escape(row.id)}"] > th`)
      ?.classList.add("is-fill-preview-row");

    for (let columnIndex = fillDrag.selectionRange.startColumnIndex; columnIndex <= fillDrag.selectionRange.endColumnIndex; columnIndex += 1) {
      const column = state.measurementSheet.columns[columnIndex];

      if (!column) {
        continue;
      }

      measurementSheetHead
        ?.querySelector(`th[data-column-id="${CSS.escape(column.id)}"]`)
        ?.classList.add("is-fill-preview-column");

      const cell = getMeasurementCellElement(row.id, column.id);
      cell?.classList.add("is-fill-target");
      cell?.classList.add("is-fill-preview-selected");

      const columnPreview = targetColumns.find((item) => item.column.id === column.id);
      const input = getMeasurementInputElement(row.id, column.id);
      if (!(input instanceof HTMLInputElement) || !columnPreview) {
        continue;
      }

      if (typeof input.dataset.previewOriginalValue !== "string") {
        input.dataset.previewOriginalValue = input.value;
      }

      const sourceOffset = (rowIndex - (fillDrag.selectionRange.endRowIndex + 1)) % selectionHeight;
      const sourceRowIndex = fillDrag.selectionRange.startRowIndex + sourceOffset;
      let previewRawValue = shiftMeasurementFillValue(
        columnPreview.snapshotValues[sourceOffset] ?? "",
        rowIndex - sourceRowIndex,
        0,
      );

      if (columnPreview.canSeries) {
        const lastNumericValue = columnPreview.numericValues[columnPreview.numericValues.length - 1];
        const step = columnPreview.numericValues.length >= 2
          ? columnPreview.numericValues[columnPreview.numericValues.length - 1]
            - columnPreview.numericValues[columnPreview.numericValues.length - 2]
          : 1;
        previewRawValue = formatMeasurementSeriesValue(
          lastNumericValue + (step * (rowIndex - fillDrag.selectionRange.endRowIndex)),
        );
      }

      input.value = isMeasurementFormula(previewRawValue)
        ? previewRawValue
        : formatMeasurementLiteralDisplayValue(
          previewRawValue,
          columnPreview.snapshotFormats[sourceOffset],
        );
      input.classList.add("is-fill-previewing");
    }
  }
}

function renderMeasurementFillMenu() {
  if (!measurementFillMenu || !measurementSheetPanel) {
    return;
  }

  const fillMenuState = state.measurementSheet.fillMenu;

  if (!fillMenuState) {
    measurementFillMenu.hidden = true;
    measurementFillMenu.style.left = "";
    measurementFillMenu.style.top = "";
    return;
  }

  const panelRect = measurementSheetPanel.getBoundingClientRect();
  const estimatedWidth = 212;
  const estimatedHeight = 52;
  const left = Math.min(
    Math.max(fillMenuState.x - panelRect.left + 12, 12),
    Math.max(12, panelRect.width - estimatedWidth - 12),
  );
  const top = Math.min(
    Math.max(fillMenuState.y - panelRect.top + 12, 12),
    Math.max(12, panelRect.height - estimatedHeight - 12),
  );

  measurementFillMenu.hidden = false;
  measurementFillMenu.style.left = `${left}px`;
  measurementFillMenu.style.top = `${top}px`;
}

function closeMeasurementFillMenu() {
  if (!state.measurementSheet.fillMenu) {
    return;
  }

  state.measurementSheet.fillMenu = null;
  clearMeasurementFillPreview();
  renderMeasurementFillMenu();
  renderMeasurementSelection();
}

function openMeasurementFillMenu(pendingFill, pointerX, pointerY) {
  closeMeasurementContextMenu();
  state.measurementSheet.fillMenu = {
    x: pointerX,
    y: pointerY,
    pendingFill,
  };
  renderMeasurementFillPreview();
  renderMeasurementFillMenu();
}

function renderMeasurementContextMenu() {
  if (!measurementContextMenu || !measurementSheetPanel) {
    return;
  }

  const contextMenuState = state.measurementSheet.contextMenu;

  if (!contextMenuState) {
    measurementContextMenu.hidden = true;
    measurementContextMenu.style.left = "";
    measurementContextMenu.style.top = "";
    return;
  }

  const hasRowActions = Number.isInteger(contextMenuState.rowIndex);
  const hasColumnActions = Number.isInteger(contextMenuState.columnIndex)
    && !state.measurementSheet.columns[contextMenuState.columnIndex]?.computed;

  measurementContextAddRowAboveButton.hidden = !hasRowActions;
  measurementContextAddRowBelowButton.hidden = !hasRowActions;
  measurementContextDeleteRowButton.hidden = !hasRowActions;
  measurementContextAddColumnLeftButton.hidden = !hasColumnActions;
  measurementContextAddColumnRightButton.hidden = !hasColumnActions;
  measurementContextDeleteColumnButton.hidden = !hasColumnActions;
  if (measurementContextDeleteRowButton) {
    measurementContextDeleteRowButton.disabled = state.measurementSheet.rows.length <= 1;
  }
  if (measurementContextDeleteColumnButton) {
    measurementContextDeleteColumnButton.disabled = getEditableMeasurementColumnIndexes().length <= 1;
  }

  if (!hasRowActions && !hasColumnActions) {
    measurementContextMenu.hidden = true;
    measurementContextMenu.style.left = "";
    measurementContextMenu.style.top = "";
    return;
  }

  const panelRect = measurementSheetPanel.getBoundingClientRect();
  const visibleItems = [
    measurementContextAddRowAboveButton,
    measurementContextAddRowBelowButton,
    measurementContextDeleteRowButton,
    measurementContextAddColumnLeftButton,
    measurementContextAddColumnRightButton,
    measurementContextDeleteColumnButton,
  ].filter((button) => !button.hidden).length;
  const estimatedWidth = 220;
  const estimatedHeight = visibleItems * 42 + 16;
  const left = Math.min(
    Math.max(contextMenuState.x - panelRect.left + 10, 10),
    Math.max(10, panelRect.width - estimatedWidth - 10),
  );
  const top = Math.min(
    Math.max(contextMenuState.y - panelRect.top + 10, 10),
    Math.max(10, panelRect.height - estimatedHeight - 10),
  );

  measurementContextMenu.hidden = false;
  measurementContextMenu.style.left = `${left}px`;
  measurementContextMenu.style.top = `${top}px`;
}

function closeMeasurementContextMenu() {
  if (!state.measurementSheet.contextMenu) {
    return;
  }

  state.measurementSheet.contextMenu = null;
  renderMeasurementContextMenu();
}

function openMeasurementContextMenu({ pointerX, pointerY, rowIndex = null, columnIndex = null }) {
  const hasRowActions = Number.isInteger(rowIndex);
  const hasColumnActions = Number.isInteger(columnIndex)
    && !state.measurementSheet.columns[columnIndex]?.computed;

  if (!hasRowActions && !hasColumnActions) {
    closeMeasurementContextMenu();
    return;
  }

  closeMeasurementFillMenu();
  state.measurementSheet.contextMenu = {
    x: pointerX,
    y: pointerY,
    rowIndex: hasRowActions ? rowIndex : null,
    columnIndex: hasColumnActions ? columnIndex : null,
  };
  renderMeasurementContextMenu();
}

function setMeasurementSelection(rowId, columnId, options = {}) {
  const rowIndex = getMeasurementRowIndex(rowId);
  const columnIndex = getMeasurementColumnIndex(columnId);

  if (rowIndex < 0 || columnIndex < 0) {
    return;
  }

  setMeasurementSelectionByIndex(rowIndex, columnIndex, options);
}

function startMeasurementSelectionDrag(rowId, columnId, pointerId) {
  const rowIndex = getMeasurementRowIndex(rowId);
  const columnIndex = getMeasurementColumnIndex(columnId);

  if (rowIndex < 0 || columnIndex < 0) {
    return;
  }

  const anchor = state.measurementSheet.selectionAnchor ?? { rowIndex, columnIndex };

  state.measurementSheet.selectionDrag = {
    mode: "cells",
    pointerId,
    anchorRowIndex: anchor.rowIndex,
    anchorColumnIndex: anchor.columnIndex,
    rowIndex,
    columnIndex,
    hasMoved: false,
  };

  document.body.classList.add("is-selecting-measurement-cells");
}

function startMeasurementHeaderSelectionDrag(mode, index, pointerId) {
  if (!["rows", "columns"].includes(mode)) {
    return;
  }

  const firstColumnIndex = getFirstEditableMeasurementColumnIndex();
  const lastColumnIndex = getLastEditableMeasurementColumnIndex();

  if (firstColumnIndex < 0 || lastColumnIndex < firstColumnIndex || state.measurementSheet.rows.length === 0) {
    return;
  }

  state.measurementSheet.selectionDrag = {
    mode,
    pointerId,
    anchorRowIndex: mode === "rows"
      ? (state.measurementSheet.selectionAnchor?.rowIndex ?? index)
      : 0,
    anchorColumnIndex: mode === "columns"
      ? (state.measurementSheet.selectionAnchor?.columnIndex ?? index)
      : firstColumnIndex,
    rowIndex: mode === "rows" ? index : state.measurementSheet.rows.length - 1,
    columnIndex: mode === "columns" ? index : lastColumnIndex,
    hasMoved: false,
  };

  document.body.classList.add("is-selecting-measurement-cells");
}

function resolveMeasurementPointerRowIndex(pointerX, pointerY) {
  const directTarget = document.elementFromPoint(pointerX, pointerY);
  const directRowId = directTarget instanceof HTMLElement
    ? (directTarget.closest("td[data-row-id][data-column-id]")?.dataset.rowId
      || directTarget.closest("tr[data-row-id]")?.dataset.rowId)
    : "";

  if (directRowId) {
    return getMeasurementRowIndex(directRowId);
  }

  const visibleRows = Array.from(measurementSheetBody?.querySelectorAll("tr[data-row-id]") ?? []);
  if (visibleRows.length === 0) {
    return -1;
  }

  const firstVisibleRow = visibleRows[0];
  const lastVisibleRow = visibleRows[visibleRows.length - 1];
  const firstRect = firstVisibleRow?.getBoundingClientRect?.();
  const lastRect = lastVisibleRow?.getBoundingClientRect?.();

  if (firstRect && pointerY <= firstRect.top) {
    return getMeasurementRowIndex(firstVisibleRow.dataset.rowId);
  }

  if (lastRect && pointerY >= lastRect.bottom) {
    return getMeasurementRowIndex(lastVisibleRow.dataset.rowId);
  }

  for (const rowElement of visibleRows) {
    const rect = rowElement.getBoundingClientRect();
    if (pointerY >= rect.top && pointerY <= rect.bottom) {
      return getMeasurementRowIndex(rowElement.dataset.rowId);
    }
  }

  return -1;
}

function resolveMeasurementPointerColumnIndex(pointerX, pointerY) {
  const directTarget = document.elementFromPoint(pointerX, pointerY);
  const directColumnId = directTarget instanceof HTMLElement
    ? (directTarget.closest("td[data-column-id][data-row-id]")?.dataset.columnId
      || directTarget.closest("th[data-column-id]")?.dataset.columnId)
    : "";

  if (directColumnId) {
    return getMeasurementColumnIndex(directColumnId);
  }

  const visibleColumns = Array.from(measurementSheetHead?.querySelectorAll("th[data-column-id]") ?? []);
  if (visibleColumns.length === 0) {
    return -1;
  }

  const firstVisibleColumn = visibleColumns[0];
  const lastVisibleColumn = visibleColumns[visibleColumns.length - 1];
  const firstRect = firstVisibleColumn?.getBoundingClientRect?.();
  const lastRect = lastVisibleColumn?.getBoundingClientRect?.();

  if (firstRect && pointerX <= firstRect.left) {
    return getMeasurementColumnIndex(firstVisibleColumn.dataset.columnId);
  }

  if (lastRect && pointerX >= lastRect.right) {
    return getMeasurementColumnIndex(lastVisibleColumn.dataset.columnId);
  }

  for (const columnElement of visibleColumns) {
    const rect = columnElement.getBoundingClientRect();
    if (pointerX >= rect.left && pointerX <= rect.right) {
      return getMeasurementColumnIndex(columnElement.dataset.columnId);
    }
  }

  return -1;
}

function updateMeasurementSelectionDragTarget(pointerX, pointerY) {
  const selectionDrag = state.measurementSheet.selectionDrag;

  if (!selectionDrag) {
    return;
  }

  if (selectionDrag.mode === "rows") {
    const rowIndex = resolveMeasurementPointerRowIndex(pointerX, pointerY);
    const firstColumnIndex = getFirstEditableMeasurementColumnIndex();
    const lastColumnIndex = getLastEditableMeasurementColumnIndex();

    if (rowIndex < 0 || firstColumnIndex < 0 || lastColumnIndex < firstColumnIndex) {
      return;
    }

    if (rowIndex === selectionDrag.rowIndex) {
      return;
    }

    selectionDrag.rowIndex = rowIndex;
    selectionDrag.columnIndex = lastColumnIndex;
    selectionDrag.hasMoved = true;
    state.measurementSheet.activeCell = {
      rowId: state.measurementSheet.rows[rowIndex]?.id,
      columnId: state.measurementSheet.columns[firstColumnIndex]?.id,
    };
    state.measurementSheet.selectedRange = createMeasurementSelectionRange(
      selectionDrag.anchorRowIndex,
      firstColumnIndex,
      rowIndex,
      lastColumnIndex,
    );
    state.measurementSheet.fillMenu = null;
    state.measurementSheet.contextMenu = null;
    clearMeasurementFillPreview();
    renderMeasurementSelection();
    renderMeasurementActiveCell();
    renderMeasurementContextMenu();
    syncMeasurementToolbar();
    return;
  }

  if (selectionDrag.mode === "columns") {
    const columnIndex = resolveMeasurementPointerColumnIndex(pointerX, pointerY);
    if (columnIndex < 0 || state.measurementSheet.columns[columnIndex]?.computed || state.measurementSheet.rows.length === 0) {
      return;
    }

    if (columnIndex === selectionDrag.columnIndex) {
      return;
    }

    selectionDrag.columnIndex = columnIndex;
    selectionDrag.rowIndex = state.measurementSheet.rows.length - 1;
    selectionDrag.hasMoved = true;
    state.measurementSheet.activeCell = {
      rowId: state.measurementSheet.rows[0]?.id,
      columnId: state.measurementSheet.columns[columnIndex]?.id,
    };
    state.measurementSheet.selectedRange = createMeasurementSelectionRange(
      0,
      selectionDrag.anchorColumnIndex,
      state.measurementSheet.rows.length - 1,
      columnIndex,
    );
    state.measurementSheet.fillMenu = null;
    state.measurementSheet.contextMenu = null;
    clearMeasurementFillPreview();
    renderMeasurementSelection();
    renderMeasurementActiveCell();
    renderMeasurementContextMenu();
    syncMeasurementToolbar();
    return;
  }

  const rowIndex = resolveMeasurementPointerRowIndex(pointerX, pointerY);
  const columnIndex = resolveMeasurementPointerColumnIndex(pointerX, pointerY);

  if (rowIndex < 0 || columnIndex < 0 || state.measurementSheet.columns[columnIndex]?.computed) {
    return;
  }

  if (rowIndex === selectionDrag.rowIndex && columnIndex === selectionDrag.columnIndex) {
    return;
  }

  selectionDrag.rowIndex = rowIndex;
  selectionDrag.columnIndex = columnIndex;
  selectionDrag.hasMoved = true;
  state.measurementSheet.activeCell = {
    rowId: state.measurementSheet.rows[rowIndex]?.id,
    columnId: state.measurementSheet.columns[columnIndex]?.id,
  };
  state.measurementSheet.selectedRange = createMeasurementSelectionRange(
    selectionDrag.anchorRowIndex,
    selectionDrag.anchorColumnIndex,
    rowIndex,
    columnIndex,
  );
  state.measurementSheet.fillMenu = null;
  state.measurementSheet.contextMenu = null;
  clearMeasurementFillPreview();
  renderMeasurementSelection();
  renderMeasurementActiveCell();
  renderMeasurementContextMenu();
}

function stopMeasurementSelectionDrag() {
  const selectionDrag = state.measurementSheet.selectionDrag;

  if (!selectionDrag) {
    return;
  }

  state.measurementSheet.selectionDrag = null;
  document.body.classList.remove("is-selecting-measurement-cells");
}

function selectMeasurementRow(rowIndex, options = {}) {
  const {
    extend = false,
  } = options;
  ensureMeasurementSheetStructure();
  const row = state.measurementSheet.rows[rowIndex];
  const firstColumnIndex = getFirstEditableMeasurementColumnIndex();
  const lastColumnIndex = getLastEditableMeasurementColumnIndex();

  if (!row || firstColumnIndex < 0 || lastColumnIndex < firstColumnIndex) {
    return;
  }

  const anchorRowIndex = extend && Number.isInteger(state.measurementSheet.selectionAnchor?.rowIndex)
    ? state.measurementSheet.selectionAnchor.rowIndex
    : rowIndex;

  state.measurementSheet.activeCell = {
    rowId: row.id,
    columnId: state.measurementSheet.columns[firstColumnIndex].id,
  };
  state.measurementSheet.selectionAnchor = {
    rowIndex: anchorRowIndex,
    columnIndex: firstColumnIndex,
  };
  state.measurementSheet.selectedRange = createMeasurementSelectionRange(
    anchorRowIndex,
    firstColumnIndex,
    rowIndex,
    lastColumnIndex,
  );
  state.measurementSheet.fillMenu = null;
  state.measurementSheet.contextMenu = null;
  renderMeasurementSelection();
  renderMeasurementActiveCell();
  renderMeasurementContextMenu();
  syncMeasurementToolbar();
}

function selectMeasurementColumn(columnIndex, options = {}) {
  const {
    extend = false,
  } = options;
  ensureMeasurementSheetStructure();
  const column = state.measurementSheet.columns[columnIndex];

  if (!column || column.computed || state.measurementSheet.rows.length === 0) {
    return;
  }

  const anchorColumnIndex = extend && Number.isInteger(state.measurementSheet.selectionAnchor?.columnIndex)
    ? state.measurementSheet.selectionAnchor.columnIndex
    : columnIndex;

  state.measurementSheet.activeCell = {
    rowId: state.measurementSheet.rows[0].id,
    columnId: column.id,
  };
  state.measurementSheet.selectionAnchor = {
    rowIndex: 0,
    columnIndex: anchorColumnIndex,
  };
  state.measurementSheet.selectedRange = createMeasurementSelectionRange(
    0,
    anchorColumnIndex,
    state.measurementSheet.rows.length - 1,
    columnIndex,
  );
  state.measurementSheet.fillMenu = null;
  state.measurementSheet.contextMenu = null;
  renderMeasurementSelection();
  renderMeasurementActiveCell();
  renderMeasurementContextMenu();
  syncMeasurementToolbar();
}

function selectAllMeasurementCells() {
  ensureMeasurementSheetStructure();
  const firstColumnIndex = getFirstEditableMeasurementColumnIndex();
  const lastColumnIndex = state.measurementSheet.columns.length - 1;

  if (state.measurementSheet.rows.length === 0 || firstColumnIndex < 0 || lastColumnIndex < firstColumnIndex) {
    return;
  }

  state.measurementSheet.activeCell = {
    rowId: state.measurementSheet.rows[0].id,
    columnId: state.measurementSheet.columns[firstColumnIndex].id,
  };
  state.measurementSheet.selectionAnchor = {
    rowIndex: 0,
    columnIndex: firstColumnIndex,
  };
  state.measurementSheet.selectedRange = createMeasurementSelectionRange(
    0,
    firstColumnIndex,
    state.measurementSheet.rows.length - 1,
    lastColumnIndex,
  );
  state.measurementSheet.fillMenu = null;
  state.measurementSheet.contextMenu = null;
  renderMeasurementSelection();
  renderMeasurementActiveCell();
  renderMeasurementContextMenu();
  syncMeasurementToolbar();
}

function moveMeasurementSelection(direction, options = {}) {
  ensureMeasurementSheetStructure();
  const editableIndexes = getEditableMeasurementColumnIndexes();

  if (!editableIndexes.length) {
    return;
  }

  if (state.measurementSheet.editingCell) {
    commitMeasurementEditMode();
  }

  const {
    extend = false,
  } = options;

  let rowIndex = state.measurementSheet.activeCell
    ? getMeasurementRowIndex(state.measurementSheet.activeCell.rowId)
    : 0;
  let columnIndex = state.measurementSheet.activeCell
    ? getMeasurementColumnIndex(state.measurementSheet.activeCell.columnId)
    : editableIndexes[0];

  if (rowIndex < 0) {
    rowIndex = 0;
  }

  if (columnIndex < 0 || state.measurementSheet.columns[columnIndex]?.computed) {
    columnIndex = editableIndexes[0];
  }

  let editablePosition = editableIndexes.indexOf(columnIndex);

  if (editablePosition < 0) {
    editablePosition = 0;
    columnIndex = editableIndexes[0];
  }

  let targetRowIndex = rowIndex;
  let targetColumnIndex = columnIndex;

  if (direction === "left") {
    targetColumnIndex = editableIndexes[Math.max(0, editablePosition - 1)] ?? columnIndex;
  }

  if (direction === "right") {
    targetColumnIndex = editableIndexes[Math.min(editableIndexes.length - 1, editablePosition + 1)] ?? columnIndex;
  }

  if (direction === "up") {
    targetRowIndex = Math.max(0, rowIndex - 1);
  }

  if (direction === "down") {
    ensureMeasurementRowsThrough(rowIndex + 1);
    targetRowIndex = Math.min(state.measurementSheet.rows.length - 1, rowIndex + 1);
  }

  if (direction === "tab-next") {
    if (editablePosition >= editableIndexes.length - 1) {
      ensureMeasurementRowsThrough(rowIndex + 1);
      targetRowIndex = Math.min(state.measurementSheet.rows.length - 1, rowIndex + 1);
      targetColumnIndex = editableIndexes[0];
    } else {
      targetColumnIndex = editableIndexes[editablePosition + 1];
    }
  }

  if (direction === "tab-prev") {
    if (editablePosition <= 0) {
      if (rowIndex === 0) {
        targetColumnIndex = editableIndexes[0];
      } else {
        targetRowIndex = rowIndex - 1;
        targetColumnIndex = editableIndexes[editableIndexes.length - 1];
      }
    } else {
      targetColumnIndex = editableIndexes[editablePosition - 1];
    }
  }

  setMeasurementSelectionByIndex(targetRowIndex, targetColumnIndex, {
    extend,
  });
}

function buildMeasurementClipboardText(range) {
  const rows = [];

  for (let rowIndex = range.startRowIndex; rowIndex <= range.endRowIndex; rowIndex += 1) {
    const values = [];

    for (let columnIndex = range.startColumnIndex; columnIndex <= range.endColumnIndex; columnIndex += 1) {
      values.push(getMeasurementCellDisplayValue(rowIndex, columnIndex));
    }

    rows.push(values.join("\t"));
  }

  return rows.join("\n");
}

function parseMeasurementClipboardText(text) {
  return String(text ?? "")
    .replace(/\r/g, "")
    .split("\n")
    .filter((row, index, rows) => row.length > 0 || index < rows.length - 1)
    .map((row) => row.split("\t"));
}

function pasteMeasurementClipboard(text) {
  const matrix = parseMeasurementClipboardText(text);

  if (!matrix.length || matrix.every((row) => row.length === 1 && row[0] === "")) {
    return false;
  }

  ensureMeasurementSheetStructure();
  const editableIndexes = getEditableMeasurementColumnIndexes();

  if (!editableIndexes.length) {
    return false;
  }

  let startRowIndex = state.measurementSheet.activeCell
    ? getMeasurementRowIndex(state.measurementSheet.activeCell.rowId)
    : 0;
  let startColumnIndex = state.measurementSheet.activeCell
    ? getMeasurementColumnIndex(state.measurementSheet.activeCell.columnId)
    : editableIndexes[0];

  if (startRowIndex < 0) {
    startRowIndex = 0;
  }

  if (startColumnIndex < 0 || state.measurementSheet.columns[startColumnIndex]?.computed) {
    startColumnIndex = editableIndexes[0];
  }

  const maxWidth = Math.max(...matrix.map((row) => Math.max(1, row.length)));
  ensureMeasurementRowsThrough(startRowIndex + matrix.length - 1);
  const targetColumnIndexes = ensureMeasurementEditableColumnsFrom(startColumnIndex, maxWidth);

  matrix.forEach((clipboardRow, rowOffset) => {
    const row = state.measurementSheet.rows[startRowIndex + rowOffset];

    targetColumnIndexes.forEach((columnIndex, columnOffset) => {
      const column = state.measurementSheet.columns[columnIndex];

      if (!row?.cells || !column || column.computed) {
        return;
      }

      row.cells[column.id] = clipboardRow[columnOffset] ?? "";
    });
  });

  const endRowIndex = startRowIndex + matrix.length - 1;
  const endColumnIndex = targetColumnIndexes[Math.max(0, maxWidth - 1)] ?? startColumnIndex;
  state.measurementSheet.selectedRange = createMeasurementSelectionRange(
    startRowIndex,
    startColumnIndex,
    endRowIndex,
    endColumnIndex,
  );
  state.measurementSheet.selectionAnchor = {
    rowIndex: startRowIndex,
    columnIndex: startColumnIndex,
  };
  state.measurementSheet.activeCell = {
    rowId: state.measurementSheet.rows[endRowIndex]?.id ?? state.measurementSheet.rows[startRowIndex]?.id,
    columnId: state.measurementSheet.columns[endColumnIndex]?.id ?? state.measurementSheet.columns[startColumnIndex]?.id,
  };
  state.measurementSheet.fillMenu = null;
  renderMeasurementSheet();
  focusMeasurementCell(
    state.measurementSheet.activeCell.rowId,
    state.measurementSheet.activeCell.columnId,
  );
  handleMeasurementSheetMutation();
  return true;
}

function clearMeasurementRange(range) {
  if (!range) {
    return;
  }

  for (let rowIndex = range.startRowIndex; rowIndex <= range.endRowIndex; rowIndex += 1) {
    const row = state.measurementSheet.rows[rowIndex];

    if (!row?.cells) {
      continue;
    }

    for (let columnIndex = range.startColumnIndex; columnIndex <= range.endColumnIndex; columnIndex += 1) {
      const column = state.measurementSheet.columns[columnIndex];

      if (!column || column.computed) {
        continue;
      }

      row.cells[column.id] = "";
    }
  }

  handleMeasurementSheetMutation();
}

function syncMeasurementSheetHeaderFromWorkOrder() {
  if (state.measurementSheet.ownerKind === "template_field") {
    const fieldIndex = getMeasurementSheetOwnerFieldIndex();
    const field = fieldIndex >= 0 ? documentTemplateFieldDrafts[fieldIndex] : null;
    const template = buildDocumentTemplateDraft();
    const company = getCompany(documentTemplateCompanyIdInput?.value || template.sampleCompanyId || "");
    const location = getLocation(documentTemplateLocationIdInput?.value || template.sampleLocationId || "");

    if (measurementCompanyInput) {
      measurementCompanyInput.value = company?.name || documentTemplateTitleInput?.value || "Template Excel";
    }

    if (measurementHeadquartersInput) {
      measurementHeadquartersInput.value = company?.headquarters || field?.label || "Excel tablica";
    }

    if (measurementLocationInput) {
      measurementLocationInput.value = location?.name || getMeasurementSheetTemplateSummary(field?.sheet);
    }

    if (measurementDateInput) {
      measurementDateInput.value = new Date().toISOString().slice(0, 10);
    }

    return;
  }

  if (state.measurementSheet.ownerKind === "document_template_runtime_field") {
    const activeWorkOrderId = String(
      state.measurementSheet.ownerRuntimeWorkOrderId
      || state.documentTemplateRuntime.activeWorkOrderId
      || "",
    ).trim();
    const workOrder = (state.workOrders ?? []).find((item) => String(item.id) === activeWorkOrderId) || null;
    const field = documentTemplateFieldDrafts.find((item) => String(item.id) === String(state.measurementSheet.ownerFieldId || "")) || null;
    const company = getCompany(workOrder?.companyId || "");
    const location = getLocation(workOrder?.locationId || "");

    if (measurementCompanyInput) {
      measurementCompanyInput.value = company?.name || documentTemplateTitleInput?.value || "Excel tablica";
    }

    if (measurementHeadquartersInput) {
      measurementHeadquartersInput.value = field?.label || "Excel tablica";
    }

    if (measurementLocationInput) {
      measurementLocationInput.value = [
        workOrder?.workOrderNumber || "",
        location?.name || "",
      ].filter(Boolean).join(" · ");
    }

    if (measurementDateInput) {
      measurementDateInput.value = getDocumentTemplateRuntimeValue(activeWorkOrderId, "inspectionDate")
        || new Date().toISOString().slice(0, 10);
    }

    return;
  }

  const company = getCompany(workOrderCompanyIdInput.value);
  const location = getLocation(workOrderLocationIdInput.value);

  if (measurementCompanyInput) {
    measurementCompanyInput.value = company?.name || "";
  }

  if (measurementHeadquartersInput) {
    measurementHeadquartersInput.value = workOrderHeadquartersInput.value || company?.headquarters || "";
  }

  if (measurementLocationInput) {
    measurementLocationInput.value = location?.name || "";
  }

  if (measurementDateInput) {
    measurementDateInput.value = workOrderOpenedDateInput.value || new Date().toISOString().slice(0, 10);
  }
}

function openTemplateMeasurementSheet(fieldId) {
  const fieldIndex = documentTemplateFieldDrafts.findIndex((field) => String(field.id) === String(fieldId));

  if (fieldIndex < 0) {
    return;
  }

  state.measurementSheet.ownerKind = "template_field";
  state.measurementSheet.ownerFieldId = String(fieldId);
  state.measurementSheet.validationPopoverOpen = false;
  documentTemplateFieldDrafts[fieldIndex].sheet = ensureDocumentTemplateMeasurementFieldSheet(documentTemplateFieldDrafts[fieldIndex]);
  applyMeasurementSheetSnapshot(documentTemplateFieldDrafts[fieldIndex].sheet);
  syncMeasurementSheetHeaderFromWorkOrder();
  renderMeasurementSheet();
  renderMeasurementSheetPresetLibrary();

  if (!state.measurementSheet.activeCell) {
    const firstColumnIndex = getFirstEditableMeasurementColumnIndex();

    if (firstColumnIndex >= 0 && state.measurementSheet.rows[0]) {
      setMeasurementSelectionByIndex(0, firstColumnIndex);
    }
  }

  setMeasurementSheetOpen(true);
  syncMeasurementToolbar();
  void loadMeasurementSheetPresetLibrary({ force: true });
}

function persistMeasurementSheetToDocumentTemplateRuntimeField({ rerenderFieldRows = false } = {}) {
  const workOrderId = String(
    state.measurementSheet.ownerRuntimeWorkOrderId
    || state.documentTemplateRuntime.activeWorkOrderId
    || "",
  ).trim();
  const fieldId = String(state.measurementSheet.ownerFieldId || "").trim();
  if (!workOrderId || !fieldId) {
    return;
  }

  const field = documentTemplateFieldDrafts.find((item) => String(item.id) === fieldId);
  const snapshot = buildMeasurementSheetSnapshot({ includeBlankStructure: true })
    ?? buildTemplateMeasurementSheetFromLegacyConfig(field ?? {});
  setDocumentTemplateRuntimeMeasurementSheet(workOrderId, fieldId, snapshot, { render: false });
  renderDocumentTemplatePreviewContent();
  syncDocumentTemplateEditorChrome();

  if (rerenderFieldRows) {
    renderDocumentTemplateFieldRows();
  }
}

function openDocumentTemplateRuntimeMeasurementSheet(fieldId, workOrderId = state.documentTemplateRuntime.activeWorkOrderId) {
  const normalizedFieldId = String(fieldId || "").trim();
  const normalizedWorkOrderId = String(workOrderId || "").trim();
  if (!normalizedFieldId || !normalizedWorkOrderId) {
    return;
  }

  const field = documentTemplateFieldDrafts.find((item) => String(item.id) === normalizedFieldId);
  if (!field) {
    return;
  }

  state.measurementSheet.ownerKind = "document_template_runtime_field";
  state.measurementSheet.ownerFieldId = normalizedFieldId;
  state.measurementSheet.ownerRuntimeWorkOrderId = normalizedWorkOrderId;
  applyMeasurementSheetSnapshot(getDocumentTemplateRuntimeMeasurementSheet(normalizedWorkOrderId, field));
  syncMeasurementSheetHeaderFromWorkOrder();
  renderMeasurementSheet();

  if (!state.measurementSheet.activeCell) {
    const firstColumnIndex = getFirstEditableMeasurementColumnIndex();

    if (firstColumnIndex >= 0 && state.measurementSheet.rows[0]) {
      setMeasurementSelectionByIndex(0, firstColumnIndex);
    }
  }

  setMeasurementSheetOpen(true);
  syncMeasurementToolbar();
}

function ensureDocumentTemplateRuntimeMeasurementSheetForField(fieldId, workOrderId = state.documentTemplateRuntime.activeWorkOrderId) {
  const normalizedFieldId = String(fieldId || "").trim();
  const normalizedWorkOrderId = String(workOrderId || "").trim();
  if (!normalizedFieldId || !normalizedWorkOrderId) {
    return;
  }

  const isSameField = state.measurementSheet.ownerKind === "document_template_runtime_field"
    && String(state.measurementSheet.ownerFieldId || "") === normalizedFieldId
    && String(state.measurementSheet.ownerRuntimeWorkOrderId || "") === normalizedWorkOrderId;

  if (!state.measurementSheet.isOpen || !isSameField) {
    openDocumentTemplateRuntimeMeasurementSheet(normalizedFieldId, normalizedWorkOrderId);
    return;
  }

  syncMeasurementSheetPanelMount();
  syncMeasurementToolbar();
}

function ensureTemplateMeasurementSheetForField(fieldId) {
  if (!fieldId) {
    return;
  }

  const normalizedFieldId = String(fieldId);
  const isSameField = state.measurementSheet.ownerKind === "template_field"
    && String(state.measurementSheet.ownerFieldId || "") === normalizedFieldId;

  if (!state.measurementSheet.isOpen || !isSameField) {
    openTemplateMeasurementSheet(normalizedFieldId);
    return;
  }

  syncMeasurementSheetPanelMount();
  syncMeasurementToolbar();
}

function buildDocumentTemplateInlineExcelPreview(field) {
  const sheet = ensureDocumentTemplateMeasurementFieldSheet(field);
  const preview = document.createElement("div");
  preview.className = "document-template-inline-excel-preview";

  const title = document.createElement("div");
  title.className = "document-template-inline-excel-preview-head";
  title.textContent = getMeasurementSheetTemplateSummary(sheet);

  const tableWrap = document.createElement("div");
  tableWrap.className = "document-template-inline-excel-preview-wrap";

  const table = document.createElement("table");
  table.className = "document-template-inline-excel-preview-table";

  const thead = document.createElement("thead");
  const headRow = document.createElement("tr");
  const indexHead = document.createElement("th");
  indexHead.textContent = "#";
  headRow.append(indexHead);
  sheet.columns.forEach((column, index) => {
    const th = document.createElement("th");
    th.textContent = column?.label || getSpreadsheetColumnLabel(index);
    headRow.append(th);
  });
  thead.append(headRow);

  const tbody = document.createElement("tbody");
  const visibleRows = sheet.rows.slice(0, Math.max(12, Math.min(24, sheet.rows.length || 12)));
  visibleRows.forEach((row, rowIndex) => {
    const tr = document.createElement("tr");
    const indexCell = document.createElement("th");
    indexCell.textContent = String(rowIndex + 1);
    tr.append(indexCell);
    sheet.columns.forEach((column) => {
      const td = document.createElement("td");
      td.textContent = String(row?.cells?.[column.id] ?? "").trim();
      tr.append(td);
    });
    tbody.append(tr);
  });

  table.append(thead, tbody);
  tableWrap.append(table);
  preview.append(title, tableWrap);
  return preview;
}

function buildDocumentTemplateInlineExcelEditor(field, draftIndex) {
  const fieldId = String(field?.id || "");
  const draft = documentTemplateFieldDrafts[draftIndex];
  let sheet = ensureDocumentTemplateMeasurementFieldSheet(draft ?? field);
  let previewRenderRaf = 0;

  const editor = document.createElement("div");
  editor.className = "document-template-inline-excel-editor";
  editor.dataset.templateFieldId = fieldId;

  const toolbar = document.createElement("div");
  toolbar.className = "document-template-inline-excel-editor-toolbar";

  const title = document.createElement("strong");
  title.className = "document-template-inline-excel-editor-title";
  title.textContent = "Excel tablica";

  const actions = document.createElement("div");
  actions.className = "document-template-inline-excel-editor-actions";

  const addRowButton = createActionButton("+ Red", "ghost-button");
  const addColumnButton = createActionButton("+ Kolona", "ghost-button");
  const resetButton = createActionButton("Reset", "ghost-button");
  const advancedButton = createActionButton("Napredni", "ghost-button");
  advancedButton.title = "Otvori napredni excel editor";

  actions.append(addRowButton, addColumnButton, resetButton, advancedButton);
  toolbar.append(title, actions);

  const gridWrap = document.createElement("div");
  gridWrap.className = "document-template-inline-excel-editor-grid-wrap";

  const syncDraftSheetMeta = () => {
    const currentDraft = documentTemplateFieldDrafts[draftIndex];
    if (!currentDraft || String(currentDraft.id || "") !== fieldId) {
      return;
    }
    currentDraft.type = "measurement_table";
    currentDraft.sheet = sheet;
    currentDraft.columns = sheet.columns.map((column) => column.label).join(", ");
    currentDraft.rowCount = String(Math.max(DEFAULT_MEASUREMENT_ROW_COUNT, sheet.rows.length || DEFAULT_MEASUREMENT_ROW_COUNT));
  };

  const queuePreviewRender = () => {
    if (previewRenderRaf) {
      cancelAnimationFrame(previewRenderRaf);
    }
    previewRenderRaf = requestAnimationFrame(() => {
      previewRenderRaf = 0;
      renderDocumentTemplatePreviewContent();
      syncDocumentTemplateEditorChrome();
    });
  };

  const buildColumnId = (index) => {
    const randomPart = Math.random().toString(36).slice(2, 8);
    return `measurement-inline-${fieldId || "field"}-${index + 1}-${randomPart}`;
  };

  const ensureRowShape = (row, rowIndex) => (
    normalizeMeasurementSheetRowSnapshotLocal(row, sheet.columns, rowIndex)
  );

  const renderGrid = () => {
    sheet.columns = sheet.columns.map((column, index) => (
      normalizeMeasurementSheetColumnSnapshotLocal(
        {
          ...column,
          id: column?.id || buildColumnId(index),
          label: String(column?.label || "").trim() || `Kolona ${index + 1}`,
        },
        index,
      )
    ));
    sheet.rows = sheet.rows.map((row, index) => ensureRowShape(row, index));
    syncDraftSheetMeta();

    const table = document.createElement("table");
    table.className = "document-template-inline-excel-editor-grid";

    const thead = document.createElement("thead");
    const headRow = document.createElement("tr");

    const indexHead = document.createElement("th");
    indexHead.className = "document-template-inline-excel-editor-index-head";
    indexHead.textContent = "#";
    headRow.append(indexHead);

    sheet.columns.forEach((column, columnIndex) => {
      const th = document.createElement("th");
      const headCell = document.createElement("div");
      headCell.className = "document-template-inline-excel-editor-head-cell";

      const letter = document.createElement("span");
      letter.className = "document-template-inline-excel-editor-letter";
      letter.textContent = getSpreadsheetColumnLabel(columnIndex);

      const labelInput = document.createElement("input");
      labelInput.type = "text";
      labelInput.className = "document-template-inline-excel-editor-column-input";
      labelInput.value = column.label || `Kolona ${columnIndex + 1}`;
      labelInput.addEventListener("input", (event) => {
        const nextLabel = String(event.currentTarget.value || "").trim() || `Kolona ${columnIndex + 1}`;
        sheet.columns[columnIndex].label = nextLabel;
        sheet.columns[columnIndex].placeholder = nextLabel;
        syncDraftSheetMeta();
        queuePreviewRender();
      });

      headCell.append(letter, labelInput);
      th.append(headCell);
      headRow.append(th);
    });

    thead.append(headRow);

    const tbody = document.createElement("tbody");
    sheet.rows.forEach((row, rowIndex) => {
      const tr = document.createElement("tr");

      const rowHead = document.createElement("th");
      rowHead.className = "document-template-inline-excel-editor-row-head";
      rowHead.textContent = String(rowIndex + 1);
      tr.append(rowHead);

      sheet.columns.forEach((column, columnIndex) => {
        const td = document.createElement("td");
        const input = document.createElement("input");
        input.type = "text";
        input.className = "document-template-inline-excel-editor-cell-input";
        input.value = String(row?.cells?.[column.id] ?? "");
        input.placeholder = column.placeholder || column.label || getSpreadsheetColumnLabel(columnIndex);
        input.addEventListener("input", (event) => {
          if (!sheet.rows[rowIndex]) {
            return;
          }
          if (!sheet.rows[rowIndex].cells || typeof sheet.rows[rowIndex].cells !== "object") {
            sheet.rows[rowIndex].cells = {};
          }
          if (!sheet.rows[rowIndex].formats || typeof sheet.rows[rowIndex].formats !== "object") {
            sheet.rows[rowIndex].formats = {};
          }

          sheet.rows[rowIndex].cells[column.id] = String(event.currentTarget.value ?? "");
          sheet.rows[rowIndex].formats[column.id] = normalizeMeasurementCellFormat(sheet.rows[rowIndex].formats[column.id]);
          syncDraftSheetMeta();
          queuePreviewRender();
        });

        td.append(input);
        tr.append(td);
      });

      tbody.append(tr);
    });

    table.append(thead, tbody);
    gridWrap.replaceChildren(table);
  };

  addRowButton.addEventListener("click", () => {
    const nextRow = normalizeMeasurementSheetRowSnapshotLocal({}, sheet.columns, sheet.rows.length);
    sheet.rows.push(nextRow);
    syncDraftSheetMeta();
    renderGrid();
    queuePreviewRender();
    requestAnimationFrame(() => {
      gridWrap.scrollTop = gridWrap.scrollHeight;
    });
  });

  addColumnButton.addEventListener("click", () => {
    const columnIndex = sheet.columns.length;
    const fallbackLabel = `Kolona ${columnIndex + 1}`;
    const nextColumn = normalizeMeasurementSheetColumnSnapshotLocal(
      {
        id: buildColumnId(columnIndex),
        label: fallbackLabel,
        placeholder: fallbackLabel,
        width: 160,
      },
      columnIndex,
    );
    sheet.columns.push(nextColumn);
    sheet.rows = sheet.rows.map((row, rowIndex) => ensureRowShape(row, rowIndex));
    syncDraftSheetMeta();
    renderGrid();
    queuePreviewRender();
  });

  resetButton.addEventListener("click", () => {
    sheet = buildTemplateMeasurementSheetFromLegacyConfig({
      columns: ["Pozicija", "Opis", "Vrijednost", "Granica", "Napomena"],
      rowCount: 12,
    });
    syncDraftSheetMeta();
    renderGrid();
    queuePreviewRender();
  });

  advancedButton.addEventListener("click", () => {
    openTemplateMeasurementSheet(fieldId);
  });

  renderGrid();
  editor.append(toolbar, gridWrap);
  return editor;
}

function syncDocumentTemplateInlineExcelPreviewVisibility() {
  if (!documentTemplateCustomFields) {
    return;
  }

  const activeFieldId = (
    state.measurementSheet.ownerKind === "template_field"
    || state.measurementSheet.ownerKind === "document_template_runtime_field"
  )
    ? String(state.measurementSheet.ownerFieldId || "")
    : "";
  const isInlineOpen = state.measurementSheet.isOpen
    && (
      state.measurementSheet.ownerKind === "template_field"
      || state.measurementSheet.ownerKind === "document_template_runtime_field"
    )
    && Boolean(activeFieldId);

  documentTemplateCustomFields.querySelectorAll(".document-template-inline-excel-host").forEach((host) => {
    if (!(host instanceof HTMLElement)) {
      return;
    }

    const hostFieldId = String(host.dataset.templateFieldId || "");
    const isActiveHost = isInlineOpen && hostFieldId === activeFieldId;
    const hasInlinePanel = host.querySelector(".measurement-sheet-panel") instanceof HTMLElement;
    host.classList.toggle("is-active", isActiveHost);
    host.querySelectorAll(".document-template-inline-excel-preview").forEach((preview) => {
      if (preview instanceof HTMLElement) {
        preview.hidden = isActiveHost && hasInlinePanel;
      }
    });
  });
}

function getTemplateMeasurementSheetInlineHost(fieldId = state.measurementSheet.ownerFieldId) {
  if (!fieldId) {
    return null;
  }

  const normalizedFieldId = String(fieldId);
  const mappedHost = documentTemplateMeasurementInlineHosts.get(normalizedFieldId);
  if (mappedHost instanceof HTMLElement && mappedHost.isConnected) {
    return mappedHost;
  }

  if (!documentTemplateCustomFields) {
    return null;
  }

  const escapedFieldId = typeof CSS !== "undefined" && typeof CSS.escape === "function"
    ? CSS.escape(normalizedFieldId)
    : normalizedFieldId.replace(/["\\]/g, "\\$&");
  const fieldRow = documentTemplateCustomFields.querySelector(`.document-template-item-card[data-template-field-id="${escapedFieldId}"]`);
  if (!(fieldRow instanceof HTMLElement)) {
    return null;
  }

  const host = fieldRow.querySelector(".document-template-inline-excel-host");
  if (host instanceof HTMLElement) {
    documentTemplateMeasurementInlineHosts.set(normalizedFieldId, host);
    return host;
  }

  return null;
}

function syncMeasurementSheetPanelMount() {
  if (!measurementSheetPanel) {
    return;
  }

  const shouldMountInline = state.measurementSheet.isOpen && (
    state.measurementSheet.ownerKind === "template_field"
    || state.measurementSheet.ownerKind === "document_template_runtime_field"
  );
  let inlineHost = shouldMountInline
    ? getTemplateMeasurementSheetInlineHost(state.measurementSheet.ownerFieldId)
    : null;

  if (!inlineHost && shouldMountInline && documentTemplateCustomFields) {
    const firstHost = documentTemplateCustomFields.querySelector(".document-template-inline-excel-host");
    if (firstHost instanceof HTMLElement) {
      inlineHost = firstHost;
      const fallbackFieldId = String(firstHost.dataset.templateFieldId || "").trim();
      if (fallbackFieldId) {
        state.measurementSheet.ownerFieldId = fallbackFieldId;
      }
    }
  }

  documentTemplateCustomFields?.querySelectorAll(".document-template-inline-excel-host").forEach((host) => {
    if (host instanceof HTMLElement) {
      host.hidden = false;
      host.removeAttribute("hidden");
    }
  });

  if (inlineHost) {
    if (measurementSheetPanel.parentElement !== inlineHost) {
      inlineHost.append(measurementSheetPanel);
    }
    measurementSheetPanel.classList.add("is-inline-template-sheet");
    if (measurementSheetModal) {
      measurementSheetModal.hidden = true;
    }
    syncDocumentTemplateInlineExcelPreviewVisibility();
    document.body.classList.remove("measurement-sheet-open");
    return;
  }

  measurementSheetPanel.classList.remove("is-inline-template-sheet");
  if (measurementSheetModal && measurementSheetPanel.parentElement !== measurementSheetModal) {
    measurementSheetModal.append(measurementSheetPanel);
  }
  if (measurementSheetModal) {
    measurementSheetModal.hidden = !state.measurementSheet.isOpen;
  }
  syncDocumentTemplateInlineExcelPreviewVisibility();
}

function renderMeasurementSheet() {
  ensureMeasurementSheetStructure();

  if (!measurementSheetBody || !measurementSheetHead || !measurementSheetColgroup) {
    return;
  }

  const mergeDescriptors = getMeasurementMergeDescriptors();
  const mergeAnchorMap = new Map();
  const coveredCells = new Set();

  mergeDescriptors.forEach((merge) => {
    mergeAnchorMap.set(`${merge.anchorRowIndex}:${merge.anchorColumnIndex}`, merge);

    for (let rowIndex = merge.anchorRowIndex; rowIndex <= merge.endRowIndex; rowIndex += 1) {
      for (let columnIndex = merge.anchorColumnIndex; columnIndex <= merge.endColumnIndex; columnIndex += 1) {
        if (rowIndex === merge.anchorRowIndex && columnIndex === merge.anchorColumnIndex) {
          continue;
        }

        coveredCells.add(`${rowIndex}:${columnIndex}`);
      }
    }
  });

  const colgroupFragment = document.createDocumentFragment();
  const cornerCol = document.createElement("col");
  cornerCol.style.width = "54px";
  colgroupFragment.append(cornerCol);

  state.measurementSheet.columns.forEach((column) => {
    const col = document.createElement("col");
    col.style.width = `${column.width || 140}px`;
    colgroupFragment.append(col);
  });

  measurementSheetColgroup.replaceChildren(colgroupFragment);

  const headRow = document.createElement("tr");
  const cornerHeader = document.createElement("th");
  cornerHeader.className = "measurement-sheet-corner";
  cornerHeader.textContent = "#";
  cornerHeader.title = "Oznaci cijelu tablicu";
  cornerHeader.addEventListener("click", () => {
    selectAllMeasurementCells();
  });
  cornerHeader.addEventListener("contextmenu", (event) => {
    event.preventDefault();
    closeMeasurementContextMenu();
  });
  headRow.append(cornerHeader);

  state.measurementSheet.columns.forEach((column, index) => {
    const th = document.createElement("th");
    th.dataset.columnId = column.id;
    th.classList.toggle(
      "has-validation-list",
      normalizeMeasurementSheetColumnValidationSnapshotLocal(column.validation, new Set(), column.id).type === "list",
    );

    const head = document.createElement("div");
    head.className = "measurement-column-head";

    const letter = document.createElement("span");
    letter.className = "measurement-column-letter";
    letter.textContent = getSpreadsheetColumnLabel(index);

      const title = document.createElement(column.readonly ? "span" : "input");
      title.className = column.readonly
        ? "measurement-column-title is-readonly"
        : "measurement-column-title";

    if (column.readonly) {
      title.textContent = column.label;
    } else {
      title.type = "text";
      title.value = column.label;
      title.addEventListener("input", (event) => {
        column.label = event.currentTarget.value || "Nova kolona";
      });
    }

    const resizeHandle = document.createElement("button");
    resizeHandle.type = "button";
    resizeHandle.className = "measurement-column-resize";
    resizeHandle.setAttribute("aria-label", `Promijeni sirinu kolone ${column.label}`);
    resizeHandle.addEventListener("pointerdown", (event) => {
      event.preventDefault();
      state.measurementSheet.resizing = {
        columnId: column.id,
        startX: event.clientX,
        startWidth: column.width || 140,
      };
      resizeHandle.setPointerCapture?.(event.pointerId);
      document.body.classList.add("is-resizing-measurement-column");
    });

    head.append(letter, title, resizeHandle);
    if (normalizeMeasurementSheetColumnValidationSnapshotLocal(column.validation, new Set(), column.id).type === "list") {
      const validationBadge = document.createElement("span");
      validationBadge.className = "measurement-column-validation-badge";
      validationBadge.textContent = "List";
      validationBadge.title = "Kolona koristi Data Validation listu";
      head.append(validationBadge);
    }
    th.append(head);
    if (!column.computed) {
      th.addEventListener("pointerdown", (event) => {
        if (event.button !== 0) {
          return;
        }

        if (event.target instanceof HTMLElement
          && (event.target.closest(".measurement-column-resize")
            || event.target.closest(".measurement-column-title"))) {
          return;
        }

        event.preventDefault();
        selectMeasurementColumn(index, { extend: event.shiftKey });
        startMeasurementHeaderSelectionDrag("columns", index, event.pointerId);
      });
      th.addEventListener("contextmenu", (event) => {
        if (event.target instanceof HTMLElement
          && (event.target.closest(".measurement-column-resize")
            || event.target.closest(".measurement-column-title"))) {
          return;
        }

        event.preventDefault();
        selectMeasurementColumn(index);
        openMeasurementContextMenu({
          pointerX: event.clientX,
          pointerY: event.clientY,
          columnIndex: index,
        });
      });
    }
    headRow.append(th);
  });

  measurementSheetHead.replaceChildren(headRow);

  const bodyFragment = document.createDocumentFragment();

  state.measurementSheet.rows.forEach((row, index) => {
    const tr = document.createElement("tr");
    tr.dataset.rowId = row.id;
    tr.classList.toggle("is-measurement-empty-row", isMeasurementRowEmpty(row));
    tr.classList.toggle("is-measurement-header-row", isMeasurementHeaderRow(row.id));

    const indexCell = document.createElement("th");
    indexCell.scope = "row";
    indexCell.textContent = String(index + 1);
    indexCell.title = `Oznaci red ${index + 1}`;
    indexCell.addEventListener("pointerdown", (event) => {
      if (event.button !== 0) {
        return;
      }

      event.preventDefault();
      selectMeasurementRow(index, { extend: event.shiftKey });
      startMeasurementHeaderSelectionDrag("rows", index, event.pointerId);
    });
    indexCell.addEventListener("contextmenu", (event) => {
      event.preventDefault();
      selectMeasurementRow(index);
      openMeasurementContextMenu({
        pointerX: event.clientX,
        pointerY: event.clientY,
        rowIndex: index,
      });
    });
    tr.append(indexCell);

    state.measurementSheet.columns.forEach((column) => {
      const columnIndex = getMeasurementColumnIndex(column.id);

      if (coveredCells.has(`${index}:${columnIndex}`)) {
        return;
      }

      const td = document.createElement("td");
      td.dataset.rowId = row.id;
      td.dataset.columnId = column.id;
      const merge = mergeAnchorMap.get(`${index}:${columnIndex}`);

      if (merge) {
        td.rowSpan = merge.rowSpan;
        td.colSpan = merge.colSpan;
        td.classList.add("is-merged-cell");
      }

      if (column.computed === "average") {
        td.className = "measurement-cell-average";
        td.textContent = formatMeasurementAverage(row);
        tr.append(td);
        return;
      }

      const shell = document.createElement("div");
      shell.className = "measurement-cell-shell";

       td.addEventListener("pointerdown", (event) => {
        if (event.button !== 0) {
          return;
        }

        if (event.target instanceof HTMLElement && event.target.closest(".measurement-fill-handle")) {
          return;
        }

        event.preventDefault();
        if (maybeInsertMeasurementFormulaReference(row.id, column.id)) {
          return;
        }

       if (state.measurementSheet.editingCell
          && (state.measurementSheet.editingCell.rowId !== row.id
            || state.measurementSheet.editingCell.columnId !== column.id)) {
          commitMeasurementEditMode();
        }

        closeMeasurementFillMenu();
        closeMeasurementContextMenu();
        setMeasurementSelection(row.id, column.id, {
          extend: event.shiftKey,
        });

        if (event.shiftKey) {
          focusMeasurementCell(row.id, column.id);
          return;
        }

        startMeasurementSelectionDrag(row.id, column.id, event.pointerId);
      });
      td.addEventListener("contextmenu", (event) => {
        event.preventDefault();

        if (!column.computed) {
          setMeasurementSelection(row.id, column.id);
        }

        openMeasurementContextMenu({
          pointerX: event.clientX,
          pointerY: event.clientY,
          rowIndex: index,
          columnIndex: column.computed ? null : getMeasurementColumnIndex(column.id),
        });
      });
      td.addEventListener("dblclick", (event) => {
        event.preventDefault();
        event.stopPropagation();
        enterMeasurementEditMode(row.id, column.id, {
          selectAll: !isMeasurementFormula(row.cells?.[column.id] ?? ""),
          selectFormulaBody: isMeasurementFormula(row.cells?.[column.id] ?? ""),
        });
      });

      const input = document.createElement("input");
      input.type = "text";
      input.className = "measurement-cell-input";
      if (merge) {
        input.classList.add("is-merged-input");
      }
      input.value = getMeasurementCellInputDisplayValue(index, getMeasurementColumnIndex(column.id));
      input.placeholder = column.placeholder || column.label;
      input.dataset.rowId = row.id;
      input.dataset.columnId = column.id;
      const validationOptions = getMeasurementColumnValidationOptions(column);
      const validation = normalizeMeasurementSheetColumnValidationSnapshotLocal(
        column.validation,
        new Set(state.measurementSheet.columns.filter((entry) => !entry.computed).map((entry) => entry.id)),
        column.id,
      );
      if (validation.type === "list" && validationOptions.length > 0) {
        const dataList = document.createElement("datalist");
        const dataListId = `measurement-validation-${String(row.id || "row").replace(/[^a-z0-9_-]/gi, "-")}-${String(column.id || "column").replace(/[^a-z0-9_-]/gi, "-")}`;
        dataList.id = dataListId;
        validationOptions.forEach((optionValue) => {
          const option = document.createElement("option");
          option.value = optionValue;
          dataList.append(option);
        });
        input.setAttribute("list", dataListId);
        shell.append(dataList);
      } else {
        input.removeAttribute("list");
      }
      input.addEventListener("focus", () => {
        state.measurementSheet.editingCell = {
          rowId: row.id,
          columnId: column.id,
        };
        state.measurementSheet.editorSource = "cell";
        syncMeasurementFormulaEditState();

        if (state.measurementSheet.activeCell?.rowId === row.id
          && state.measurementSheet.activeCell?.columnId === column.id) {
          return;
        }

        setMeasurementSelection(row.id, column.id);
      });
      input.addEventListener("blur", () => {
        if (!isMeasurementValidationValueAllowed(column, input.value)) {
          input.value = "";
          setMeasurementCellRawValue(row.id, column.id, "");
        }
        if (isMeasurementEditingCell(row.id, column.id)) {
          exitMeasurementEditMode();
        }
      });
      input.addEventListener("input", (event) => {
        state.measurementSheet.editingCell = {
          rowId: row.id,
          columnId: column.id,
        };
        state.measurementSheet.editorSource = "cell";
        setMeasurementCellRawValue(row.id, column.id, event.currentTarget.value);
        syncMeasurementFormulaEditState();
        updateMeasurementEditingCellPreview(row.id, column.id);
        scheduleMeasurementSheetComputedRefresh();
      });

      const fillHandle = document.createElement("button");
      fillHandle.type = "button";
      fillHandle.className = "measurement-fill-handle";
      fillHandle.setAttribute("aria-label", `Kopiraj vrijednost prema dolje za kolonu ${column.label}`);
      fillHandle.addEventListener("pointerdown", (event) => {
      event.preventDefault();
      event.stopPropagation();
        fillHandle.setPointerCapture?.(event.pointerId);
        const currentRange = getMeasurementSelectedRange();

        if (!currentRange
          || index !== currentRange.endRowIndex
          || getMeasurementColumnIndex(column.id) !== currentRange.endColumnIndex) {
          setMeasurementSelection(row.id, column.id);
        }

        closeMeasurementFillMenu();
        const selectionRange = getMeasurementSelectedRange();

        if (!selectionRange) {
          return;
        }

        const snapshotRows = state.measurementSheet.rows
          .slice(selectionRange.startRowIndex, selectionRange.endRowIndex + 1)
          .map((sourceRow) => ({
            cells: { ...sourceRow.cells },
            formats: { ...(sourceRow.formats ?? {}) },
          }));

        state.measurementSheet.fillDrag = {
          selectionRange,
          endRowIndex: selectionRange.endRowIndex,
          snapshotRows,
          pointerX: event.clientX,
          pointerY: event.clientY,
        };
        document.body.classList.add("is-filling-measurement-cells");
        renderMeasurementFillPreview();
      });
      fillHandle.addEventListener("dblclick", (event) => {
        event.preventDefault();
        event.stopPropagation();

        const currentRange = getMeasurementSelectedRange();
        if (!currentRange) {
          setMeasurementSelection(row.id, column.id);
        }

        const selectionRange = getMeasurementSelectedRange();
        if (!selectionRange) {
          return;
        }

        const snapshotRows = state.measurementSheet.rows
          .slice(selectionRange.startRowIndex, selectionRange.endRowIndex + 1)
          .map((sourceRow) => ({
            cells: { ...sourceRow.cells },
            formats: { ...(sourceRow.formats ?? {}) },
          }));
        const lastMeaningfulRowIndex = state.measurementSheet.rows.reduce((lastIndex, candidate, candidateIndex) => (
          isMeasurementSheetRowMeaningful(candidate, state.measurementSheet.columns)
            ? candidateIndex
            : lastIndex
        ), -1);
        const targetEndRowIndex = Math.max(
          selectionRange.endRowIndex,
          lastMeaningfulRowIndex > selectionRange.endRowIndex ? lastMeaningfulRowIndex : Math.min(state.measurementSheet.rows.length - 1, selectionRange.endRowIndex + 12),
        );

        if (targetEndRowIndex <= selectionRange.endRowIndex) {
          return;
        }

        applyMeasurementFill("series", {
          pendingFill: {
            selectionRange,
            endRowIndex: targetEndRowIndex,
            snapshotRows,
          },
        });
      });

      shell.append(input, fillHandle);
      td.append(shell);
      td.classList.toggle("has-formula-cell", isMeasurementFormula(row.cells?.[column.id] ?? ""));
      tr.append(td);
    });

    bodyFragment.append(tr);
  });

  measurementSheetBody.replaceChildren(bodyFragment);
  refreshMeasurementSheetComputedValues();
  renderMeasurementSelection();
  renderMeasurementActiveCell();
  renderMeasurementFillPreview();
  renderMeasurementFillMenu();
  renderMeasurementContextMenu();
}

function extendMeasurementSheetRowsIfNeeded() {
  if (!measurementSheetGridWrap || !state.measurementSheet.isOpen) {
    return;
  }

  const nearBottom = measurementSheetGridWrap.scrollTop + measurementSheetGridWrap.clientHeight
    >= measurementSheetGridWrap.scrollHeight - 420;

  if (!nearBottom) {
    return;
  }

  const previousScrollTop = measurementSheetGridWrap.scrollTop;
  const previousScrollLeft = measurementSheetGridWrap.scrollLeft;
  appendMeasurementRows();
  renderMeasurementSheet();
  measurementSheetGridWrap.scrollTop = previousScrollTop;
  measurementSheetGridWrap.scrollLeft = previousScrollLeft;
}

function setMeasurementSheetOpen(isOpen) {
  state.measurementSheet.isOpen = Boolean(isOpen);
  const inlineTemplateSheet = state.measurementSheet.isOpen && state.measurementSheet.ownerKind === "template_field";
  document.body.classList.toggle("measurement-sheet-open", state.measurementSheet.isOpen && !inlineTemplateSheet);
  syncMeasurementSheetPanelMount();

  if (!state.measurementSheet.isOpen) {
    document.body.classList.remove("is-filling-measurement-cells");
    clearMeasurementFillPreview();
    renderMeasurementFillMenu();
    renderMeasurementContextMenu();
    state.measurementSheet.validationPopoverOpen = false;
  }

  renderMeasurementSheetPresetLibrary();
}

function openMeasurementSheet() {
  state.measurementSheet.ownerKind = "work_order";
  state.measurementSheet.ownerFieldId = "";
  state.measurementSheet.ownerRuntimeWorkOrderId = "";
  syncMeasurementSheetHeaderFromWorkOrder();
  renderMeasurementSheet();
  if (!state.measurementSheet.activeCell) {
    const firstColumnIndex = getFirstEditableMeasurementColumnIndex();

    if (firstColumnIndex >= 0 && state.measurementSheet.rows[0]) {
      setMeasurementSelectionByIndex(0, firstColumnIndex);
    }
  }
  setMeasurementSheetOpen(true);
  syncMeasurementToolbar();
}

function closeMeasurementSheet() {
  if (state.measurementSheet.editingCell) {
    commitMeasurementEditMode();
  }

  if (state.measurementSheet.ownerKind === "template_field") {
    persistMeasurementSheetToTemplateField({ rerenderFieldRows: true });
  } else if (state.measurementSheet.ownerKind === "document_template_runtime_field") {
    persistMeasurementSheetToDocumentTemplateRuntimeField({ rerenderFieldRows: true });
  }

  clearScheduledMeasurementSheetRefresh();
  stopMeasurementFillAutoScroll();
  state.measurementSheet.selectionDrag = null;
  state.measurementSheet.fillMenu = null;
  state.measurementSheet.fillDrag = null;
  state.measurementSheet.contextMenu = null;
  state.measurementSheet.editingCell = null;
  state.measurementSheet.editorSource = null;
  state.measurementSheet.formulaReferences = [];
  state.measurementSheet.validationPopoverOpen = false;
  document.body.classList.remove("is-selecting-measurement-cells");
  document.body.classList.remove("is-filling-measurement-cells");
  setMeasurementSheetOpen(false);
  syncMeasurementToolbar();
  if (state.measurementSheet.ownerKind === "work_order" && state.workOrderAutoSave.dirty) {
    void persistWorkOrderAutoSave({ immediate: true });
  }
  state.measurementSheet.ownerKind = "work_order";
  state.measurementSheet.ownerFieldId = "";
  state.measurementSheet.ownerRuntimeWorkOrderId = "";
  state.measurementSheet.presetLibrary = {
    scopeKey: "",
    status: "idle",
    items: [],
    error: "",
    message: "",
  };
}

function resetMeasurementSheet() {
  clearScheduledMeasurementSheetRefresh();
  stopMeasurementFillAutoScroll();
  state.measurementSheet.columns = buildDefaultMeasurementColumns();
  state.measurementSheet.rows = buildDefaultMeasurementRows();
  state.measurementSheet.merges = [];
  state.measurementSheet.headerRows = [];
  state.measurementSheet.resizing = null;
  state.measurementSheet.activeCell = null;
  state.measurementSheet.editingCell = null;
  state.measurementSheet.editorSource = null;
  state.measurementSheet.selectionAnchor = null;
  state.measurementSheet.selectedRange = null;
  state.measurementSheet.selectionDrag = null;
  state.measurementSheet.fillDrag = null;
  state.measurementSheet.fillMenu = null;
  state.measurementSheet.contextMenu = null;
  state.measurementSheet.validationPopoverOpen = false;
  syncMeasurementSheetHeaderFromWorkOrder();
  renderMeasurementSheet();
  syncMeasurementToolbar();
  handleMeasurementSheetMutation();
}

function addMeasurementColumn() {
  ensureMeasurementSheetStructure();
  appendMeasurementEditableColumn();
  renderMeasurementSheet();
  handleMeasurementSheetMutation();
}

function expandMeasurementMergesForInsertedRow(insertionIndex) {
  getMeasurementMergeDescriptors().forEach((merge) => {
    if (insertionIndex > merge.anchorRowIndex && insertionIndex <= merge.endRowIndex) {
      const target = (state.measurementSheet.merges ?? []).find((item) => (
        item.rowId === merge.rowId && item.columnId === merge.columnId
      ));

      if (target) {
        target.rowSpan += 1;
      }
    }
  });
}

function expandMeasurementMergesForInsertedColumn(insertionIndex) {
  getMeasurementMergeDescriptors().forEach((merge) => {
    if (insertionIndex > merge.anchorColumnIndex && insertionIndex <= merge.endColumnIndex) {
      const target = (state.measurementSheet.merges ?? []).find((item) => (
        item.rowId === merge.rowId && item.columnId === merge.columnId
      ));

      if (target) {
        target.colSpan += 1;
      }
    }
  });
}

function insertMeasurementRowAt(index) {
  ensureMeasurementSheetStructure();
  const insertionIndex = Math.max(0, Math.min(index, state.measurementSheet.rows.length));
  const activeColumnIndex = getMeasurementActiveCellPosition()?.columnIndex ?? getFirstEditableMeasurementColumnIndex();
  const scrollTop = measurementSheetGridWrap?.scrollTop ?? 0;
  const scrollLeft = measurementSheetGridWrap?.scrollLeft ?? 0;

  state.measurementSheet.rows.splice(insertionIndex, 0, createMeasurementRow());
  expandMeasurementMergesForInsertedRow(insertionIndex);
  renderMeasurementSheet();

  if (measurementSheetGridWrap) {
    measurementSheetGridWrap.scrollTop = scrollTop;
    measurementSheetGridWrap.scrollLeft = scrollLeft;
  }

  if (activeColumnIndex >= 0 && !state.measurementSheet.columns[activeColumnIndex]?.computed) {
    setMeasurementSelectionByIndex(insertionIndex, activeColumnIndex, { focus: true });
  }

  closeMeasurementContextMenu();
  handleMeasurementSheetMutation();
}

function insertMeasurementColumnAt(index) {
  ensureMeasurementSheetStructure();
  const insertionIndex = Math.max(0, Math.min(index, state.measurementSheet.columns.length));
  const activeRowIndex = getMeasurementActiveCellPosition()?.rowIndex ?? 0;
  const scrollTop = measurementSheetGridWrap?.scrollTop ?? 0;
  const scrollLeft = measurementSheetGridWrap?.scrollLeft ?? 0;
  const nextColumnIndex = insertMeasurementEditableColumnAt(insertionIndex);
  expandMeasurementMergesForInsertedColumn(insertionIndex);

  renderMeasurementSheet();

  if (measurementSheetGridWrap) {
    measurementSheetGridWrap.scrollTop = scrollTop;
    measurementSheetGridWrap.scrollLeft = scrollLeft;
  }

  if (nextColumnIndex >= 0 && state.measurementSheet.rows[activeRowIndex]) {
    setMeasurementSelectionByIndex(activeRowIndex, nextColumnIndex, { focus: true });
  }

  closeMeasurementContextMenu();
  handleMeasurementSheetMutation();
}

function insertMeasurementContextRow(position) {
  const contextMenuState = state.measurementSheet.contextMenu;

  if (!contextMenuState || !Number.isInteger(contextMenuState.rowIndex)) {
    return;
  }

  insertMeasurementRowAt(position === "above" ? contextMenuState.rowIndex : contextMenuState.rowIndex + 1);
}

function insertMeasurementContextColumn(position) {
  const contextMenuState = state.measurementSheet.contextMenu;

  if (!contextMenuState || !Number.isInteger(contextMenuState.columnIndex)) {
    return;
  }

  insertMeasurementColumnAt(position === "left"
    ? contextMenuState.columnIndex
    : contextMenuState.columnIndex + 1);
}

function deleteMeasurementRowAt(index) {
  ensureMeasurementSheetStructure();

  if (!Number.isInteger(index) || state.measurementSheet.rows.length <= 1) {
    return;
  }

  const targetRow = state.measurementSheet.rows[index];
  if (!targetRow) {
    return;
  }

  state.measurementSheet.rows.splice(index, 1);
  state.measurementSheet.headerRows = state.measurementSheet.headerRows.filter((rowId) => rowId !== targetRow.id);
  state.measurementSheet.merges = getMeasurementMergeDescriptors()
    .filter((merge) => index < merge.anchorRowIndex || index > merge.endRowIndex)
    .map((merge) => ({
      rowId: merge.rowId,
      columnId: merge.columnId,
      rowSpan: merge.rowSpan,
      colSpan: merge.colSpan,
    }));

  renderMeasurementSheet();
  const nextRowIndex = Math.max(0, Math.min(index, state.measurementSheet.rows.length - 1));
  const nextColumnIndex = getFirstEditableMeasurementColumnIndex();
  if (nextColumnIndex >= 0 && state.measurementSheet.rows[nextRowIndex]) {
    setMeasurementSelectionByIndex(nextRowIndex, nextColumnIndex, { focus: true });
  }
  closeMeasurementContextMenu();
  handleMeasurementSheetMutation();
}

function deleteMeasurementColumnAt(index) {
  ensureMeasurementSheetStructure();
  const targetColumn = state.measurementSheet.columns[index];

  if (!targetColumn || targetColumn.computed) {
    return;
  }

  const editableColumns = getEditableMeasurementColumnIndexes();
  if (editableColumns.length <= 1) {
    return;
  }

  state.measurementSheet.columns.splice(index, 1);
  state.measurementSheet.rows.forEach((row) => {
    if (row?.cells) {
      delete row.cells[targetColumn.id];
    }
    if (row?.formats) {
      delete row.formats[targetColumn.id];
    }
  });
  state.measurementSheet.merges = getMeasurementMergeDescriptors()
    .filter((merge) => index < merge.anchorColumnIndex || index > merge.endColumnIndex)
    .map((merge) => ({
      rowId: merge.rowId,
      columnId: merge.columnId,
      rowSpan: merge.rowSpan,
      colSpan: merge.colSpan,
    }));

  renderMeasurementSheet();
  const nextEditableIndexes = getEditableMeasurementColumnIndexes();
  const nextColumnIndex = nextEditableIndexes.find((columnIndex) => columnIndex >= index)
    ?? nextEditableIndexes[nextEditableIndexes.length - 1]
    ?? -1;
  const activeRowIndex = Math.max(0, getMeasurementActiveCellPosition()?.rowIndex ?? 0);
  if (nextColumnIndex >= 0 && state.measurementSheet.rows[activeRowIndex]) {
    setMeasurementSelectionByIndex(activeRowIndex, nextColumnIndex, { focus: true });
  }
  closeMeasurementContextMenu();
  handleMeasurementSheetMutation();
}

function deleteMeasurementContextRow() {
  const contextMenuState = state.measurementSheet.contextMenu;

  if (!contextMenuState || !Number.isInteger(contextMenuState.rowIndex)) {
    return;
  }

  deleteMeasurementRowAt(contextMenuState.rowIndex);
}

function deleteMeasurementContextColumn() {
  const contextMenuState = state.measurementSheet.contextMenu;

  if (!contextMenuState || !Number.isInteger(contextMenuState.columnIndex)) {
    return;
  }

  deleteMeasurementColumnAt(contextMenuState.columnIndex);
}

function getEditableMeasurementColumnsInRange(range) {
  return state.measurementSheet.columns
    .slice(range.startColumnIndex, range.endColumnIndex + 1)
    .filter((column) => !column.computed);
}

function formatMeasurementSeriesValue(value) {
  if (!Number.isFinite(value)) {
    return "";
  }

  if (Number.isInteger(value)) {
    return String(value);
  }

  return String(Number(value.toFixed(2))).replace(".", ",");
}

function applyMeasurementFill(mode, options = {}) {
  const {
    pendingFill = state.measurementSheet.fillMenu?.pendingFill,
    showMenuAfter = false,
    menuX = 0,
    menuY = 0,
  } = options;

  if (!pendingFill) {
    return;
  }

  const { selectionRange, endRowIndex, snapshotRows } = pendingFill;
  const targetColumns = getEditableMeasurementColumnsInRange(selectionRange);
  const selectionHeight = selectionRange.endRowIndex - selectionRange.startRowIndex + 1;

  targetColumns.forEach((column) => {
    const snapshotValues = snapshotRows.map((row) => row.cells?.[column.id] ?? "");
    const snapshotFormats = snapshotRows.map((row) => normalizeMeasurementCellFormat(row.formats?.[column.id]));
    const numericValues = snapshotValues.map(parseMeasurementNumber);
    const canSeries = mode === "series" && numericValues.every((value) => value !== null);

    if (canSeries) {
      let currentValue = numericValues[numericValues.length - 1];
      const step = numericValues.length >= 2
        ? numericValues[numericValues.length - 1] - numericValues[numericValues.length - 2]
        : 1;

      for (let rowIndex = selectionRange.endRowIndex + 1; rowIndex <= endRowIndex; rowIndex += 1) {
        currentValue += step;
        const row = state.measurementSheet.rows[rowIndex];

        if (row?.cells) {
          row.cells[column.id] = formatMeasurementSeriesValue(currentValue);
          row.formats = row.formats ?? {};
          row.formats[column.id] = { ...snapshotFormats[(rowIndex - (selectionRange.endRowIndex + 1)) % selectionHeight] };
        }
      }

      return;
    }

    for (let rowIndex = selectionRange.endRowIndex + 1; rowIndex <= endRowIndex; rowIndex += 1) {
      const sourceOffset = (rowIndex - (selectionRange.endRowIndex + 1)) % selectionHeight;
      const row = state.measurementSheet.rows[rowIndex];
      const sourceRowIndex = selectionRange.startRowIndex + sourceOffset;

      if (row?.cells) {
        row.cells[column.id] = shiftMeasurementFillValue(
          snapshotValues[sourceOffset] ?? "",
          rowIndex - sourceRowIndex,
          0,
        );
        row.formats = row.formats ?? {};
        row.formats[column.id] = { ...snapshotFormats[sourceOffset] };
      }
    }
  });

  state.measurementSheet.selectedRange = createMeasurementSelectionRange(
    selectionRange.startRowIndex,
    selectionRange.startColumnIndex,
    endRowIndex,
    selectionRange.endColumnIndex,
  );
  state.measurementSheet.activeCell = {
    rowId: state.measurementSheet.rows[endRowIndex]?.id ?? state.measurementSheet.rows[selectionRange.endRowIndex]?.id,
    columnId: state.measurementSheet.columns[selectionRange.endColumnIndex]?.id,
  };
  state.measurementSheet.selectionAnchor = {
    rowIndex: selectionRange.startRowIndex,
    columnIndex: selectionRange.startColumnIndex,
  };
  state.measurementSheet.fillMenu = null;
  renderMeasurementSheet();
  handleMeasurementSheetMutation();

  if (showMenuAfter) {
    openMeasurementFillMenu(pendingFill, menuX, menuY);
  }
}

function updateMeasurementColumnWidth(pointerX) {
  const resizeState = state.measurementSheet.resizing;

  if (!resizeState) {
    return;
  }

  const column = state.measurementSheet.columns.find((item) => item.id === resizeState.columnId);

  if (!column) {
    return;
  }

  column.width = Math.max(90, resizeState.startWidth + (pointerX - resizeState.startX));
  renderMeasurementSheet();
}

function stopMeasurementColumnResize() {
  if (!state.measurementSheet.resizing) {
    return;
  }

  state.measurementSheet.resizing = null;
  document.body.classList.remove("is-resizing-measurement-column");
  handleMeasurementSheetMutation();
}

function getMeasurementFillAutoScrollDelta(pointerX, pointerY) {
  if (!(measurementSheetGridWrap instanceof HTMLElement)) {
    return { x: 0, y: 0 };
  }

  const rect = measurementSheetGridWrap.getBoundingClientRect();
  const verticalThreshold = 72;
  const horizontalThreshold = 44;
  let deltaX = 0;
  let deltaY = 0;

  if (pointerY > rect.bottom - verticalThreshold) {
    deltaY = Math.max(20, Math.ceil((pointerY - (rect.bottom - verticalThreshold)) / 4));
  } else if (pointerY < rect.top + verticalThreshold) {
    deltaY = -Math.max(20, Math.ceil(((rect.top + verticalThreshold) - pointerY) / 4));
  }

  if (pointerX > rect.right - horizontalThreshold) {
    deltaX = Math.max(16, Math.ceil((pointerX - (rect.right - horizontalThreshold)) / 5));
  } else if (pointerX < rect.left + horizontalThreshold) {
    deltaX = -Math.max(16, Math.ceil(((rect.left + horizontalThreshold) - pointerX) / 5));
  }

  return { x: deltaX, y: deltaY };
}

function applyMeasurementFillAutoScroll(pointerX, pointerY) {
  if (!(measurementSheetGridWrap instanceof HTMLElement)) {
    return false;
  }

  const { x, y } = getMeasurementFillAutoScrollDelta(pointerX, pointerY);
  if (!x && !y) {
    return false;
  }

  const previousTop = measurementSheetGridWrap.scrollTop;
  const previousLeft = measurementSheetGridWrap.scrollLeft;
  measurementSheetGridWrap.scrollTop = Math.max(0, previousTop + y);
  measurementSheetGridWrap.scrollLeft = Math.max(0, previousLeft + x);
  extendMeasurementSheetRowsIfNeeded();
  return previousTop !== measurementSheetGridWrap.scrollTop || previousLeft !== measurementSheetGridWrap.scrollLeft;
}

function stopMeasurementFillAutoScroll() {
  if (state.measurementSheet.fillAutoScrollFrame) {
    window.cancelAnimationFrame(state.measurementSheet.fillAutoScrollFrame);
    state.measurementSheet.fillAutoScrollFrame = 0;
  }
}

function scheduleMeasurementFillAutoScroll() {
  if (state.measurementSheet.fillAutoScrollFrame || !state.measurementSheet.fillDrag) {
    return;
  }

  state.measurementSheet.fillAutoScrollFrame = window.requestAnimationFrame(() => {
    state.measurementSheet.fillAutoScrollFrame = 0;

    const fillDrag = state.measurementSheet.fillDrag;
    if (!fillDrag) {
      return;
    }

    const pointerX = fillDrag.pointerX ?? 0;
    const pointerY = fillDrag.pointerY ?? 0;
    const scrolled = applyMeasurementFillAutoScroll(pointerX, pointerY);
    updateMeasurementFillTarget(pointerX, pointerY, { skipAutoScroll: true });

    if (scrolled) {
      scheduleMeasurementFillAutoScroll();
    }
  });
}

function updateMeasurementFillTarget(pointerX, pointerY, options = {}) {
  const {
    skipAutoScroll = false,
  } = options;
  const fillDrag = state.measurementSheet.fillDrag;

  if (!fillDrag) {
    return;
  }

  fillDrag.pointerX = pointerX;
  fillDrag.pointerY = pointerY;

  if (!skipAutoScroll) {
    if (applyMeasurementFillAutoScroll(pointerX, pointerY)) {
      scheduleMeasurementFillAutoScroll();
    } else {
      stopMeasurementFillAutoScroll();
    }
  }

  const hoveredColumnIndex = resolveMeasurementPointerColumnIndex(pointerX, pointerY);
  if (hoveredColumnIndex >= 0
    && (hoveredColumnIndex < fillDrag.selectionRange.startColumnIndex
      || hoveredColumnIndex > fillDrag.selectionRange.endColumnIndex)) {
    fillDrag.endRowIndex = fillDrag.selectionRange.endRowIndex;
    renderMeasurementFillPreview();
    return;
  }

  const hoveredRowIndex = resolveMeasurementPointerRowIndex(pointerX, pointerY);
  if (hoveredRowIndex < 0) {
    fillDrag.endRowIndex = fillDrag.selectionRange.endRowIndex;
    renderMeasurementFillPreview();
    return;
  }

  fillDrag.endRowIndex = hoveredRowIndex >= fillDrag.selectionRange.endRowIndex
    ? hoveredRowIndex
    : fillDrag.selectionRange.endRowIndex;
  renderMeasurementFillPreview();
}

function stopMeasurementFillDrag(applyFill = true, pointerX = 0, pointerY = 0) {
  const fillDrag = state.measurementSheet.fillDrag;

  if (!fillDrag) {
    return;
  }

  state.measurementSheet.fillDrag = null;
  stopMeasurementFillAutoScroll();
  document.body.classList.remove("is-filling-measurement-cells");

  if (applyFill && fillDrag.endRowIndex > fillDrag.selectionRange.endRowIndex) {
    applyMeasurementFill("copy", {
      pendingFill: fillDrag,
      showMenuAfter: true,
      menuX: pointerX,
      menuY: pointerY,
    });
    return;
  }

  closeMeasurementFillMenu();
  renderMeasurementFillPreview();
}

function createCell(text) {
  const cell = document.createElement("td");
  cell.textContent = text;
  return cell;
}

function createActionButton(label, className, onClick) {
  const button = document.createElement("button");
  button.type = "button";
  button.className = className;
  button.textContent = label;
  button.setAttribute("aria-label", label);
  button.title = label;
  button.addEventListener("click", onClick);
  return button;
}

function createListLine(text, className) {
  const line = document.createElement("div");
  line.className = className;
  line.textContent = text;
  return line;
}

function createMetaPill(text, className = "") {
  const pill = document.createElement("span");
  pill.className = ["list-meta-pill", className].filter(Boolean).join(" ");
  pill.textContent = text;
  return pill;
}

function createStatusPill(text, isActive = true) {
  return createMetaPill(text, isActive ? "is-success" : "is-muted");
}

function createStackCell({
  eyebrow = "",
  title = "",
  subtitle = "",
  tertiary = "",
  meta = [],
  className = "",
} = {}) {
  const cell = document.createElement("td");
  if (className) {
    cell.className = className;
  }

  const stack = document.createElement("div");
  stack.className = "list-cell";

  if (eyebrow) {
    stack.append(createListLine(eyebrow, "list-eyebrow"));
  }

  if (title) {
    stack.append(createListLine(title, "list-primary"));
  }

  if (subtitle) {
    stack.append(createListLine(subtitle, "list-secondary"));
  }

  if (tertiary) {
    stack.append(createListLine(tertiary, "list-tertiary"));
  }

  const metaItems = meta.filter(Boolean);

  if (metaItems.length > 0) {
    const metaRow = document.createElement("div");
    metaRow.className = "list-meta-row";

    for (const item of metaItems) {
      if (typeof Node !== "undefined" && item instanceof Node) {
        metaRow.append(item);
      } else if (typeof item === "string") {
        metaRow.append(createMetaPill(item));
      } else {
        metaRow.append(createMetaPill(item.label, item.className));
      }
    }

    stack.append(metaRow);
  }

  cell.append(stack);
  return cell;
}

function createCompanyIdentityCell(company) {
  const cell = document.createElement("td");
  const stack = document.createElement("div");
  stack.className = "company-list-cell";

  const logo = document.createElement("span");
  logo.className = "company-list-logo";
  renderCompanyLogo(logo, company);

  const copy = document.createElement("div");
  copy.className = "company-list-copy";
  copy.append(
    createListLine(company.name || "Tvrtka", "list-primary"),
    createListLine(company.headquarters || "Bez sjedišta", "list-secondary"),
    createListLine(company.oib ? `OIB ${company.oib}` : "Bez OIB-a", "list-tertiary"),
  );

  stack.append(logo, copy);
  cell.append(stack);
  return cell;
}

function createUserIdentityCell(user) {
  const cell = document.createElement("td");
  const stack = document.createElement("div");
  stack.className = "people-list-cell";

  const avatar = document.createElement("span");
  avatar.className = "people-list-avatar";
  renderAvatar(avatar, user);

  const copy = document.createElement("div");
  copy.className = "people-list-copy";
  copy.append(
    createListLine(user.fullName || user.email || "User", "list-primary"),
    createListLine(user.legacyUsername ? `Legacy: ${user.legacyUsername}` : "Web account", "list-secondary"),
    createListLine((user.organizations ?? []).map((organization) => organization.name).join(", ") || "Bez organizacije", "list-tertiary"),
  );

  stack.append(avatar, copy);
  cell.append(stack);
  return cell;
}

function createUserElectricalCell(user) {
  const panicQualification = getUserElectricalQualification(user, "elektro");
  const switchQualification = getUserElectricalQualification(user, "tipkalo");
  const statusMeta = [];
  const summarizeQualification = (qualification, label) => {
    const detail = [
      qualification.classCode ? `Klasa ${qualification.classCode}` : "",
      qualification.urbroj ? `UrBROJ ${qualification.urbroj}` : "",
      qualification.eBroj ? `E ${qualification.eBroj}` : "",
    ].filter(Boolean).join(" | ");

    return detail ? `${label}: ${detail}` : `${label}: nema podataka`;
  };

  if (panicQualification.canInspect) {
    statusMeta.push({ label: "Panik ispitivač", className: "is-success" });
  }
  if (panicQualification.canAuthorize) {
    statusMeta.push({ label: "Panik nositelj", className: "is-accent" });
  }
  if (switchQualification.canInspect) {
    statusMeta.push({ label: "Tipkalo ispitivač", className: "is-success" });
  }
  if (switchQualification.canAuthorize) {
    statusMeta.push({ label: "Tipkalo nositelj", className: "is-accent" });
  }

  return createStackCell({
    title: statusMeta.length > 0 ? "Aktivna ovlaštenja" : "Bez ovlaštenja",
    subtitle: summarizeQualification(panicQualification, "Panik"),
    tertiary: summarizeQualification(switchQualification, "Tipkalo"),
    meta: statusMeta,
  });
}

function createBadgeCell(badge, subtitle = "", tertiary = "") {
  const cell = document.createElement("td");
  const stack = document.createElement("div");
  stack.className = "list-cell list-cell-tight";
  stack.append(badge);

  if (subtitle) {
    stack.append(createListLine(subtitle, "list-secondary"));
  }

  if (tertiary) {
    stack.append(createListLine(tertiary, "list-tertiary"));
  }

  cell.append(stack);
  return cell;
}

function createBadge(text, className = "") {
  const badge = document.createElement("span");
  badge.className = ["badge", className].filter(Boolean).join(" ");
  badge.textContent = text;
  return badge;
}

function joinParts(values, separator = " | ") {
  return values.filter(Boolean).join(separator);
}

function isClosedWorkOrder(status) {
  return ["Gotov RN", "Ovjeren RN", "Fakturiran RN", "Storno RN"].includes(String(status ?? ""));
}

function isOverdueWorkOrder(item) {
  if (!item?.dueDate || isClosedWorkOrder(item.status)) {
    return false;
  }

  return item.dueDate < new Date().toISOString().slice(0, 10);
}

function getOptionLabel(options, value) {
  return options.find((option) => option.value === value)?.label ?? value;
}

function resetWorkOrderActivityState() {
  state.workOrderActivity = {
    workOrderId: "",
    loading: false,
    items: [],
    error: "",
  };
  renderWorkOrderActivity();
}

function renderWorkOrderActivity() {
  if (!workOrderActivityList || !workOrderActivityEmpty || !workOrderActivityLoading || !workOrderActivityError || !workOrderActivityCount) {
    return;
  }

  const { workOrderId, loading, items, error } = state.workOrderActivity;
  workOrderActivityCount.textContent = String(items.length);
  workOrderActivityLoading.hidden = !loading;
  workOrderActivityError.hidden = !error;
  workOrderActivityError.textContent = error;
  workOrderActivityList.replaceChildren();

  const emptyMessage = !workOrderId
    ? "Otvori radni nalog da vidi? promjene i status timeline."
    : "Još nema zabilježenih promjena za ovaj RN.";
  workOrderActivityEmpty.textContent = emptyMessage;
  workOrderActivityEmpty.hidden = loading || Boolean(error) || items.length > 0;

  items.forEach((entry) => {
    const item = document.createElement("article");
    item.className = "work-order-activity-item";

    const avatar = document.createElement("span");
    avatar.className = "work-order-activity-avatar";
    avatar.textContent = getUserInitials({ fullName: entry.actorLabel });

    const body = document.createElement("div");
    body.className = "work-order-activity-item-body";

    const top = document.createElement("div");
    top.className = "work-order-activity-item-top";

    const description = document.createElement("strong");
    description.className = "work-order-activity-description";
    description.textContent = entry.description || "Ažuriranje radnog naloga";

    const time = document.createElement("span");
    time.className = "work-order-activity-time";
    time.textContent = formatDateTime(entry.createdAt);

    top.append(description, time);

    const meta = document.createElement("div");
    meta.className = "work-order-activity-meta";

    const actor = document.createElement("span");
    actor.className = "work-order-activity-actor";
    actor.textContent = entry.actorLabel || "Safety360";
    meta.append(actor);

    if (entry.fieldLabel) {
      const field = document.createElement("span");
      field.className = "work-order-activity-field";
      field.textContent = entry.fieldLabel;
      meta.append(field);
    }

    if (entry.oldValue || entry.newValue) {
      const diff = document.createElement("div");
      diff.className = "work-order-activity-diff";
      const hasOldValue = Boolean(entry.oldValue);
      const hasNewValue = Boolean(entry.newValue);

      if (hasOldValue) {
        const previous = document.createElement("span");
        previous.className = "work-order-activity-old";
        previous.textContent = entry.oldValue;
        diff.append(previous);
      }

      if (hasOldValue && hasNewValue) {
        const arrow = document.createElement("span");
        arrow.className = "work-order-activity-arrow";
        arrow.textContent = "->";
        diff.append(arrow);
      }

      if (hasNewValue) {
        const next = document.createElement("span");
        next.className = "work-order-activity-new";
        next.textContent = entry.newValue;
        diff.append(next);
      }

      body.append(top, meta, diff);
    } else {
      body.append(top, meta);
    }

    item.append(avatar, body);
    workOrderActivityList.append(item);
  });
}

async function loadWorkOrderActivity(workOrderId) {
  if (!workOrderId) {
    resetWorkOrderActivityState();
    return;
  }

  state.workOrderActivity = {
    workOrderId: String(workOrderId),
    loading: true,
    items: [],
    error: "",
  };
  renderWorkOrderActivity();

  try {
    const payload = await apiRequest(`/work-orders/${workOrderId}/activity`);

    if (state.workOrderActivity.workOrderId !== String(workOrderId)) {
      return;
    }

    state.workOrderActivity = {
      workOrderId: String(workOrderId),
      loading: false,
      items: payload.items ?? [],
      error: "",
    };
  } catch (error) {
    if (state.workOrderActivity.workOrderId !== String(workOrderId)) {
      return;
    }

    state.workOrderActivity = {
      workOrderId: String(workOrderId),
      loading: false,
      items: [],
      error: error.message,
    };
  }

  renderWorkOrderActivity();
}

function resetWorkOrderDocumentsState() {
  state.workOrderDocuments = {
    workOrderId: "",
    loading: false,
    uploading: false,
    busyId: "",
    items: [],
    error: "",
  };
  renderWorkOrderDocuments();
}

function getWorkOrderDocumentExtension(fileName = "", fileType = "") {
  const normalizedName = String(fileName ?? "").trim();

  if (normalizedName.includes(".")) {
    return normalizedName.split(".").pop().toUpperCase();
  }

  const normalizedType = String(fileType ?? "").trim().toUpperCase();
  return normalizedType.includes("/") ? normalizedType.split("/").pop() : (normalizedType || "FILE");
}

function getWorkOrderDocumentSourceLabel(sourceType = "editor") {
  return sourceType === "activity" ? "Activity" : "Otvaranje";
}

function formatFileSize(value) {
  const size = Number(value);

  if (!Number.isFinite(size) || size <= 0) {
    return "0 KB";
  }

  if (size >= 1024 * 1024) {
    return `${(size / (1024 * 1024)).toFixed(size >= 10 * 1024 * 1024 ? 0 : 1)} MB`;
  }

  return `${Math.max(1, Math.round(size / 1024))} KB`;
}

function createWorkOrderDocumentCard(item, { compact = false } = {}) {
  const card = document.createElement("article");
  card.className = compact ? "work-order-document-card is-compact" : "work-order-document-card";
  const isBusy = state.workOrderDocuments.busyId === String(item.id);

  const badge = document.createElement("span");
  badge.className = "work-order-document-badge";
  badge.textContent = getWorkOrderDocumentExtension(item.fileName, item.fileType);

  const body = document.createElement("div");
  body.className = "work-order-document-card-body";

  const nameInput = document.createElement("input");
  nameInput.className = "work-order-document-name-input";
  nameInput.type = "text";
  nameInput.value = item.fileName || "";
  nameInput.placeholder = "Naziv dokumenta";
  nameInput.disabled = isBusy;

  const descriptionInput = document.createElement("textarea");
  descriptionInput.className = "work-order-document-description-input";
  descriptionInput.rows = compact ? 2 : 3;
  descriptionInput.value = item.description || "";
  descriptionInput.placeholder = "Opis dokumenta";
  descriptionInput.disabled = isBusy;

  const meta = document.createElement("span");
  meta.className = "work-order-document-meta";
  meta.textContent = [
    formatFileSize(item.fileSize),
    getWorkOrderDocumentSourceLabel(item.sourceType),
    formatDateTime(item.createdAt),
  ].filter(Boolean).join(" · ");

  body.append(nameInput, descriptionInput, meta);

  const actions = document.createElement("div");
  actions.className = "work-order-document-actions";

  const saveButton = document.createElement("button");
  saveButton.type = "button";
  saveButton.className = "ghost-button work-order-document-button";
  saveButton.textContent = isBusy ? "Spremam..." : "Spremi";
  saveButton.disabled = isBusy;
  saveButton.addEventListener("click", () => {
    void saveWorkOrderDocument(item.id, {
      fileName: nameInput.value,
      description: descriptionInput.value,
    });
  });

  const link = document.createElement("a");
  link.className = "ghost-button work-order-document-link";
  link.href = item.dataUrl || "#";
  link.target = "_blank";
  link.rel = "noreferrer";
  link.download = item.fileName || "dokument";
  link.textContent = "Otvori";
  link.setAttribute("aria-disabled", String(isBusy));

  const deleteButton = document.createElement("button");
  deleteButton.type = "button";
  deleteButton.className = "ghost-button work-order-document-button is-danger";
  deleteButton.textContent = isBusy ? "..." : "Makni";
  deleteButton.disabled = isBusy;
  deleteButton.addEventListener("click", () => {
    void deleteWorkOrderDocument(item.id, item.fileName);
  });

  actions.append(saveButton, link, deleteButton);

  card.append(badge, body, actions);
  return card;
}

function syncWorkOrderDocumentDropzone(dropzone, uploading, defaultTitle, defaultSubtitle) {
  if (!dropzone) {
    return;
  }

  dropzone.disabled = uploading;
  dropzone.dataset.uploading = uploading ? "true" : "false";
  const title = dropzone.querySelector(".work-order-document-dropzone-copy strong");
  const subtitle = dropzone.querySelector(".work-order-document-dropzone-copy span");

  if (title) {
    title.textContent = uploading ? "Upload u tijeku..." : defaultTitle;
  }

  if (subtitle) {
    subtitle.textContent = uploading ? "Datoteke se upravo spremaju na RN." : defaultSubtitle;
  }
}

function renderWorkOrderDocuments() {
  const {
    workOrderId,
    loading,
    uploading,
    items,
    error,
  } = state.workOrderDocuments;

  if (
    !workOrderDocumentList
    || !workOrderDocumentEmpty
    || !workOrderDocumentLoading
    || !workOrderDocumentError
    || !workOrderActivityDocumentList
    || !workOrderActivityDocumentEmpty
    || !workOrderActivityDocumentLoading
    || !workOrderActivityDocumentError
  ) {
    return;
  }

  if (workOrderDocumentCount) {
    workOrderDocumentCount.textContent = String(items.length);
  }

  if (workOrderActivityDocumentCount) {
    workOrderActivityDocumentCount.textContent = String(items.length);
  }

  workOrderDocumentLoading.hidden = !loading;
  workOrderActivityDocumentLoading.hidden = !loading;
  workOrderDocumentError.hidden = !error;
  workOrderActivityDocumentError.hidden = !error;
  workOrderDocumentError.textContent = error;
  workOrderActivityDocumentError.textContent = error;
  workOrderDocumentList.replaceChildren();
  workOrderActivityDocumentList.replaceChildren();

  syncWorkOrderDocumentDropzone(
    workOrderDocumentDropzone,
    uploading,
    "Dodaj dokumente u RN",
    "Povuci mailove, PDF, slike, Word, Excel i slične fajlove ili klikni. Drag and drop radi i bilo gdje u lijevom dijelu prozora.",
  );
  syncWorkOrderDocumentDropzone(
    workOrderActivityDropzone,
    uploading,
    "Dodaj iz activityja",
    "Povuci ili klikni za upload. Drag and drop radi i bilo gdje u desnom activity dijelu.",
  );

  items.forEach((item) => {
    workOrderDocumentList.append(createWorkOrderDocumentCard(item));
    workOrderActivityDocumentList.append(createWorkOrderDocumentCard(item, { compact: true }));
  });

  const editorEmptyMessage = !workOrderId
    ? "Povuci dokumente ovdje. Ako je RN nov, prvo spremimo osnovne podatke pa dokument vežemo uz njega."
    : "Još nema dokumenata za ovaj RN.";
  const activityEmptyMessage = !workOrderId
    ? "Dokumenti ?e se pojaviti kad RN bude spremljen."
    : "Još nema dokumenata u activity prikazu.";

  workOrderDocumentEmpty.textContent = editorEmptyMessage;
  workOrderActivityDocumentEmpty.textContent = activityEmptyMessage;
  workOrderDocumentEmpty.hidden = loading || Boolean(error) || items.length > 0;
  workOrderActivityDocumentEmpty.hidden = loading || Boolean(error) || items.length > 0;
}

async function loadWorkOrderDocuments(workOrderId) {
  if (!workOrderId) {
    resetWorkOrderDocumentsState();
    return;
  }

  state.workOrderDocuments = {
    workOrderId: String(workOrderId),
    loading: true,
    uploading: state.workOrderDocuments.uploading,
    busyId: state.workOrderDocuments.busyId,
    items: [],
    error: "",
  };
  renderWorkOrderDocuments();

  try {
    const payload = await apiRequest(`/work-orders/${workOrderId}/documents`);

    if (state.workOrderDocuments.workOrderId !== String(workOrderId)) {
      return;
    }

    state.workOrderDocuments = {
      workOrderId: String(workOrderId),
      loading: false,
      uploading: state.workOrderDocuments.uploading,
      busyId: state.workOrderDocuments.busyId,
      items: payload.items ?? [],
      error: "",
    };
  } catch (error) {
    if (state.workOrderDocuments.workOrderId !== String(workOrderId)) {
      return;
    }

    state.workOrderDocuments = {
      workOrderId: String(workOrderId),
      loading: false,
      uploading: state.workOrderDocuments.uploading,
      busyId: state.workOrderDocuments.busyId,
      items: [],
      error: error.message,
    };
  }

  renderWorkOrderDocuments();
}

function isWorkOrderDocumentFileAllowed(file) {
  const extension = String(file?.name ?? "").trim().includes(".")
    ? String(file.name).trim().split(".").pop().toLowerCase()
    : "";

  if (extension && WORK_ORDER_DOCUMENT_ALLOWED_EXTENSIONS.has(extension)) {
    return true;
  }

  const mimeType = String(file?.type ?? "").trim().toLowerCase();
  return mimeType.startsWith("image/")
    || mimeType === "application/pdf"
    || mimeType === "message/rfc822"
    || mimeType === "application/vnd.ms-outlook"
    || mimeType === "application/msword"
    || mimeType === "application/vnd.openxmlformats-officedocument.wordprocessingml.document"
    || mimeType === "application/vnd.ms-excel"
    || mimeType === "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    || mimeType === "text/csv"
    || mimeType === "text/plain";
}

async function ensureWorkOrderReadyForDocumentUpload() {
  const requiresSave = !workOrderIdInput.value || state.workOrderAutoSave.dirty;

  if (!requiresSave) {
    return String(workOrderIdInput.value || "");
  }

  const success = await persistWorkOrderAutoSave({ immediate: true });

  if (!success || !workOrderIdInput.value) {
    state.workOrderDocuments.error = workOrderError.textContent || "Prvo spremi radni nalog prije uploada dokumenata.";
    renderWorkOrderDocuments();
    return "";
  }

  return String(workOrderIdInput.value || "");
}

async function buildWorkOrderDocumentUploadPayload(files) {
  const uploadFiles = Array.from(files ?? []).filter((file) => file instanceof File);

  if (!uploadFiles.length) {
    return [];
  }

  for (const file of uploadFiles) {
    if (!isWorkOrderDocumentFileAllowed(file)) {
      throw new Error(`Format ${file.name} nije podrzan. Dozvoljeno: ${WORK_ORDER_DOCUMENT_ACCEPT_LABEL}`);
    }

    if (file.size > WORK_ORDER_DOCUMENT_MAX_SIZE_BYTES) {
      throw new Error(`Datoteka ${file.name} mora biti manja od 12 MB.`);
    }
  }

  return Promise.all(uploadFiles.map(async (file) => ({
    fileName: file.name,
    fileType: file.type,
    fileSize: file.size,
    dataUrl: await readFileAsDataUrl(file, `Ne mogu učitati datoteku ${file.name}.`),
  })));
}

async function handleWorkOrderDocumentSelection(files, sourceType = "editor") {
  const selectedFiles = Array.from(files ?? []).filter((file) => file instanceof File);
  workOrderEditorMain?.classList.remove("is-document-panel-active");
  workOrderActivityPanel?.classList.remove("is-document-panel-active");

  if (!selectedFiles.length || state.workOrderDocuments.uploading || state.workOrderDocuments.busyId) {
    return;
  }

  state.workOrderDocuments.error = "";
  state.workOrderDocuments.uploading = true;
  renderWorkOrderDocuments();

  try {
    const workOrderId = await ensureWorkOrderReadyForDocumentUpload();

    if (!workOrderId) {
      return;
    }

    const payloadFiles = await buildWorkOrderDocumentUploadPayload(selectedFiles);
    await apiRequest(`/work-orders/${workOrderId}/documents`, {
      method: "POST",
      body: {
        sourceType,
        files: payloadFiles,
      },
    });
    workOrderError.textContent = "";
    await Promise.all([
      loadWorkOrderDocuments(workOrderId),
      loadWorkOrderActivity(workOrderId),
    ]);
  } catch (error) {
    state.workOrderDocuments.error = error.message;
    workOrderError.textContent = error.message;
  } finally {
    state.workOrderDocuments.uploading = false;
    renderWorkOrderDocuments();

    if (workOrderDocumentFileInput) {
      workOrderDocumentFileInput.value = "";
    }

    if (workOrderActivityFileInput) {
      workOrderActivityFileInput.value = "";
    }
  }
}

async function saveWorkOrderDocument(documentId, patch = {}) {
  const workOrderId = state.workOrderDocuments.workOrderId || workOrderIdInput.value;

  if (!workOrderId || state.workOrderDocuments.busyId) {
    return;
  }

  state.workOrderDocuments.busyId = String(documentId);
  state.workOrderDocuments.error = "";
  renderWorkOrderDocuments();

  try {
    await apiRequest(`/work-orders/${workOrderId}/documents/${documentId}`, {
      method: "PATCH",
      body: {
        fileName: String(patch.fileName ?? "").trim(),
        description: String(patch.description ?? "").trim(),
      },
    });
    workOrderError.textContent = "";
    await Promise.all([
      loadWorkOrderDocuments(workOrderId),
      loadWorkOrderActivity(workOrderId),
    ]);
  } catch (error) {
    state.workOrderDocuments.error = error.message;
    workOrderError.textContent = error.message;
  } finally {
    state.workOrderDocuments.busyId = "";
    renderWorkOrderDocuments();
  }
}

async function deleteWorkOrderDocument(documentId, fileName = "") {
  const workOrderId = state.workOrderDocuments.workOrderId || workOrderIdInput.value;

  if (!workOrderId || state.workOrderDocuments.busyId) {
    return;
  }

  if (!window.confirm(`Maknuti dokument ${fileName || "bez naziva"}?`)) {
    return;
  }

  state.workOrderDocuments.busyId = String(documentId);
  state.workOrderDocuments.error = "";
  renderWorkOrderDocuments();

  try {
    await apiRequest(`/work-orders/${workOrderId}/documents/${documentId}`, {
      method: "DELETE",
    });
    workOrderError.textContent = "";
    await Promise.all([
      loadWorkOrderDocuments(workOrderId),
      loadWorkOrderActivity(workOrderId),
    ]);
  } catch (error) {
    state.workOrderDocuments.error = error.message;
    workOrderError.textContent = error.message;
  } finally {
    state.workOrderDocuments.busyId = "";
    renderWorkOrderDocuments();
  }
}

function isFileDragEvent(event) {
  return Array.from(event.dataTransfer?.types ?? []).includes("Files");
}

function bindWorkOrderDocumentDropzone(dropzone, fileInput, sourceType) {
  if (!dropzone || !fileInput) {
    return;
  }

  let dragDepth = 0;

  dropzone.addEventListener("click", () => {
    if (!state.workOrderDocuments.uploading) {
      fileInput.click();
    }
  });

  fileInput.addEventListener("change", () => {
    void handleWorkOrderDocumentSelection(fileInput.files, sourceType);
  });

  dropzone.addEventListener("dragenter", (event) => {
    if (!isFileDragEvent(event)) {
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    dragDepth += 1;
    dropzone.classList.add("is-drag-over");
  });

  dropzone.addEventListener("dragover", (event) => {
    if (!isFileDragEvent(event)) {
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    dropzone.classList.add("is-drag-over");
  });

  dropzone.addEventListener("dragleave", (event) => {
    if (!isFileDragEvent(event)) {
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    dragDepth = Math.max(0, dragDepth - 1);

    if (dragDepth === 0) {
      dropzone.classList.remove("is-drag-over");
    }
  });

  dropzone.addEventListener("drop", (event) => {
    if (!isFileDragEvent(event)) {
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    dragDepth = 0;
    dropzone.classList.remove("is-drag-over");
    void handleWorkOrderDocumentSelection(event.dataTransfer?.files, sourceType);
  });
}

function bindWorkOrderDocumentPanelTarget(target, sourceType) {
  if (!target) {
    return;
  }

  let dragDepth = 0;

  target.addEventListener("dragenter", (event) => {
    if (!isFileDragEvent(event)) {
      return;
    }

    event.preventDefault();
    dragDepth += 1;
    target.classList.add("is-document-panel-active");
  });

  target.addEventListener("dragover", (event) => {
    if (!isFileDragEvent(event)) {
      return;
    }

    event.preventDefault();
    event.dataTransfer.dropEffect = "copy";
    target.classList.add("is-document-panel-active");
  });

  target.addEventListener("dragleave", (event) => {
    if (!isFileDragEvent(event)) {
      return;
    }

    event.preventDefault();
    dragDepth = Math.max(0, dragDepth - 1);

    if (dragDepth === 0) {
      target.classList.remove("is-document-panel-active");
    }
  });

  target.addEventListener("drop", (event) => {
    if (!isFileDragEvent(event)) {
      return;
    }

    event.preventDefault();
    dragDepth = 0;
    target.classList.remove("is-document-panel-active");
    void handleWorkOrderDocumentSelection(event.dataTransfer?.files, sourceType);
  });
}

