function getDocumentTemplateRuntimeSignatureEntriesFor(template = buildDocumentTemplateDraft(), workOrder = null) {
  const activeWorkOrder = workOrder || getDocumentTemplateRuntimeActiveWorkOrder();
  if (!template || !activeWorkOrder) {
    return [];
  }

  const context = buildDocumentTemplatePreviewContext(template, { workOrder: activeWorkOrder });
  const dedupe = new Set();
  const items = [];

  (Array.isArray(template.customFields) ? template.customFields : []).forEach((field) => {
    const type = String(field?.type || "").trim().toLowerCase();
    if (!["qualified_inspectors", "inspector_signature", "authorization_holder_signature", "digital_signature"].includes(type)) {
      return;
    }

    const entries = type === "qualified_inspectors"
      ? buildDocumentTemplateQualifiedInspectorEntries(field, context)
      : type === "digital_signature"
        ? buildDocumentTemplateDigitalSignatureEntries(field, context)
        : [buildDocumentTemplateSignatureEntry(field, context)];

    entries.forEach((entry) => {
      const key = [
        String(entry?.name || "").trim().toLowerCase(),
        String(entry?.role || "").trim().toLowerCase(),
        String(field?.signatureArea || "").trim().toLowerCase(),
      ].join("::");
      if (!key || dedupe.has(key)) {
        return;
      }
      dedupe.add(key);
      items.push(entry);
    });
  });

  return items;
}

function getDocumentTemplateRuntimeTimelineLabel(entry = {}) {
  const rawTitle = String(entry?.templateTitle || "").trim();
  if (!rawTitle) {
    return "Zapisnik";
  }

  const upperTitle = rawTitle.toUpperCase();
  const knownLabels = ["TZIN", "SPR", "ZNR", "TIPKALO", "PANIK"];
  const matchedLabel = knownLabels.find((label) => upperTitle.includes(label));
  if (matchedLabel) {
    return matchedLabel;
  }

  const sanitized = upperTitle
    .replace(/[^A-Z0-9_\s-]+/g, " ")
    .split(/[\s_-]+/)
    .map((part) => part.replace(/\d+/g, "").trim())
    .find(Boolean);
  return sanitized || rawTitle;
}

function groupDocumentTemplateRuntimeDockEntries(entries = []) {
  const groups = [];
  const groupsByWorkOrderId = new Map();

  (Array.isArray(entries) ? entries : []).forEach((entry, index) => {
    const workOrderId = String(entry?.workOrderId || `group-${index}`);
    let group = groupsByWorkOrderId.get(workOrderId);
    if (!group) {
      group = {
        workOrderId,
        workOrderNumber: String(entry?.workOrderNumber || "").trim() || "bez broja",
        items: [],
      };
      groupsByWorkOrderId.set(workOrderId, group);
      groups.push(group);
    }

    group.items.push({
      ...entry,
      dockIndex: index,
      timelineLabel: getDocumentTemplateRuntimeTimelineLabel(entry),
    });
  });

  return groups;
}

function clampDocumentTemplateRuntimeSequenceIndex(targetIndex, entries = getDocumentTemplateRuntimeSequenceEntries()) {
  const normalizedEntries = Array.isArray(entries) ? entries : [];
  if (normalizedEntries.length === 0) {
    return -1;
  }

  const summaryIndex = normalizedEntries.length;
  const parsedIndex = Number.parseInt(targetIndex, 10);
  const safeIndex = Number.isFinite(parsedIndex) ? parsedIndex : 0;
  return Math.max(0, Math.min(safeIndex, summaryIndex));
}

function scrollDocumentTemplateRuntimeDockTrack(direction = 1) {
  if (!documentTemplateRuntimeDockTrack) {
    return;
  }

  const safeDirection = direction >= 0 ? 1 : -1;
  const scrollAmount = Math.max(240, Math.round(documentTemplateRuntimeDockTrack.clientWidth * 0.7));
  documentTemplateRuntimeDockTrack.scrollBy({
    left: scrollAmount * safeDirection,
    top: 0,
    behavior: "smooth",
  });
}

function renderDocumentTemplateRuntimeContext() {
  if (!documentTemplateRuntimeContext || !documentTemplateRuntimeWorkOrders || !documentTemplateRuntimeCommon) {
    return;
  }

  const template = buildDocumentTemplateDraft();
  const hasContext = hasDocumentTemplateRuntimeContext();
  const fillMode = isDocumentTemplateRuntimeFillMode();
  const sequenceState = fillMode ? getDocumentTemplateRuntimeSequenceState() : null;
  const hasSequence = Boolean(sequenceState);
  const isSummaryStep = Boolean(sequenceState?.isSummary);
  const hasWizardRuntime = fillMode && state.documentTemplateRuntime.source === "wizard";
  const workOrders = hasContext ? getDocumentTemplateRuntimeWorkOrders() : [];
  const activeWorkOrder = hasContext ? getDocumentTemplateRuntimeActiveWorkOrder() : null;
  const activeSequenceEntry = hasSequence && !isSummaryStep
    ? (Array.isArray(sequenceState?.entries) ? (sequenceState.entries[sequenceState.activeIndex] || sequenceState.entries[0] || null) : null)
    : null;
  documentTemplateRuntimeContext.hidden = !hasContext || isSummaryStep || fillMode;
  documentTemplateRuntimeContext.classList.toggle("is-fill-mode", fillMode);
  if (documentTemplateRuntimeHeaderBadges) {
    documentTemplateRuntimeHeaderBadges.hidden = !fillMode || !hasContext || isSummaryStep || !activeWorkOrder;
    documentTemplateRuntimeHeaderBadges.replaceChildren();
  }
  if (documentTemplateRuntimeClearButton) {
    documentTemplateRuntimeClearButton.hidden = !hasContext || fillMode;
  }
  if (documentTemplateRuntimeBackButton) {
    documentTemplateRuntimeBackButton.hidden = true;
  }
  if (documentTemplateRuntimePrevButton) {
    documentTemplateRuntimePrevButton.hidden = true;
    documentTemplateRuntimePrevButton.disabled = !hasSequence || sequenceState.index <= 0;
  }
  if (documentTemplateRuntimeNextButton) {
    documentTemplateRuntimeNextButton.hidden = true;
    documentTemplateRuntimeNextButton.disabled = !hasSequence || sequenceState.index >= sequenceState.total - 1;
    documentTemplateRuntimeNextButton.textContent = "NEXT";
  }
  if (documentTemplateRuntimePrintAllButton) {
    documentTemplateRuntimePrintAllButton.hidden = true;
  }
  if (documentTemplateRuntimeSendSignatureButton) {
    documentTemplateRuntimeSendSignatureButton.hidden = true;
  }
  if (documentTemplateRuntimeSequenceProgress) {
    documentTemplateRuntimeSequenceProgress.hidden = true;
    documentTemplateRuntimeSequenceProgress.textContent = "";
  }
  if (documentTemplateRuntimeDockBackButton) {
    documentTemplateRuntimeDockBackButton.hidden = !hasWizardRuntime;
  }
  if (documentTemplateRuntimeDockPrintAllButton) {
    documentTemplateRuntimeDockPrintAllButton.hidden = true;
  }
  if (documentTemplateRuntimeDockSendSignatureButton) {
    documentTemplateRuntimeDockSendSignatureButton.hidden = true;
  }
  if (documentTemplateRuntimeDockSignScanButton) {
    documentTemplateRuntimeDockSignScanButton.hidden = true;
  }
  if (documentTemplateRuntimeDockSignDigitalButton) {
    documentTemplateRuntimeDockSignDigitalButton.hidden = true;
  }
  if (documentTemplateRuntimeDockPdfButton) {
    documentTemplateRuntimeDockPdfButton.hidden = true;
  }
  if (documentTemplateRuntimeDockWordButton) {
    documentTemplateRuntimeDockWordButton.hidden = true;
  }
  if (documentTemplateRuntimeSidePrevButton) {
    documentTemplateRuntimeSidePrevButton.hidden = !hasSequence;
    documentTemplateRuntimeSidePrevButton.disabled = !hasSequence || sequenceState.index <= 0;
  }
  if (documentTemplateRuntimeSideNextButton) {
    documentTemplateRuntimeSideNextButton.hidden = !hasSequence;
    documentTemplateRuntimeSideNextButton.disabled = !hasSequence || sequenceState.index >= sequenceState.total - 1;
  }

  const renderRuntimeDock = () => {
    if (!documentTemplateRuntimeDock || !documentTemplateRuntimeDockTrack || !documentTemplateRuntimeDockTitle || !documentTemplateRuntimeDockMeta) {
      return;
    }

    if (!fillMode || !activeWorkOrder) {
      documentTemplateRuntimeDock.hidden = true;
      documentTemplateRuntimeDockTrack.replaceChildren();
      documentTemplateRuntimeDockTitle.textContent = "Aktivni zapisnik";
      documentTemplateRuntimeDockMeta.textContent = "RN i zapisnik u tijeku";
      return;
    }

    const dockEntries = hasSequence
      ? sequenceState.entries
      : [{
        templateId: template.id || "",
        templateTitle: template.title || getDocumentTemplateTypeLabel(template.documentType) || "Zapisnik",
        workOrderId: activeWorkOrder.id,
        workOrderNumber: activeWorkOrder.workOrderNumber || "bez broja",
      }];

    const activeIndex = hasSequence
      ? (sequenceState.isSummary ? sequenceState.itemTotal : sequenceState.index)
      : 0;
    const activeEntry = sequenceState?.isSummary
      ? dockEntries[dockEntries.length - 1]
      : (dockEntries[activeIndex] || dockEntries[0]);
    const groupedEntries = groupDocumentTemplateRuntimeDockEntries(dockEntries);
    documentTemplateRuntimeDock.hidden = dockEntries.length === 0;
    if (sequenceState?.isSummary) {
      documentTemplateRuntimeDockTitle.textContent = "Summary";
      documentTemplateRuntimeDockMeta.textContent = "Završetak";
    } else {
      documentTemplateRuntimeDockTitle.textContent = `RN ${activeEntry?.workOrderNumber || activeWorkOrder.workOrderNumber || "bez broja"}`;
      documentTemplateRuntimeDockMeta.textContent = activeWorkOrder.companyName || "";
    }

    const dockNodes = groupedEntries.map((group) => {
      const groupCard = document.createElement("article");
      groupCard.className = "document-template-runtime-dock-group";
      if (!sequenceState?.isSummary && String(group.workOrderId) === String(activeEntry?.workOrderId || "")) {
        groupCard.classList.add("is-active");
      }

      const groupHead = document.createElement("div");
      groupHead.className = "document-template-runtime-dock-group-head";

      const groupTitle = document.createElement("strong");
      groupTitle.textContent = `RN ${group.workOrderNumber}`;

      const groupMeta = document.createElement("span");
      groupMeta.textContent = "";

      groupHead.append(groupTitle, groupMeta);

      const groupItems = document.createElement("div");
      groupItems.className = "document-template-runtime-dock-group-items";

      group.items.forEach((entry) => {
        const index = Number(entry.dockIndex);
        const itemButton = document.createElement("button");
        itemButton.type = "button";
        itemButton.className = "document-template-runtime-dock-item";
        if (index === activeIndex) {
          itemButton.classList.add("is-active");
        } else if (index >= 0 && index < activeIndex) {
          itemButton.classList.add("is-complete");
        }
        itemButton.textContent = entry.timelineLabel;
        itemButton.setAttribute("aria-label", `${entry.timelineLabel} za RN ${group.workOrderNumber}`);
        itemButton.addEventListener("click", () => {
          if (hasSequence) {
            if (index !== activeIndex && index >= 0) {
              openDocumentTemplateRuntimeSequenceIndex(index);
            }
            return;
          }

          if (String(entry.workOrderId || "") !== String(activeWorkOrder?.id || "")) {
            setDocumentTemplateRuntimeActiveWorkOrder(entry.workOrderId, { render: true });
          }
        });
        groupItems.append(itemButton);
      });

      groupCard.append(groupHead, groupItems);
      return groupCard;
    });

    if (sequenceState) {
      const summaryCard = document.createElement("article");
      summaryCard.className = "document-template-runtime-dock-group is-summary";
      if (sequenceState.isSummary) {
        summaryCard.classList.add("is-active");
      }

      const summaryHead = document.createElement("div");
      summaryHead.className = "document-template-runtime-dock-group-head";
      const summaryTitle = document.createElement("strong");
      summaryTitle.textContent = "Summary";
      const summaryMeta = document.createElement("span");
      summaryMeta.textContent = "";
      summaryHead.append(summaryTitle, summaryMeta);

      const summaryItems = document.createElement("div");
      summaryItems.className = "document-template-runtime-dock-group-items";
      const summaryButton = document.createElement("button");
      summaryButton.type = "button";
      summaryButton.className = "document-template-runtime-dock-item";
      if (sequenceState.isSummary) {
        summaryButton.classList.add("is-active");
      }
      summaryButton.textContent = "Summary";
      summaryButton.addEventListener("click", () => {
        openDocumentTemplateRuntimeSequenceIndex(sequenceState.summaryIndex);
      });
      summaryItems.append(summaryButton);

      summaryCard.append(summaryHead, summaryItems);
      dockNodes.push(summaryCard);
    }

    documentTemplateRuntimeDockTrack.replaceChildren(...dockNodes);
  };

  if (!hasContext) {
    documentTemplateRuntimeWorkOrders.replaceChildren();
    documentTemplateRuntimeCommon.replaceChildren();
    renderRuntimeDock();
    return;
  }

  if (isSummaryStep) {
    documentTemplateRuntimeWorkOrders.replaceChildren();
    documentTemplateRuntimeCommon.replaceChildren();
    renderRuntimeDock();
    return;
  }

  const visibleWorkOrders = hasSequence
    ? workOrders.filter((workOrder) => String(workOrder.id) === String(sequenceState.entry.workOrderId))
    : workOrders;

  if (documentTemplateRuntimeHelper) {
    documentTemplateRuntimeHelper.textContent = fillMode
      ? ""
      : (workOrders.length > 1
        ? "Template trenutno čita zajedničke podatke iz batch odabira. Klikom na RN mijenjaš aktivni preview i Word export."
        : "Template trenutno čita podatke iz odabranog RN-a i zajedničkih dokument podataka.");
    documentTemplateRuntimeHelper.hidden = fillMode;
  }

  documentTemplateRuntimeWorkOrders.replaceChildren(...visibleWorkOrders.map((workOrder) => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "document-template-runtime-chip";
    button.classList.toggle("is-active", String(workOrder.id) === String(activeWorkOrder?.id || ""));
    button.addEventListener("click", () => {
      setDocumentTemplateRuntimeActiveWorkOrder(workOrder.id, { render: true });
    });

    const title = document.createElement("strong");
    title.textContent = workOrder.workOrderNumber || "Bez broja RN";

    const meta = document.createElement("span");
    meta.textContent = [
      workOrder.companyName || "Bez tvrtke",
      getDocumentTemplateRuntimeValue(workOrder.id, "inspectionDate")
        ? `Ispitivanje ${formatCompactDate(getDocumentTemplateRuntimeValue(workOrder.id, "inspectionDate"))}`
        : "",
    ].filter(Boolean).join(" · ");

    button.append(title, meta);
    return button;
  }));

  const commonBadges = [
    {
      label: "Zapisnik",
      value: activeSequenceEntry?.timelineLabel
        || documentTemplateTitleInput?.value?.trim()
        || "",
    },
    {
      label: "Datum ispitivanja",
      value: activeWorkOrder ? getDocumentTemplateRuntimeValue(activeWorkOrder.id, "inspectionDate") : "",
    },
    {
      label: "Datum izdavanja",
      value: activeWorkOrder ? getDocumentTemplateRuntimeValue(activeWorkOrder.id, "issuedDate") : "",
    },
    {
      label: "Mjesto izdavanja",
      value: activeWorkOrder ? getDocumentTemplateRuntimeValue(activeWorkOrder.id, "issuedPlace") : "",
    },
    {
      label: "Napomena",
      value: activeWorkOrder ? getDocumentTemplateRuntimeValue(activeWorkOrder.id, "note") : "",
    },
    {
      label: "Panik ispitivač",
      value: activeWorkOrder
        ? getWorkOrderDocumentSignaturePersonNames(
          {
            electricalInspectorUserIds: getDocumentTemplateRuntimeArrayValue(activeWorkOrder.id, "electricalInspectorUserIds"),
            electricalInspectorUserId: getDocumentTemplateRuntimeValue(activeWorkOrder.id, "electricalInspectorUserId"),
          },
          WORK_ORDER_DOCUMENT_SIGNATURE_PERSON_FIELDS[0],
        ).join(", ")
        : "",
    },
    {
      label: "Panik odgovorna osoba",
      value: activeWorkOrder
        ? getWorkOrderDocumentSignaturePersonName(
          {
            electricalAuthorizationHolderUserId: getDocumentTemplateRuntimeValue(activeWorkOrder.id, "electricalAuthorizationHolderUserId"),
          },
          "electricalAuthorizationHolderUserId",
        )
        : "",
    },
    {
      label: "Tipkalo ispitivač",
      value: activeWorkOrder
        ? getWorkOrderDocumentSignaturePersonNames(
          {
            tipkaloInspectorUserIds: getDocumentTemplateRuntimeArrayValue(activeWorkOrder.id, "tipkaloInspectorUserIds"),
            tipkaloInspectorUserId: getDocumentTemplateRuntimeValue(activeWorkOrder.id, "tipkaloInspectorUserId"),
          },
          WORK_ORDER_DOCUMENT_SIGNATURE_PERSON_FIELDS[2],
        ).join(", ")
        : "",
    },
    {
      label: "Tipkalo odgovorna osoba",
      value: activeWorkOrder
        ? getWorkOrderDocumentSignaturePersonName(
          {
            tipkaloAuthorizationHolderUserId: getDocumentTemplateRuntimeValue(activeWorkOrder.id, "tipkaloAuthorizationHolderUserId"),
          },
          "tipkaloAuthorizationHolderUserId",
        )
        : "",
    },
    {
      label: "Ispitivači",
      value: activeWorkOrder
        ? getUsersByIds(getDocumentTemplateRuntimeArrayValue(activeWorkOrder.id, "inspectorUserIds"))
          .map((user) => user.fullName || user.email || "")
          .filter(Boolean)
          .join(", ")
        : "",
    },
    {
      label: "Nositelj",
      value: activeWorkOrder
        ? getUsersByIds([getDocumentTemplateRuntimeValue(activeWorkOrder.id, "authorizationHolderUserId")])[0]?.fullName || ""
        : "",
    },
  ].filter((entry) => String(entry.value || "").trim());

  if (fillMode && activeWorkOrder && documentTemplateRuntimeHeaderBadges) {
    const workOrderChip = document.createElement("div");
    workOrderChip.className = "document-template-runtime-chip is-active";

    const workOrderTitle = document.createElement("strong");
    workOrderTitle.textContent = activeWorkOrder.workOrderNumber || "Bez broja RN";

    const workOrderMeta = document.createElement("span");
    workOrderMeta.textContent = activeWorkOrder.companyName || "Bez tvrtke";

    workOrderChip.append(workOrderTitle, workOrderMeta);

    const headerBadgeWrap = document.createElement("div");
    headerBadgeWrap.className = "document-template-runtime-common-badges";

    const headerBadges = [
      commonBadges.find((entry) => entry.label === "Zapisnik"),
      commonBadges.find((entry) => entry.label === "Datum ispitivanja"),
      commonBadges.find((entry) => entry.label === "Datum izdavanja"),
    ].filter(Boolean);

    headerBadgeWrap.append(...headerBadges.map((entry) => {
      const badge = document.createElement("div");
      badge.className = "document-template-runtime-badge";
      if (String(entry.label || "").trim().toLowerCase() === "zapisnik") {
        badge.classList.add("is-primary");
      }

      const label = document.createElement("span");
      label.textContent = entry.label;

      const value = document.createElement("strong");
      value.textContent = entry.label.toLowerCase().includes("datum")
        ? formatCompactDate(entry.value)
        : entry.value;

      badge.append(label, value);
      return badge;
    }));

    documentTemplateRuntimeHeaderBadges.replaceChildren(workOrderChip, headerBadgeWrap);
  }

  const runtimeCommonNodes = [];

  if (commonBadges.length === 0) {
    const empty = document.createElement("p");
    empty.className = "helper-copy module-copy";
    empty.textContent = "Nema dodatnih zajednickih podataka. Template i dalje koristi podatke iz samog RN-a.";
    runtimeCommonNodes.push(empty);
  } else {
    const badgeWrap = document.createElement("div");
    badgeWrap.className = "document-template-runtime-common-badges";
    badgeWrap.append(...commonBadges.map((entry) => {
      const badge = document.createElement("div");
      badge.className = "document-template-runtime-badge";
      if (String(entry.label || "").trim().toLowerCase() === "zapisnik") {
        badge.classList.add("is-primary");
      }

      const label = document.createElement("span");
      label.textContent = entry.label;

      const value = document.createElement("strong");
      value.textContent = entry.label.toLowerCase().includes("datum")
        ? formatCompactDate(entry.value)
        : entry.value;

      badge.append(label, value);
      return badge;
    }));
    runtimeCommonNodes.push(badgeWrap);
  }

  if (fillMode && activeWorkOrder) {
    const signatureMode = normalizeDocumentTemplateSignatureMethod(state.documentTemplateRuntime.common?.signatureMode);
    const signatureEntries = getDocumentTemplateRuntimeSignatureEntriesFor(template, activeWorkOrder);
    if (documentTemplateRuntimeDockSignScanButton) {
      documentTemplateRuntimeDockSignScanButton.title = signatureEntries.length > 0
        ? `${signatureEntries.length} potpisnika · Scan potpisa`
        : "Scan potpisa";
      documentTemplateRuntimeDockSignScanButton.classList.toggle("is-active", signatureMode === "scan");
    }
    if (documentTemplateRuntimeDockSignDigitalButton) {
      documentTemplateRuntimeDockSignDigitalButton.title = signatureEntries.length > 0
        ? `${signatureEntries.length} potpisnika · Digitalni potpis`
        : "Digitalni potpis";
      documentTemplateRuntimeDockSignDigitalButton.classList.toggle("is-active", signatureMode === "digital");
    }
  }

  documentTemplateRuntimeCommon.replaceChildren(...runtimeCommonNodes);
  renderRuntimeDock();
}

function syncDocumentTemplateEditorChrome() {
  const fillMode = isDocumentTemplateRuntimeFillMode();
  if (documentTemplateEditorTitle) {
    if (fillMode) {
      const activeWorkOrder = getDocumentTemplateRuntimeActiveWorkOrder();
      const sequenceState = getDocumentTemplateRuntimeSequenceState();
      const sequenceEntries = Array.isArray(sequenceState?.entries) ? sequenceState.entries : [];
      const activeEntry = sequenceState?.isSummary
        ? null
        : (sequenceEntries[sequenceState?.activeIndex ?? 0] || sequenceEntries[0] || null);

      documentTemplateEditorTitle.textContent = sequenceState?.isSummary
        ? `Summary · ${sequenceEntries.length} ${sequenceEntries.length === 1 ? "zapisnik" : "zapisnika"}`
        : [
          activeEntry?.workOrderNumber ? `RN ${activeEntry.workOrderNumber}` : "",
          activeWorkOrder?.companyName || "",
        ].filter(Boolean).join(" · ");
      documentTemplateEditorTitle.hidden = !sequenceState?.isSummary;
    } else {
      documentTemplateEditorTitle.textContent = documentTemplateIdInput?.value
        ? `Uredi template | ${documentTemplateTitleInput?.value?.trim() || "Bez naziva"}`
        : "Template editor";
      documentTemplateEditorTitle.hidden = false;
    }
  }

  if (documentTemplateEditorPanel) {
    documentTemplateEditorPanel.classList.toggle("is-fill-mode", fillMode);
  }

  if (documentTemplateDeleteButton) {
    documentTemplateDeleteButton.hidden = fillMode || !documentTemplateIdInput?.value;
  }

  if (documentTemplateSaveButton) {
    documentTemplateSaveButton.hidden = fillMode;
  }
  if (documentTemplateOpenPdfPreviewButton) {
    documentTemplateOpenPdfPreviewButton.hidden = true;
  }
  if (documentTemplateExportPreviewButton) {
    documentTemplateExportPreviewButton.hidden = true;
  }
  if (documentTemplateRuntimeSendSignatureButton) {
    documentTemplateRuntimeSendSignatureButton.hidden = true;
  }
  if (documentTemplateRuntimePrintAllButton) {
    documentTemplateRuntimePrintAllButton.hidden = true;
  }
  if (documentTemplateMetaGrid) {
    documentTemplateMetaGrid.hidden = fillMode;
  }
  if (documentTemplateDescriptionField) {
    documentTemplateDescriptionField.hidden = fillMode;
  }
  if (documentTemplateLayoutActions) {
    documentTemplateLayoutActions.hidden = fillMode;
  }
  if (documentTemplateBuilderSidebar) {
    documentTemplateBuilderSidebar.hidden = fillMode;
  }
  if (documentTemplateFormActions) {
    documentTemplateFormActions.hidden = fillMode;
  }

  renderDocumentTemplateRuntimeContext();
  if (!fillMode) {
    renderDocumentTemplateReferenceMeta();
    renderDocumentTemplatePlaceholderPalette();
  } else {
    documentTemplateReferenceMeta?.replaceChildren();
    documentTemplatePlaceholderPalette?.replaceChildren();
  }
  renderDocumentTemplatePreviewContent();
}

